INSERT INTO `reviews` VALUES (90019,'Nakoa','Maya Prastio',5,'2 bulan lalu','🌸Sudah berkali-kali ke Malang tapi baru pertama kali ke Cafe ini karena dekat dengan pondoknya anak saya😍 🌸Kayaknya ini cafe bakalan jadi tempat nongki favorit saya kalau pas ke Malang🎉🤗 …','pondok anak nongkrong favorit'),(90020,'Nakoa','Kee Hoo',4,'sebulan lalu','Baru pertama kali coba tempat ini setelah berulang kali lewati. Ternyata tdk ada makanan berat, hanya burger, roti, risoles, beverages. …','ulang tdk makan berat burger roti risoles beverages'),(90021,'Nakoa','Aditya B. Prakoso',5,'sebulan lalu','Nyaman untuk kerja remote / online meeting, tempat luas (indoor & outdoor). Secara personal suka bagian outdoor, ada pepohonan, kadang ada suara kicau burung dan tonggeret juga 👍🏼 …','nyaman kerja remote online kerja luas indoor outdoor personal suka outdoor pohon kadang suara kicau burung tonggeret'),(90022,'Nakoa','A M RD',5,'sebulan lalu','Enak nih kopinya worth lah dengan harganya yang terlihat lebih mahal tetapi kita dapat apa yang kita bayar, tempat cozy bisa untuk rame² AC cukup dingin meski di siang hari, saran saja untuk pegawai kasir dan barista kalau bisa lebih ramah 🙏🏻','nikmat nih layak harga mahal bayar nyaman ramai dingin saran pegawai kasir barista ramah'),(90023,'Nakoa','Moh. Fikri Rizaldi',5,'8 bulan lalu','Sebagai wisatawan yang beberapa kali menginjakkan kaki di Malang, saya penasaran mencoba salah satu cafe yang cukup hits di sini, Nakoa. Pagi menjelang siang, suasananya tenang dan nyaman, cocok untuk yang ingin sarapan santai sambil menikmati udara Malang yang sejuk.  Menu yang saya pesan: - Donat Bomboloni Coklat 🍫 - Risol Mayo Mentai - Donat Almond - Ice Shaken Jelly Tea Lychee 🧋  Semua menu datang dengan tampilan cantik dan menggoda, tapi juaranya menurut saya adalah Donat Bomboloni Coklat, teksturnya empuk, isi coklatnya melimpah, manisnya pas, dan meleleh di mulut. Risol mayo mentainya gurih dan creamy, sementara donat almond punya sensasi renyah dari topping almond. Ice shaken jelly tea rasa lychee segar banget, perpaduan wangi leci dan kenyalnya jelly bikin segar di tengah hari.  💡 Tips buat yang mau ke sini:  1. Datang pagi menjelang siang kalau mau suasana tenang dan sejuk. 2. Bomboloni coklat wajib coba! 3. Harga sangat terjangkau untuk ukuran cafe dengan ambience senyaman ini. 4. Cocok untuk kerja laptop-an atau sekadar ngobrol santai.  Kesimpulannya, Cafe Nakoa sukses bikin kesan pertama saya di Malang jadi manis. Rasanya bakal masuk list kunjungan ulang kalau ke Malang lagi. 🌿','wisatawan injak kaki penasaran hits jelang suasana tenang nyaman cocok sarap santai nikmat udara sejuk menu pesan donat bomboloni coklat risol mayo mentai donat almond ice shaken jelly tea lychee menu tampil cantik goda juara donat bomboloni coklat tekstur empuk isi coklat limpah manis leleh mulut risol mayo mentainya gurih creamy donat almond sensasi renyah topping almond ice shaken jelly tea lychee segar padu wangi leci kenyal jelly segar tips jelang suasana tenang sejuk bomboloni coklat wajib harga murah ukur ambience nyaman cocok kerja laptop ngobrol santai simpul sukses kesan manis list kunjung ulang'),(90024,'Nakoa','Brilliant A.',5,'Diedit 4 bulan lalu','tEmpaatnya cocok untuk WFH wifinya jg lancAaaR habisitu tempatnya bener bener luaas 🚹🚹🚹🤍🤍💟enak banget!! kakaknya ramaah-rAamaaahh 🩷❤️❤️‍🩹🖐🏻🖐🏻🖐🏻tp ad beberapa tempat yg kotor gt (mungkin karena self service? atau gaa  kakaknya blm sempet bersiin) 😵‍💫😵‍💫','tempaatnya cocok kerja wifi lancaaar habisitu bener bener luaas nikmat kakak ramaah raamaaahh kotor self service gaa kakak sempet bersiin'),(90025,'Nakoa','Indra Dwi Cahya',5,'sebulan lalu','Cozy, enak buat SFC  Ada printer gratis buat yg perlu cetak-cetak  Makanannya enak dan masih ramah kantong','nyaman nikmat sfc printer gratis cetak cetak makan nikmat ramah kantong'),(90026,'Nakoa','Kharisma layar',5,'6 bulan lalu','Selalu ngerasa aman tiap nugas di nakoa, walaupun super rame dari pagi sampe malem, tapi kalo kita mau ninggal tas mau solat/keluar, rasanya aman aja gitu karna yg lain udh sibuk sama laptopnya masing2😂😆 Tiap meja ada colokan, toilet bersih, wifi ok, AC super dingin, ada parkir tapi mas parkirnya pasti bantu.','ngerasa aman tugas super ramai malem ninggal tas solat aman udh sibuk laptop meja colok toilet bersih wifi super dingin parkir mas parkir bantu'),(90027,'Nakoa','Alex M. Sumayku',4,'11 bulan lalu','Tempatnya enak sekali. Luas, parkir gampang dan dingin AC nya. Nyaman banget utk nongkrong or nugas. Cuma kopinya ga tau kenapa rasanya biasa aja apa karena di campur air ya? , tapi chocolate nya enak sama Lyche Sodanya ok.  Mochinya lumayan enak, tapi Susennya engga 🥲','nikmat luas parkir gampang dingin nyaman nongkrong tugas tau campur air chocolate nikmat lyche soda mochi lumayan nikmat susennya'),(90028,'Nakoa','Hanna Syabrina',5,'2 bulan lalu','self service, makanan hanya desert dan roti2 saja. cocok buat wfc','self service makan desert roti cocok kerja'),(90029,'Nakoa','Rini Amaliza',4,'6 bulan lalu','Tempatnya enak, luas, suasana juga enak cocok buat nugas, tapi maaf untuk colokannya banyak yang ga bisa nyala (mau nugas jadi bingung soalnya tempat yang colokan nyala pada di tempatin :( , semoga kedepan segera diperbaiki','nikmat luas suasana nikmat cocok tugas maaf colok nyala tugas bingung colok nyala tempatin moga'),(90030,'Nakoa','Muhammad Ainul Yaqin',5,'11 bulan lalu','Nakoa Kafe Suhat, Malang: Simple, Cozy, Berkarakter Ngafe di Nakoa itu kayak mampir ke tempat yang udah ngerti kamu capek. Interiornya clean dan minimalis, tapi hangat. Baristanya ramah, vibes-nya santai banget.  Pesan iced latte, duduk di pojok dekat jendela. Rasanya pas, nggak neko-neko, tapi nagih. Tempat ini cocok buat nugas, ngobrol santai, atau sekadar nyendiri sambil dengerin playlist lo-fi.  Nakoa bukan cuma soal kopi — tapi soal ketenangan kecil di tengah riuhnya Malang','simple nyaman karakter ngafe mampir ngerti capek interior clean minimal hangat baristanya ramah vibes santai pesan iced latte duduk pojok jendela neko neko nagih cocok tugas ngobrol santai nyendiri dengerin playlist tenang riuh'),(90031,'Nakoa','Vitania Fauzyah',5,'Diedit setahun lalu','Salah satu Coffee Shop di Malang yang wajib banget didatengin. Rata-rata semua minumannya enak, tidak ada makanan berat tapi semua jenis pastry/kuenya enak (recommen: es kopi susu gula aren, asian dolce latte, choco tiramisu🥇). Fasilitasnya lengkap ada musholla, toilet, wi-Fi, dan colokan banyak bgt. Indoornya cocok untuk yang mau nugas/WFC, outdoornya cocok untuk nongkrong sama temen, spacenya banyak banget!!  Pelayanannya ramah banget dan cepet, pas mau selesai transaksi minuman udah selesai, jadi gaperlu nunggu lama (kondisional sih, kebetulan datangnya pas sepi jadinya selesai transaksi bisa langsung diambil minumnya)','wajib didatengin minum nikmat makan berat jenis pastry kue nikmat recommen susu gula asi dolce latte choco tiramisu fasilitas lengkap musholla toilet colok indoornya cocok tugas kerja outdoornya cocok nongkrong teman spacenya layan ramah cepat selesai transaksi minum selesai gaperlu nunggu kondisional sepi selesai transaksi ambil minum'),(90032,'Nakoa','Yanti Sandika',4,'sebulan lalu','tempat bagus nyaman bersih sngat dingin','bagus nyaman bersih sngat dingin'),(90033,'Nakoa','Simson Salouw',4,'3 bulan lalu','Tempatnya luas berAC utk dalam ruang dan ada juga luar ruang yg spotnya lebih banyak lagi. Layanan cepat. Ada minuman yang salah tidak sesuai orderan langsung diganti. Parkiran luas. Tutup pukul 24.00. harga menengah.','luas berac ruang ruang spotnya layan cepat minum order ganti parkir luas harga'),(90034,'Nakoa','Andis Julian',5,'7 bulan lalu','Tempat nongki nyaman enk dan luas bngt . Ngak usah binggung kalau mau cari tempat karna ruang out doornya bnyk, indoo juga nyaman','nongkrong nyaman enk luas bngt ngak binggung cari ruang doornya indoo nyaman'),(90035,'Nakoa','Hardanto Suryo Pratomo',4,'2 bulan lalu','Seperti biasa nakoa the best untuk WFC. Tapi mohon diperhatikan musholla di bagian belakang cafe, seperti tidak terawat. Lantai tempat wudhu licin, banyak daun2 kering yang masuk, dan juga tembok sudah berjamur dan ada remahan kayu dari plafon yang tidak dibersihkan','kerja mohon perhati musholla awat lantai wudhu licin daun kering tembok jamur remah kayu plafon bersih'),(90036,'Nakoa','Ahmad Bachtiar Arif',5,'2 tahun lalu','Kafe estetik yang cukup digemari oleh kaum muda yang ada di Malang. Rasa minuman dan harganya standard kafe pada umumnya. Tempatnya cukup luas dan tersedia banyak meja serta colokan, sehingga cocok digunakan untuk working space atau nugas. Tempat duduknya ada yang indoor dan outdoor. Fasilitasnya cukup lengkap dan ada mushollanya. Sebelum ada cabang di Jalan Panjaitan, kafe ini sangat ramai dan harus antri lama ketika memesan. Namun, untuk saat ini situasinya tidak terlalu ramai karena sudah ada cabangnya. Lokasinya sangat strategis karena terletak dekat dengan Jalan Suhat. Untuk tempat parkirnya juga cukup luas.','indah gari kaum muda minum harga standard luas meja colok cocok working tugas duduk indoor outdoor fasilitas lengkap mushollanya cabang panjaitan ramai antri mes situasi ramai cabang strategis letak parkir luas'),(90037,'Nakoa','Ananta Sapta',5,'11 bulan lalu','Tempat nongkrong yg nyaman, ada indoor & outdoor, minuman & makanannya juga enak, pelayanan cepat & ramah, harga lumayan terjangkau… 😊','nongkrong nyaman indoor outdoor minum makan nikmat layan cepat ramah harga lumayan murah'),(90038,'Nakoa','Dewi Firdausi',5,'2 tahun lalu','Tempatnya cozy dan harga minumannya terjangkau, khususnya untuk temen2 yg kuliah. Buat nongkrong dan ngerjain tugas juga oke, krn di setiap tempat duduk ada colokannya. Buat pecinta kopi kayanya bisa nambah espresso krn kurang kerasa kopinya, pas aku pesen americano, jadi americano nya lebih light, tapi masih tetep ok.  Service waiternya ok, dan kita nanti ambil sendiri pas udah dipanggil namanya.  Disini ga jualan air mineral, tapi disediakan dispenser buat free air mineral dan udau ada gelasnya juga kok. Tapi gaapa kalau bawa tempat sendiri','nyaman harga minum murah teman kuliah nongkrong ngerjain tugas duduk colok cinta kaya nambah espresso pesan americano americano light tetep service waiternya ambil panggil nama jual air mineral sedia dispenser free air mineral udau gelas gaapa bawa'),(90039,'Nakoa','Erlin Febri Hdyni',5,'3 tahun lalu','Pertama kali ke Nakoa nih selama kuliah di Malang. Interiornya bagus, suasananya juga nyaman. Tempatnya cocok untuk anak muda bersua. Baik buat ngerjain tugas atau ngumpul biasa sama teman-teman.  Ada indoor dan outdoor. Dua duanya nyaman, asri dan bersih dong tentunya. Dalam ruangan ada banyak fasilitas yang dapat digunakan untuk mengerjakan tugas, jadi enak. Kalau yang diluar ruangan nya remang-remang, bisa lihat di foto. Dan gak terlalu berisik juga. Banyak tanamannya, jadi kayak asri dan sejuk gitu.  Untuk makanan dan minumannya lumayan, yaa namanya juga cafe. Tapi makanannya enak. Donatnya enak, walaupun bukan tipe donat yang empuk banget tapi tetap enak. Pelayanannya juga bagus. Staffnya ramah-ramah sekali.  Thank you, Nakoa!','nih kuliah interior bagus suasana nyaman cocok anak muda sua ngerjain tugas nongkrong teman teman indoor outdoor nyaman asri bersih ruang fasilitas tugas nikmat ruang remang remang lihat berisik tanam asri sejuk makan minum lumayan yaa nama makan nikmat donat nikmat tipe donat empuk nikmat layan bagus staffnya ramah ramah thank'),(90040,'Nakoa','Ahmad Musyadad A.',5,'3 tahun lalu','Lokasi strategis. Mudah di temukan karena bangunannya gede, gampang di lihat. Parkirannya luas. Tempatnya luas, banyak tempat duduk / kursi nya. Harga oke, rasa juga oke. Pelayanannya baik. Ada outdoor nya juga kok.  IG: ahmad_musyadad_a','strategis mudah temu bangun gede gampang lihat parkir luas luas duduk kursi harga layan outdoor ahmad musyadad'),(90041,'Nakoa','Aldrin Rachman Pradana',5,'3 tahun lalu','Salah satu cafe yang lumayan ramai di Kota Malang. Cocok untuk nugas atau bekerja karena ada colokan dan banyak space utk duduk. Minuman mulai dari Rp24,000 dan makanan mulai dari Rp 20,000 Tempatnya lumayan cozy dan ber ac yg did alam dan juga ada yg outdoor. Cuman klo cuaca mendung duduk di outdoor siap2 aja kehujanan dan rebutan duduk utk ke dalam 😄.','lumayan ramai cocok tugas colok duduk minum makan lumayan nyaman ber alam outdoor cuaca mendung duduk outdoor hujan rebut duduk'),(90042,'Nakoa','Hildan Fathoni',5,'3 tahun lalu','Nakoa yang di Soekarno Hatta ini lebih luas daripada di jalan Bondowoso. Ada dua ruangan outdoor di bagian depan dan di bagian belakang. Keduanya cocok untuk nongkrong sore hari dan suasana langit yang cerah. Sedangkan untuk cuaca hujan lebih baik kita di ruangan indoor. Ruangan tidurnya sendiri asik buat bekerja dan tenang. Sedangkan ruangan outdoornya cenderung lebih ramai dan berangin.  Untuk minumannya sama dengan nakoa di jalan Bondowoso. Rasanya enak pelayanannya cepat dan harganya terjangkau. Makanannya juga sama dengan di cabang lain. Sukses selalu ya','luas bondowoso ruang outdoor cocok nongkrong sore suasana langit cerah cuaca hujan ruang indoor ruang tidur nyaman tenang ruang outdoornya cenderung ramai angin minum bondowoso nikmat layan cepat harga murah makan cabang sukses'),(90043,'Nakoa','Zuhri Pribadi',5,'11 bulan lalu','Lokasi di pusat kota. Tempatnya luas, wifi kencang, dan kursi dengan colokan laptop cukup banyak. Cocok buat WFC dan ngerjain tugas kuliah.  Di sini jg ada mushollanya. Nongkrong OK, ibadah OK ✅','pusat luas wifi kencang kursi colok laptop cocok kerja ngerjain tugas kuliah mushollanya nongkrong ibadah'),(90044,'Nakoa','Cheryl ́。• ᴗ •。`',5,'sebulan lalu','Sukak poll good ambience, betah sih di sana, duinginn p9ll tpi berasa masuk kulkas','sukak bagus ambience betah duinginn asa kulkas'),(90045,'Nakoa','Wafa Baihaqi',4,'Diedit setahun lalu','Jujur kesan pertama kali kesini itu ketika ngeliat bangunan dari luar mikir ini tempat gede banget. Tiap tempat duduk itu ada colokan. Cocok banget buat nugas dan rapat kecil-kecilan. Untuk dari segi makanan dan minuman, ya standardnya cafe lah. Harga average, ramah buat anak sekolah, kampus, maupun yang kerja.','jujur kesan ngeliat bangun mikir gede duduk colok cocok tugas rapat segi makan minum standardnya harga average ramah anak sekolah kampus kerja'),(90046,'Nakoa','Riyo April',5,'setahun lalu','Tolong dong yang hari ini tanggal 25 sept 2024 sekitar pukul 12.00 an nemu cincin perak di toilet, minta tolong banget dikembalikan ke kasir, bukan masalah harga nya karna itu cincin kawin saya 🙏😥🙏😥🙏','tolong tanggal sept nemu cincin perak toilet tolong kasir harga cincin kawin'),(90047,'Nakoa','Fajerin Biabdillah',5,'Diedit 3 tahun lalu','Amaze bgt sih sama tempatnya. Luas dan lega banget, tempat parkir motornya juga luas. Sangat banyak tempat duduk sehingga tidak perlu khawatir kepenuhan. Bisa memilih indoor ataupun outdoor, semuanya ada tempat untuk charger. Sangat nyaman berlama lama disana, baik sendiri maupun bersama kerabat. Outdoornya ada dua, ada yg didepan ada yg dibelakang, semi outdoornya juga ada. Minuman dan makanannya cuma ada dessert, enak semua sih keliatannya. Pelayanan sangat cepat juga. Overall sangat rekomended banget lah.','amaze luas lega parkir motor luas duduk khawatir penuh pilih indoor outdoor charger nyaman kerabat outdoornya semi outdoornya minum makan dessert nikmat liat layan cepat rekomended'),(90048,'Nakoa','Hibatulloh Zaki Ardiansyah',5,'2 tahun lalu','Salah satu tempat untuk tempat nongkrong, makan bisa, nugas, atau bahkan satu satunya zoom meeting di Suhat, Malang.  Tempat yang bersih, rapi, aman, sejuk, terawat, cukup strategis, parkiran cukup luas untuk beberapa mobil dan seperti biasa di Kota ini ada parkir berbayar yang disayangkan.  Harga masuk akal apa fasilitas yang ditawarkan, tempat yang suasana sangat enak, adem, dan bagus pokoknya. Pelayanan cukup cepat, fasilitas juga lengkap.  sekian terimakasih.','nongkrong makan tugas zoom kerja bersih rapi aman sejuk awat strategis parkir luas mobil parkir bayar sayang harga akal fasilitas tawar suasana nikmat adem bagus pokok layan cepat fasilitas lengkap sekian terimakasih'),(90049,'Nakoa','Devoellory Khei',5,'3 tahun lalu','Salah satu workingspace yang bisa jdi pilihan untuk bekerja meeting or sekedang nongkrong sama teman\". Outdoor yang luas buat smw yg pengen ngumpul sama teman bisa bgt. Indoor juga bnyk kursi dan colokkan yang bsa d gunakan.','workingspace jdi pilih kerja kedang nongkrong teman outdoor luas smw ken nongkrong teman indoor kursi colok bsa'),(90050,'Nakoa','Adhet Si Kentang',5,'setahun lalu','Ini salah satu cafe yang nyaman banget buat nongkrong sih. Luas mau outdoor indoor ada, fasilita lengkap ada mushola juga. Dan kopi nya. Tuh beneran enak bangett. Harga nya juga aman sih.  Best lah','nyaman nongkrong luas outdoor indoor fasilita lengkap mushola tuh beneran nikmat harga aman'),(90051,'Nakoa','Lidwina Arin',4,'Diedit 3 tahun lalu','Harga terjangkau, tempat luas baik indoor maupun outdoor, tempatnya nyaman, dan makanan minumannya enak. Hanya saja waktu saya ke sini, sistem sedang eror sehingga tidak bisa menerima pesanan, dan harus menunggu sekitar 15 menit.','harga murah luas indoor outdoor nyaman makan minum nikmat sistem eror terima pesan tunggu menit'),(90052,'Nakoa','XP UP',5,'setahun lalu','Warung Kopi Kekinian di Malang yang tempatnya lumayan strategis, kopi rasanya oke, harga lumayan affordable, pelayanan baik.  parkir kendaraan agak sulit, apa lagi yang roda 4','warung lumayan strategis harga lumayan affordable layan parkir kendara sulit roda'),(90053,'Nakoa','M. Rizki Trianto',5,'9 bulan lalu','café estetik indoor-outdoor, kopi & snack Rp15–30k, Wi‑Fi kenceng + colokan komplet','caf indah indoor outdoor snack kenceng colok komplet'),(90054,'Nakoa','Sepdhyo Wahyu',5,'3 tahun lalu','Salah satu coffee shop di malang. Tempatnya bersih dan luas. Parkiran luas baik motor dan mobil. Pilihan menu banyak ada coffee dan non coffee. Pilihan snack banyak ada donat, croissant, dll. Ada ruangan indoor dan outdoor. Cocok untuk nongkrong dan mengerjakan tugas. Ada mushola. Kamar mendi harum dan bersih namun hanya ada 1 kamar mandi untuk tiap gender sehingga bisa antre lama jika kamar mandi tersebut dipakai. Saran saya bisa ditambah jumlah kamar mandinya. Selebihnya bagus. Recommended','bersih luas parkir luas motor mobil pilih menu pilih snack donat croissant dll ruang indoor outdoor cocok nongkrong tugas mushola kamar mendi harum bersih kamar mandi gender antre kamar mandi pakai saran kamar mandi bagus rekomendasi'),(90055,'Nakoa','Laily Amaniyah',4,'setahun lalu','Harga standart spt umumnya , tempat luas, wifi kenceng, kamar mandi bersih , pelayanan top , hanya satu menurut saya yg kurang mukena di musholla hanya 1 dan maaf bau nya tidak enak , tolong kalau bisa ditambahkan mukena lg mengingat pengunjung banyak yg sholat di situ , trimkasih','harga standart spt luas wifi kenceng kamar mandi bersih layan top mukena musholla maaf bau nikmat tolong mukena unjung sholat situ trimkasih'),(90056,'Nakoa','Susan Sun',5,'3 tahun lalu','Tempatnya enak dan harga juga bersahabat dengan kantong, taste enak, kopi gula arennya enak, dark Coco juga enak, cafe menyediakan tempat duduk indoor Dan outdoor, staf juga ramah, Lokasi strategis, parkir juga mudah. Recommended juga buat yang suka foto.','nikmat harga sahabat kantong taste nikmat gula nikmat dark coco nikmat sedia duduk indoor outdoor staf ramah strategis parkir mudah rekomendasi suka'),(90057,'Nakoa','Eka Edy',4,'2 tahun lalu','Tempat nyaman. Parkir mobil muat sekitar 7-8 an Parkir Motor luas. Makanan enak. Harga standart. Ada semi outdoor di belakang dan tempat merokok. Toilet bersih.','nyaman parkir mobil muat parkir motor luas makan nikmat harga standart semi outdoor rokok toilet bersih'),(90058,'Nakoa','Noval',5,'Diedit 3 tahun lalu','Sudah 4-6x kesini dan baru kasih ulasan.  Tempatnya nyaman untuk WFC tentunya, vibe kerja dan nugas nya bagus! Alasan satu2nya saya kesini, karena ini.  Area indoor cukup dingin, sedia outer & jaket just in case. Walau full window tapi ac nya dingin, takjub.  Area outdoor cenderung sepi di siang hari karena bener2 terbuka, bisa terik.  Toilet cuma dua, gak jarang harus ngantre ketika kebelet. Mohon dipertimbangkan.','kasih nyaman kerja vibe kerja tugas bagus alas area indoor dingin sedia outer jaket case full window dingin takjub area outdoor cenderung sepi bener terik toilet jarang ngantre kebelet mohon timbang'),(90059,'Nakoa','Nafiz Lucien',5,'3 tahun lalu','Tempatnya cozy dan mewah banget tapi harga bersahabat, tempatnya ada indoor ber ac dan outdoor. Untuk minuman banyak pilihan menu mulai dari coffe, milkbased, boba boba an, yogurt dan lain2. Snacknya juga enak2. Disini bukanya mulai dari jam 8.30 sampai 00.00 sama ada wifi toilet dan mushollanya juga','nyaman mewah harga sahabat indoor ber outdoor minum pilih menu coffe milkbased boba boba yogurt snacknya nikmat jam wifi toilet mushollanya'),(90060,'Nakoa','Nikmatul Azizah',5,'2 tahun lalu','Tempatnya luas, nyaman, wifi nya kenceng. Cuman untuk makanannya bisa ditambahkan makanan berat yang ada nasinya. Selebihnya worth it buat nugas karna banyak stop kontak, tapi kalo butuh konsentrasi tinggi di tempat yg bener2 hening kayak aku ini kurang rekomendasi sih karna pasti ada musiknya.','luas nyaman wifi kenceng makan makan berat nasi layak tugas stop kontak butuh konsentrasi bener hening rekomendasi musik'),(90061,'Nakoa','Maulidina Dafitri',5,'setahun lalu','Aku udah dua kali beli “Strawberry Cotton Candy” yang enak banget, sweetnya tuh pas dan ada ekstrak dari buah stroberinya. Temenku pesen matcha enak banget tapi kurang manis, kopinya juga best. Also the “Vanilla Milk Bun” enak kayak jastip di Thailand serius, ga ada bedanya. Untuk nongkrong atau mau ngerjain tugas oke banget sih.','beli strawberry cotton candy nikmat sweetnya tuh ekstrak buah stroberi temenku pesan matcha nikmat manis also vanilla milk bun nikmat jastip thailand serius beda nongkrong ngerjain tugas'),(90062,'Nakoa','ayu triutami',4,'setahun lalu','Tempat luas, croffle cheese bobanya enak, matcha latte nya agak kurang mantul sih ya, tempatnya luas tapi rasanya lebih cakep dan enak malam hari, kalo siang hari, nugas leptopan agak silau karena kaca smua sih..','luas croffle cheese bobanya nikmat matcha latte bagus luas cakep nikmat tugas leptopan silau kaca smua'),(90063,'Nakoa','Teddy Martono',5,'2 bulan lalu','Asik buat nongkrong, nugas, atau sekedar menghabiskan waktu. Minuman favorit tetap ice americano dan matcha nya wajib dicoba.','nyaman nongkrong tugas dar habis minum favorit ice americano matcha wajib'),(90064,'Nakoa','Novan C N',3,'3 tahun lalu','Tempatnya bagus dan lapang dengan tema industrial. Tempat duduk juga banyak bisa milih yg di indoor maupun outdoor. Meskipun crowded masih keliatan lapang karena ceilingnya tinggi. Untuk makanan dan minuman harganya terjangkau banget utk ukuran kafe, porsi juga besar. Yg bikin ga nyaman adalah pelayan cewek yg kaku banget. Pesan tambahan donat aja yg tinggal ambil di etalase, buat ngambil harus menunggu nama dipanggil. Untuk ngambil makanan nunggunya hampir sejam padahal ga order minuman. Pesan croissant juga lama karena harus diangetin dulu di microwave yg kecil. Parkiran sempit dan kalau penuh harus parkir di seberang jalan.','bagus lapang tema industrial duduk milih indoor outdoor crowded liat lapang ceilingnya makan minum harga murah ukur porsi nyaman layan cewek kaku pesan donat tinggal ambil etalase ngambil tunggu nama panggil ngambil makan nunggunya jam order minum pesan croissant diangetin microwave parkir sempit penuh parkir seberang'),(90065,'Nakoa','anggita frada',4,'3 tahun lalu','Suasananya enak banget, cocok buat wfh di pagi hari. Tapi kalo udah siang ke sore udah ramai banget. Minumannya oke aja, donutnya enak! Banyak colokan, tapi banyak semut merahnya juga, apalagi kalo lagi makan yg manis2, semutnya pada dateng ke meja yg deket jendela. Parah sih semutnya sakit bangetttt, semut merah soalnya 😭','suasana nikmat cocok kerja sore ramai minum donutnya nikmat colok semut merah makan manis semut meja deket jendela jelek semut sakit bangetttt semut merah'),(90066,'Nakoa','Syifa Nurazizah',4,'3 tahun lalu','Kesini pas weekdays siang-siang, sangat crowded. Cukup susah buat cari tempat duduk yang indoor. Pesannya cukup antri.  Kamar mandinya bersih. Cocok buat nugas. WiFi nya cukup kencang dan ada banyak stopkontak. Kopi dan makanannya standar.','weekdays crowded susah cari duduk indoor pesan antri kamar mandi bersih cocok tugas wifi kencang stopkontak makan standar'),(90067,'Nakoa','Satya Trisnasari',5,'Diedit setahun lalu','Jujur kalo di Nakoa daripada makanannya, tempat dan suasananya sih yang bikin nyaman dan pw puol buat nugas atau cuman ngobrol dan ketemu temen🫶 tapi tetep croissant dan kopinya oke sih☝️✨️','jujur makan suasana nyaman nyaman puol tugas ngobrol ketemu teman tetep croissant'),(90068,'Nakoa','Affif Surya Diantika Diantika',5,'4 tahun lalu','Tempatnya luas, ada indoor dan outdoor, terdapat fasilitas ac, colokan listrik, wifi, mushola. Toiletnya sangat bagus dan bersih, senang sekali tempat seramai itu masih memperhatikan kebersihan tolietnya. Tempat parkir mobil dan motor juga luas, tukang parkirnya juga sangat membantu. Makanan dan minuman rasanya enak sesuai dengan harganya. Pelayanannya juga sangat baik, cukup cekatan dan membantu, kebersihan juga selalu dijaga dengan baik, nongkrong di sini sejauh ini masih nyaman.','luas indoor outdoor fasilitas colok listrik wifi mushola toilet bagus bersih senang serama perhati bersih tolietnya parkir mobil motor luas tukang parkir bantu makan minum nikmat harga layan cekat bantu bersih jaga nongkrong nyaman'),(90069,'Nakoa','Kadek Luhur Nugraha',5,'3 tahun lalu','Terletak di daerah suhat sehingga tidak sulit mencarinya memiliki lahan parkir yang lumayan lebar, tempatnya besar dan nyaman, memiliki suasana yang chill dan comfy di indoor tidak boleh merokok sehingga suasana bebas asap, tenang buat kalian yang merokok terdapat area outdoor yg boleh untuk merokok, karena memiliki wifi yang kencang tetntu sangat enak untuk nongkrong, buat tugas atau sekedar menghabiskan waktu dengan membaca novel sambil menikmati coffe signature dari nakoa. @kd_luhur','letak daerah sulit cari milik lahan parkir lumayan lebar nyaman milik suasana chill nyaman indoor rokok suasana bebas asap tenang rokok area outdoor rokok milik wifi kencang tetntu nikmat nongkrong tugas dar habis baca novel nikmat coffe signature luhur'),(90070,'Nakoa','Yuan Ekatama Putra',5,'3 tahun lalu','tempat yang nyaman dan luas, menu yang beragam dengan harga yang cukup affordable. Rasa dari minumannya juara, terutama minuman yang mengandung rasa pisang, terasa mantap. Pemberian aksen lampu warm white yang tepat dan akurat membuat tempat ini nyaman baik indoor ataupun outdoor nya','nyaman luas menu agam harga affordable minum juara minum kandung pisang bagus aksen lampu warm white akurat nyaman indoor outdoor'),(90071,'Nakoa','Lita Prikas',5,'2 tahun lalu','Tempat untuk santai nongkrong sama pasangan maupun teman².. suasana nyaman ada indoor juga outdoor.. lokasinya strategis dan menurutku harganya worth it sesuai lah sama makanan dan minumannya..','santai nongkrong pasang teman suasana nyaman indoor outdoor strategis harga layak makan minum'),(90072,'Nakoa','Putri Tjondrokoesoemo',5,'Diedit 4 tahun lalu','tempatnya guede bgt! ac nya bener2 kerasa. semua sudutnya enak bgt buat helaing mata. menunya enak2. dessertnya juga enak. yg lebih enak lg bakal di panasin lg sebelum di kasih ke kita. kmaren pesen bomboloni coklat, alhasil filling coklatnya bener2 lumer','guede bener sudut nikmat helaing mata menu nikmat dessertnya nikmat nikmat panasin kasih kmaren pesan bomboloni coklat alhasil filling coklat bener lumer'),(90073,'Nakoa','Bella Larasati',4,'3 tahun lalu','Baru pertama ke nakoa suhat soalnya kata orang sih rame banget wkwk, dan ya ternyata benar emang rame banget. Memang posisinya lagi hari sabtu malam wajar aja sih kalau rame. Pas saya dateng habis maghrib sih didalam sudah rame, ngga antri waktu pesan. Pas jam 7 keatas wow langsung ruamai sampai antri antri diluar. Tempatnya lumayan luas sih, tapi sayang klau tempat seluas ini hanya ada 1 toilet untuk cewe dan 1 toilet untuk cowo. Dan sangat disayangkan juga kebersihan toilet di nakoa suhat sangat kurang. Banyak tisu2 yang penuh di toilet tapi tidak kunjung dibersihkan. Sangat berbeda dengan cabang nakoa yang lainnya. Plus nya sih sudah ada mushola disini, terimakasih. Kemudian saat saya memesan minuman dan makanan dari grab (pick up), saya langsung di arahkan ke tempat pick up tanpa ditanya mau dine in atau take away. Berbeda dengan nakoa lainnya, bisanya saya dikonfirmasi dulu pesanan saya di kasir dan ditanya dine in atau take away. Jadinya pas saya ngambil pesananan saya sudah dalam kondisi siap dibawa pulang, padahal saya mau dine in. Akhirnya saya bilang mas nya baru dibetulkan. Saran saja mungkin kedepannya kalau ada customer yang pickup dari aplikasi ojol bisa di konfirmasi terlebih dahulu mau dine in atau take away. Sukses selalu nakoa!','orang ramai wkwk emang ramai posisi sabtu wajar ramai habis maghrib ramai antri pesan jam wow ruamai antri antri lumayan luas sayang klau luas toilet cewe toilet cowo sayang bersih toilet tisu penuh toilet kunjung bersih beda cabang plus mushola terimakasih mes minum makan grab pick arah pick dine take away beda konfirmasi pesan kasir dine take away ngambil pesananan kondisi bawa pulang dine bilang mas saran customer pickup aplikasi ojol konfirmasi dine take away sukses'),(90074,'Nakoa','Mala Adwiaty',5,'3 tahun lalu','Toko blm buka tp sudah pd antri menunggu ya. Parkiran ckp luas. Harga snacknya 15-25rb, minumannya jg enak. Tempatnya luas,ada indoor dan outdoor,  klo ngobrol ga kedengeran meja lain hehe. Toiletnya bersih 👍','toko antri tunggu parkir ckp luas harga snacknya minum nikmat luas indoor outdoor ngobrol kedengeran meja hehe toilet bersih'),(90075,'Nakoa','Febby Cha',5,'Diedit 2 tahun lalu','Cafe Nakoa yg baru tepat ada diseberang sman9 Malang , arah mau ke perum. Permata Jingga . Tersedia berbagai macam kopi yg enak enak bgt , dan bbrp Snack ( tdk ada makanan berat ) . Rasa kopi 9/10 Snack 9 / 10 Utk tempatnya ada yg outdoor dan indoor , tempatnya sangat luas sekaliiii .','seberang sman arah perum permata jingga nikmat nikmat snack tdk makan berat snack outdoor indoor luas sekaliiii'),(90076,'Nakoa','Naiya Armesti',5,'2 tahun lalu','Ini termasuk kafe di Malang yang selalu ramai oleh orang nongkrong dan nugas. Katanya ada 4 cabang di sana? Keren! Aku suka konsepnya 🪐💡  Overall makanannya cukup bervariatif, mostly berupa cake dan pastry. Pastry dan donatnya enak, ga kalah sama merk terkenal lainnya. Harga menurutku masih standar kafe pada umumnya yah. Pelayanan oke juga.  Ada banyak tempat duduk baik di indoor maupun outdoor. AC-nya dingin juga. Wifi kencang.  Overall 9/10 💕','ramai orang nongkrong tugas cabang keren suka konsep makan variatif mostly cake pastry pastry donat nikmat kalah merk kenal harga standar yah layan duduk indoor outdoor dingin wifi kencang'),(90077,'Nakoa','Candra Tri Oktabrianto',5,'setahun lalu','Kesini karena diajakin teman, harganya terjangkau, tempat sangat luas dan mewah. Nyoba 2 es kopi yang namanya susah saya tulis, seinget saya ada colombian aren sama butterschot #cmiiw, keduanya sangat enak sekali. Ketersediaan wifi saya tidak tahu, karena tidak bertanya kepada pekerjanya, tapi sepertinya ada wifinya karena terlihat banyak mahasiswa/i, karyawan yang sibuk dengan pekerjaannya. Pekerjanya sangat ramah, dan penjelasan sangat detail ketika saya dan teman saya bertanya (semoga sehat selalu). Btw, ada banyak kue-kue juga.','diajakin teman harga murah luas mewah nyoba nama susah tulis seinget colombian butterschot cmiiw nikmat sedia wifi kerja wifi mahasiswa karyawan sibuk kerja kerja ramah detail teman moga sehat btw kue kue'),(90078,'Nakoa','Aiswara Denisya',5,'3 bulan lalu','Tempatnya nyaman cocok buat ngadete nugas dan wfc juga wifinya lancar padahal banyak yang pakai toilet bersih','nyaman cocok ngadete tugas kerja wifi lancar pakai toilet bersih'),(90079,'Nakoa','Mutina Wahyudi',4,'setahun lalu','Minumannya enak bangettt. Kalo makanannya juga enak sii, cuman bukan yang enak bangettt. Tempat nyaman, tempat duduk banyak, dingin, toilet proper dan bersih. Cocok banget buat nugas. Kebetulan juga jarak nakoa cabang yang ini dengan kosan deket banget. Hanya satu yang kurang, yaitu wiffinya agak lemot dan tiba-tiba logout sendiri. Mungkin bisa diperbaiki.','minum nikmat bangettt makan nikmat sii nikmat bangettt nyaman duduk dingin toilet proper bersih cocok tugas jarak cabang kosan deket wiffinya lot logout'),(90080,'Nakoa','Rezza Keppen',4,'setahun lalu','Gw kasih bintang banyak emang keren sih.. Apalagi ada printer nyaaaaa! Kita bisa pakai tapi bawa kertas sendiri. Cocok kalau lagi butuh print something bisa sekalian disini sambil nongkrong. Jarang ada cafe yg ada kayak giniannnya haha','kasih emang keren printer nyaaaaa pakai bawa kertas cocok butuh print something nongkrong jarang giniannnya haha'),(90081,'Nakoa','Satriyo Adi',5,'2 tahun lalu','Kalo menurut gw sih tempat ini harus jadi the best 10/10 muli dari makanan dan minuman nya sangatlah the best terus juga ada roti sosis walau ada rasa pedesnya bagi gw terus dekat dgn sekolah kakak ku bayangkan!!!','muli makan minum roti sosis pedesnya sekolah kakak bayang'),(90082,'Nakoa','Jeriko Agustinus',5,'4 tahun lalu','Tempatnya enak & bagus buat nonkrong, kerja kelompok, rapat tugas atau kerjaan proyek, ruanganya luas indoor maupun outdoor, untuk drink & food nya lumayanlah, tempat duduknya banyak, lahan parkirnya mencukupi untuk pengunjung, yang pasti desain bangunan & desain interior bagus sih keren, nyaman banget, udah berkali-kali ke sini, mantap lah, cewenya kesini juga pada cakep-cakep haha🤣🙏','nikmat bagus nonkrong kerja kelompok rapat tugas kerja proyek ruanganya luas indoor outdoor lumayan duduk lahan parkir unjung desain bangun desain interior bagus keren nyaman bagus cewenya cakep cakep haha'),(90083,'Nakoa','ARIEF R',5,'2 tahun lalu','Ok saja sih kalau untuk tempat nongkrong, konsep industrial. Banyak yang meeting klien non formal, kerjakan tugas, atau ngedate seperti saya. Kalau aspek rasa, relatif masing-masing lidah, ga spesial, tapi harga masih wajar lah dengan yang ditawarkan. Parkir akan mulai masalah kalau malam, peak hours. Di bagian belakang, yang mau out door, sambil merokok, ada tempatnya sendiri, bagus juga. Sayangnya WC hanya 1 saja untuk masing-masing laki-laki n perempuan.','nongkrong konsep industrial kerja klien formal kerja tugas ngedate aspek relatif lidah spesial harga wajar tawar parkir peak hours door rokok bagus sayang laki laki perempuan'),(90084,'Nakoa','Ayumei Wulandar',5,'Diedit 2 tahun lalu','Co working space ternyaman menurutku. Sudah coba berbagai cafe & co working di malang, ini yang paling nyaman, minim bising, tenang. Minumannya enak2, toiletnya sangat bersih dan wangi (poin plus)','working nyaman working nyaman minim bising tenang minum nikmat toilet bersih wangi poin plus'),(90085,'Nakoa','Rose Fiunnur Lina',5,'setahun lalu','Tempat yg enak bwt sekedar nongkrong, ngopi maupun ngobrol,,,😎🤩 Minuman sm makanan.nya enak,,,🤤😍','nikmat bwt dar nongkrong ngobrol minum makan nikmat'),(90086,'Nakoa','Dwi Isro\'atul Jannah',5,'4 tahun lalu','Dulu kesini masih soft opening, uda beda banget sekarang konsepnya lebih bagus. Luas & nyaman buat ngerjain tugas, indoor & outdoor sama2 aesthetic. Pilihan menu nya oke buat nongki cantik/ngerjain tugas.','soft opening uda beda konsep bagus luas nyaman ngerjain tugas indoor outdoor indah pilih menu nongkrong cantik ngerjain tugas'),(90087,'Nakoa','Tiang Blitar',5,'4 tahun lalu','Wahh . Cafe keren abis dah , dari tempatnya sangat cocok banget buat para kaum milenial untuk mengambil spot2 foto , terkhusus untuk anak muda yang suka foto2 termasuk para selebgram nih hehe . Tapi ketika malam Minggu . Yakin dah antriannya sepanjang harapan ku ke dia 🤭 ,Panjang banget ...jadi extra sabar ya broo ,oh iya tapi jangan kawatir ketika salah satu temen antri kamu juga harus tau menu2 nya dulu ya karena di meja gak ada daftar menu adanya di pamflet di Deket baristanya .','wahh keren abis dah cocok kaum milenial ambil spot khusus anak muda suka selebgram nih hehe minggu dah antri harap extra sabar broo iya kawatir teman antri tau menu meja daftar menu pamflet deket baristanya'),(90088,'Nakoa','Adrian N',4,'4 tahun lalu','Kalau datang weekend malam antrinya kayak ular hampir 1 jam, untuk harga tidak terlalu mahal kalau cuma buat pesen kopi atau minum. Juga buat snak2nya rasanya enak. Tempat ada indoor yang bagus buat foto2 tapi dinginn banget kalau malam. Enak diluar sejuk cuma kalau habis hujan bangkunya basah2 jdi kita lap sendiri.','weekend antri ular jam harga mahal pesan minum snak nikmat indoor bagus dinginn nikmat sejuk habis hujan bangku basah jdi lap'),(90089,'Nakoa','eliadaffa restanti',5,'3 tahun lalu','luasss mewah nyaman banget tempatnya.cocok buat anak kuliah nugas.meski cuma sediakan snack tapi aku suka croissant keju nya...bikin ga mau berhenti makan.kopi nya standar rata2 cabang nakoa enak.','luasss mewah nyaman cocok anak kuliah tugas sedia snack suka croissant keju henti makan standar cabang nikmat'),(90090,'Nakoa','David Ananta',4,'setahun lalu','Salah satu coffeeshop di malang yang cocok untuk bersantai dan kumpul bareng temen, tersedia berbagai macam pilihan makanan dan minuman, untuk harga standart tidak mahal dan tidak murah, untuk fasilitas juga lengkap. Tersedia indor dan outdor, colokan listrik, free wifi, toilet yang bersih','coffeeshop cocok santa kumpul bareng teman pilih makan minum harga standart mahal murah fasilitas lengkap indor outdor colok listrik free wifi toilet bersih'),(90091,'Nakoa','annisa marta',5,'3 tahun lalu','waktu ke malang kemarin aku nyoba mampir ke nakoa cafe, cafenya luass banget, adem juga, semi semi co workin space gitu  untuk ambience nya enak bgt, cocok untuk meeting, ngobrol, musik yg diputer juga bukan yang keras, banyak mahasiswa nugas juga  untuk rasa so so, harganya standar juga ga murah dan ga terlalu mahal  makanan mulai 9k, ada donat, eclair, sandwich, mentai dll','kemarin nyoba mampir cafenya luass adem semi semi workin ambience nikmat cocok kerja ngobrol musik puter keras mahasiswa tugas harga standar murah mahal makan donat eclair sandwich mentai dll'),(90092,'Nakoa','GALIH NUGROHO',5,'2 tahun lalu','Salah satu tempat rekomendasi untuk nongkrong bersama rekan kerja maupun teman-teman kuliah. Tempat nya cukup luas dan nyaman. Untuk harga masih masuk untuk kantong mahasiswa. Rasanya kopinya juga pas, donat nya enak.','rekomendasi nongkrong rekan kerja teman teman kuliah luas nyaman harga kantong mahasiswa donat nikmat'),(90093,'Nakoa','Afifah Hasya',5,'2 tahun lalu','Tempatnya luas, enak buat nugas, lagu cafe nya tenang, staff nya ramah semua, lighting nyaman di mata klo malam, harga affordable, desain bangunan dan interior cakep, cafe yg bersih selalu dipantau sama staffnya.','luas nikmat tugas lagu tenang staff ramah lighting nyaman mata harga affordable desain bangun interior cakep bersih pantau staffnya'),(90094,'Nakoa','Paul Mr',5,'3 bulan lalu','Kopinya enak banget, banana cake nya enak, service nya luar biasa, pelayanan ramah, tempat nyaman,  banyak mahasiswa nongkrong di sini,','nikmat banana cake nikmat service layan ramah nyaman mahasiswa nongkrong'),(90095,'Nakoa','Miew - All About Culinary',5,'setahun lalu','Comfort place for wfc Suasananya enakkk bngt bngt buat wfc Ac nya tp kdg terlalu dingin  Bev nya so so lah Price juga standar egak terlalu mahal Tempat wfc ternyaman si so far','comfort kerja suasana enakkk bngt bngt kerja kdg dingin bev price standar egak mahal kerja nyaman far'),(90096,'Nakoa','Sando Triwibowo',5,'2 tahun lalu','Tempatnya nyaman bersih, ada indoor & outdoor, buka sampe malem jam 12, pelayanan baik, enak buat nongkrong ato ngerjain kerjaan. Musik nggak kenceng banget jadi enak buat ngobrol2 👍','nyaman bersih indoor outdoor malem jam layan nikmat nongkrong ato ngerjain kerja musik kenceng nikmat ngobrol'),(90097,'Nakoa','Dariy Dzhofron',5,'Diedit 3 tahun lalu','Saya baru saja mengunjungi Cafe Nakoa di Suhat dan saya sangat senang dengan pengalaman saya di sini. Lokasi cafenya sangat nyaman dan tenang, dengan dekorasi yang modern dan elegan.  Ketika saya memesan minuman dan makanan, saya sangat terkesan dengan kualitas dan presentasi dari makanan yang disajikan. Semuanya sangat lezat dan segar, dengan porsi yang cukup besar dan harga yang sangat terjangkau.  Staf di Cafe Nakoa juga sangat ramah dan profesional. Mereka dengan senang hati memberikan rekomendasi tentang menu dan memberikan layanan yang sangat baik selama kunjungan saya.  Selain itu, fasilitas di Cafe Nakoa juga sangat lengkap dan modern, termasuk akses Wi-Fi gratis dan outlet listrik yang mudah dijangkau.  Secara keseluruhan, saya sangat merekomendasikan Cafe Nakoa di Suhat untuk semua orang yang mencari tempat makan yang berkualitas tinggi dengan harga yang terjangkau. Terima kasih kepada seluruh staf di Cafe Nakoa atas pengalaman yang luar biasa!','unjung senang alam cafenya nyaman tenang dekorasi modern elegan mes minum makan kes kualitas presentasi makan saji lezat segar porsi harga murah staf ramah profesional senang hati rekomendasi menu layan kunjung fasilitas lengkap modern akses gratis outlet listrik mudah jangkau rekomendasi orang cari makan kualitas harga murah terima kasih staf alam'),(90098,'Nakoa','c mayangs',5,'4 tahun lalu','Salah satu cafe dan coworking yang nyaman buat kerja wfh / nugas kuliah, me time, diskusi , sekedar nongkrong aja. Yang paling aku suka dr nakoa suhat ini tempatnya luas, rame dan musik instrumennya bikin tenang bgt. Harganya gak terlalu mahal start from 15 rb. Ada area outdoor, semi indoor  dan indoor ber AC','coworking nyaman kerja kerja tugas kuliah time diskusi dar nongkrong suka luas ramai musik instrumen tenang harga mahal start area outdoor semi indoor indoor ber'),(90099,'Nakoa','Dini',4,'3 tahun lalu','Tempat ngopi di malang. Pas datang kesana, cemilannya banyak yang ga ada. Pilihan minuman dan rasanya biasa saja. Memang bagus sih buat nongkrong atau mengerjakan tugas. Ada 2 area, ac dan non smoking.','kesana cemilannya pilih minum bagus nongkrong tugas area smoking'),(90100,'Nakoa','Auliya 83',5,'3 tahun lalu','cakenya ga kemanisan dan gabikin eneg, cuma ada beberapa minuman non coffe yang harus minta less sugar biar ga kemanisan eneg. garlic breadnya juga enak banget kalo masih hangat cheese nya melt','cakenya manis gabikin eneg minum coffe less sugar manis eneg garlic breadnya nikmat hangat cheese melt'),(90101,'Nakoa','Shabila Tharifa A',5,'3 tahun lalu','Lokasi sangat strategis. Tempatnya nyaman buat kumpul bareng temen. Terdapat area indoor maupun outdoor, banyak pilihan tempat duduk. Tersedia juga colokan buat yang mau nugas. Toiletnya bersih dan pelayanannya baik. Kalau kesini paling suka sama kopi gula arennya.','strategis nyaman kumpul bareng teman area indoor outdoor pilih duduk colok tugas toilet bersih layan suka gula'),(90102,'Nakoa','Arina Akmalia',5,'3 tahun lalu','Lumayan lama nunggu minuman. Giliran ditunggu g dipanggil² klau ndak di samperin dulu baru dikasih.huhuhu. tempat luas nyaman buat nongki² dan nugas.','lumayan nunggu minum gilir tunggu panggil klau samperin kasih huhuhu luas nyaman nongkrong tugas'),(90103,'Nakoa','erika aditya',5,'3 tahun lalu','Tempatnya worth it dan rekomended buat sekedar nongki, kerja WFA atau ngerjakan tugas baik sendiri atau rame-rame. Untuk yg outdoor juga bersih, rapi & angin sepoi-sepoi tp tidak rekomend milih duduk disini kalau pas musim hujan atau siang hari. Es kopi gula arennya juga enak, worth it lah dengan harga yg segitu. Pelayanan juga cepat, cocok banget buat me time, hangout dll.','layak rekomended dar nongkrong kerja kerja ngerjakan tugas ramai ramai outdoor bersih rapi angin sepoi sepoi rekomend milih duduk musim hujan gula nikmat layak harga segitu layan cepat cocok time hangout dll'),(90104,'Nakoa','annisa susdiarini',5,'setahun lalu','Sebuah tempat nongkrong (ada area indoor dan outdoor) yang nyaman dan cocok buat meeting, kerja via online, atau sekedar santai dengan orang tercinta atau teman, rasa minuman & makanannya juga enak, harga juga sesuai','nongkrong area indoor outdoor nyaman cocok kerja kerja via online dar santai orang cinta teman minum makan nikmat harga'),(90105,'Nakoa','Rahma M',4,'8 bulan lalu','Tempat nyaman bgt banyak colokannya buat ngecas, nugas nongkrong. Tapi untuk pastry nya 5/10 biasa aja.','nyaman colok ngecas tugas nongkrong pastry'),(90106,'Nakoa','Aryo Sanjaya',5,'3 tahun lalu','Tempatnya luas, banyak pilihan tempat duduk. Pilihan menunya juga variatif.  Suasananya juga nyaman, enak untuk berlama-lama di sini.  Tapi jika sedang ramai, maka siap-siap antri saat pesan makanan.','luas pilih duduk pilih menu variatif suasana nyaman nikmat ramai antri pesan makan'),(90107,'Nakoa','Ridho Prasojo',5,'7 bulan lalu','Gak pernah sepi pengunjung, kopi papuanya joss  Wifi cukup stabil','sepi unjung papuanya joss wifi stabil'),(90108,'Nakoa','andre winyoto',4,'setahun lalu','Tempat bagus, luas. Sekarang banyak tambahan snack sprti donut, croissant, dll. Suasana enak buat kerja atau meeting bersama kolega. Hanya saja kopinya terlalu encer dan kurang berasa, meskipun sudah upgrade ke Arabica beans.','bagus luas snack sprti donut croissant dll suasana nikmat kerja kerja kolega encer asa upgrade arabica beans'),(90109,'Nakoa','Resty Trisna',5,'4 tahun lalu','keliatan jelas bgt ini tempatnya lebih luas dari nakoa yg satunya lebih banyak tempat duduknya. untuk makanan minuman nya cita rasanya sama kek nakoa^ yg lain cuma disini kalo mau pesen dan nunggu pesanan lama bgtttt karna mas mas nya nunggu sampai beberapa minuman tersedia baru dipanggilin gitu toiletnya bagus kok dan bersih juga','liat luas duduk makan minum cita kek pesan nunggu pesan bgtttt mas mas nunggu minum dipanggilin toilet bagus bersih'),(90110,'Nakoa','Bagas Eka Pratama',5,'5 bulan lalu','Okelah, enjoy suasananya. Cuma americano disana ketika saya beli, watery rasanya. Kaya kurang kopinya mungkin. Lebih kebanyakan air','enjoy suasana americano beli watery kaya air'),(90111,'Nakoa','Theresia Lonika',4,'3 tahun lalu','Sukakk poll makin oke minumannya ... Plizz jangan ilangin menu choco avocadonya coz bbrp kali sdh gak ada. Cotton candynya sdh discontinued 😭','sukakk minum plizz ilangin menu choco avocadonya coz sdh cotton candynya sdh discontinued'),(90112,'Nakoa','Akhmad Yudo',4,'2 tahun lalu','salah satu kafe yang paling rame di Malang. harganya standar untuk kafe upper-middle class. saya beli roti, rasa enak (dipanasin terlebih dahulu). bobanya enak tetapi susah untuk diminum (nyangkut di sedotan). Sayang sekali tidak jual makanan berat dan untuk outdoornya kurang pencahayaan. meja yang besar & panjang cuma ada sedikit, kurang cocok untuk kumpul-kumpul rapat ringan/lainnya yg butuh meja. bisa sih kalau dapet mejanya yg panjang. bagian outdoor enaknya memang cuma untuk nongkrong saja.','ramai harga standar upper middle class beli roti nikmat dipanasin bobanya nikmat susah minum nyangkut sedot sayang jual makan berat outdoornya cahaya meja cocok kumpul kumpul rapat ringan butuh meja dapet meja outdoor enak nongkrong'),(90113,'Nakoa','yanles 11',5,'3 tahun lalu','Saya datang kesini ampuuunnn ramaiii amat sobat... nyamaaàaannn disini. Pokoknya tempat nongkrong anak muda nya kota malang sobat... duh ke sini deh kalo ke kota malang. Ga sah kalo ga kesini....','ampuuunnn ramaiii sobat nyamaa aannn pokok nongkrong anak muda sobat duh sah'),(90114,'Nakoa','faizul hafid',5,'setahun lalu','Tempatnya nyaman dan luas. Ada outdoor area di bagian belakang. Dan ada non smoking area yang tertata dan clean. Untuk harga masih cukup bersahabat untuk kantong kuliahan.','nyaman luas outdoor area smoking area tata clean harga sahabat kantong kuliah'),(90115,'Nakoa','putra edi',3,'Diedit 5 bulan lalu','Tukang parkirnya dikasih edukasi dong, masa parkir ga diarahin atau dibantu sama sekali giliran mau jalan pulang minta uang ga jelas','tukang parkir kasih edukasi parkir diarahin bantu gilir pulang uang'),(90116,'Nakoa','Rezky Dharmawan',5,'3 tahun lalu','Kopi lokal khas malang,yang hampir mirip sekelas Starbucks tapi versi Low Standar budget. Untuk rasa udah bintang 5 jadi jangan ragu untuk kesini. Kemarin saya pesen matcha cake Boba nya sangat manis dan enak.','lokal khas kelas starbucks versi low standar budget ragu kemarin pesan matcha cake boba manis nikmat'),(90117,'Nakoa','lusi wardhanie',5,'6 bulan lalu','Tempatnya emang enak buat nongki, ada indoor jg outdoor tinggal pilih aja.....','emang nikmat nongkrong indoor outdoor tinggal pilih'),(90118,'Nakoa','Ira wati',5,'2 tahun lalu','Menu kopi dan snack enak, pelayanan kondisional tergantung antrian. Suasana ramai jadi terkadang agak tidak kondusif untuk mengerjakan sesuatu. Pelayanan biasa saja terkadang ramah terkadang tidak. Colokan banyak dan memadai. Kecepatan wifi dulu bagus, namun saat ini agak lemot','menu snack nikmat layan kondisional gantung antri suasana ramai terkadang kondusif layan terkadang ramah terkadang colok cepat wifi bagus lot'),(90119,'Nakoa','Diantika Ambardina',5,'3 tahun lalu','Tersedia berbagai pastry dan kue yang enak. Minumannya juga oke dengan varian kopi dan non kopi. Tempat parkir cukup luas untuk mobil dan motor. Tempat bersih dan dingin. Cocok buat nugas, WFA, ataupun sekedar ngopi-ngopi cantik. Tersedia toilet dan musala.','pastry kue nikmat minum varian parkir luas mobil motor bersih dingin cocok tugas kerja dar cantik toilet musala'),(90120,'Nakoa','Zee Sherif',5,'3 tahun lalu','Ambiencenya enak bgt walau kadang rame tpi nyaman disinii harganya juga murah di banding cafe yg lain krn gaada tax tax tambahan. Kamar mandinya okelah ada musholla juga.','ambiencenya nikmat kadang ramai nyaman harga murah banding gaada tax tax kamar mandi musholla'),(90121,'Nakoa','missilmyra',5,'Diedit 3 tahun lalu','Kafe dengan gaya kekinian, cocok bagi anda yg mencari ambience yg bagus untuk feed sosial media. Pengunjung di dominasi kaum millenial dan GenZ yg rata2 sibuk dengan laptop. Kafe ini hanya menyediakan kopi2an dan jajanan ringan seperti donat,croissant dan sejenisnya, jadi jangan harap menemukan makanan berat ya..😆. Untuk harga kopi kisaran  20-35k, sedangkan cemilan 18-30k.','gaya cocok cari ambience bagus feed sosial media unjung dominasi kaum millenial genz sibuk laptop sedia jajan ringan donat croissant jenis harap temu makan berat harga kisar cemilan'),(90122,'Nakoa','Probo Nogoya',5,'3 tahun lalu','Tempat mahasiswa dan mahasiswi berkumpul, dengan jumlah parkiran motor terbanyak namun jumlah parkiran mobil terbatas. Tempat nyaman untuk meeting bumble dan kopi selagi tugas akhir','mahasiswa mahasiswi kumpul parkir motor parkir mobil batas nyaman kerja bumble selagi tugas'),(90123,'Nakoa','Lusi Agustina',5,'Diedit 11 bulan lalu','suka cakenya :> banyak stopkontak jadi pw bgt lah buat nongki atau nugas, cuma kurang kenceng','suka cakenya stopkontak nyaman nongkrong tugas kenceng'),(90124,'Nakoa','Ceacilia Erma',5,'3 tahun lalu','Untuk harga sangat terjangkau Menyediakan tempat outdoor dan indoor Cocok untuk ngopi bersama keluarga juga Mushola ✅ WiFi ✅ Toilet ✅ Parkir r4&R2 ✅','harga murah sedia outdoor indoor cocok keluarga mushola wifi toilet parkir'),(90125,'Nakoa','Dayana Hidayat',5,'3 tahun lalu','Tempat luasssss bgt, ada indoor ada outdoor...always rame but ramenya tuh bukan rame berisik, suasananya meskipun rame tpi tenang gitu. WiFi kencengnya jangan diragukan 👍🏻 banyak yg nugas disini Makanan minuman okeoke aja ❤️ …','luasssss indoor outdoor always ramai ramenya tuh ramai berisik suasana ramai tenang wifi kenceng ragu tugas makan minum okeoke'),(90126,'Nakoa','nona zesifa',5,'2 tahun lalu','🌷Luas banget tempatnya, cocok buat nongki ramean, bagian indoor banyak yg pada nugas, bagian outdoor depan banyak yg pada nongki ramean, bagian taman banyak yg pada nongki ramean juga  🌷Minuman nya seperti di chatime, rasanya manis semua, cocok buat ciwi” karena rasa kopinya kurang menurutku  🌷Pelayanan nya cukup bagus, disini tuh self service, jadi tunggu pesanan kmu untuk dipanggil lalu kamu cari tempat duduk  🌷Jangan lupa cup nya langsung dibuang ditempat sampah yagesya bantu baristanya dan customer selanjutnya yg hendak duduk disitu','luas cocok nongkrong ramean indoor tugas outdoor nongkrong ramean taman nongkrong ramean minum chatime manis cocok ciwi layan bagus tuh self service tunggu pesan kmu panggil cari duduk lupa cup buang sampah yagesya bantu baristanya customer duduk situ'),(90127,'Nakoa','Miftah Farizt',5,'2 tahun lalu','Tempatnya enak nyaman banget apalagi buat kerja dan ngerjain tugas, tapi siang2 aja ya soalnya kalo malam pasti rame banget. AC nya juga dingin banget, minuman makanannya enak2 dan harga masih terjangkau. Tempatnya luas banget ada indoor dan outdoornya.','nikmat nyaman kerja ngerjain tugas ramai dingin minum makan nikmat harga murah luas indoor outdoornya'),(90128,'Nakoa','Kalunas Skin',5,'2 tahun lalu','Udah paling bener WFC di Nakoa suhatt! Wifinya kenceng, ga begitu rame, colokan banyak, tempatnya enak bangett😍✨ minusnya, AC di dalem duingin bangettt kakk!🤣 Tapi selalu oke dan bisa seminggu 2-3x wfc disini wkwk','bener kerja suhatt wifi kenceng ramai colok nikmat minus dalem duingin bangettt kakk minggu kerja wkwk'),(90129,'Nakoa','agyl ph',5,'2 tahun lalu','Tempat nongkrong nyaman di suhat, luas nyaman dan cocok buat nugas buka laptop (banyak colokan)','nongkrong nyaman luas nyaman cocok tugas laptop colok'),(90130,'Nakoa','Yeyen Ikawidyawati',5,'2 tahun lalu','Pastry & minumannya lumayan enak, tapi untuk level less sugar menurutku masih cukup manis (kebetulan aku kurang suka manis). Tapi recommend banget untuk yg mau ngerjain tugas, zoom meet dll. 👍🏻👍🏻','pastry minum lumayan nikmat level less sugar manis suka manis recommend ngerjain tugas zoom meet dll'),(90131,'Nakoa','Adellia',5,'3 tahun lalu','Tempatnya bagus, tapi kalo malem ramee banget dan antrinya lama sampe mengular, harga makanan dan minumannya sih masih cukup terjangkau lah','bagus malem ramai antri ular harga makan minum murah'),(90132,'Nakoa','icoow',5,'setahun lalu','Untuk segi harga bisa dibilang agak mahal daripada tempat lain, tapi Nakoa Suhat jauh lebih nyaman buat nugas atau me time. Indoornya dingin banget AC nya, lumayan banyak colokan juga (kecuali yang duduknya di tengah-tengah).  Menunya enak semua terus sekarang pemesanan bisa lewat aplikasi Nakoanya sendiri jadi lebih enak. 🤩🤩🤩','segi harga bilang mahal nyaman tugas time indoornya dingin lumayan colok kecuali duduk menu nikmat mesan aplikasi nakoanya nikmat'),(90133,'Nakoa','Agung Prasetyo',5,'setahun lalu','16 November 2024/malam  Tempatnya cozy & kopinya enak. Lokasinya luas & strategis, tempat duduknya juga banyak (indoor & outdoor).','november nyaman nikmat luas strategis duduk indoor outdoor'),(90134,'Nakoa','Grady Febrian',5,'3 tahun lalu','Tempatnya luas, nyaman, staff juga ramah\". Harga juga terbilang worth it, waktu itu pesen Caramel Latte (large) 24k, dan Garlic Bread 20k. Semua harga menu disini sudah nett, ga ada ppn dll. Garlic Bread nya uenakkk parah sih. Next kalo ke Malang bakal kesini lg','luas nyaman staff ramah harga bilang layak pesan caramel latte large garlic bread harga menu nett ppn dll garlic bread uenakkk jelek next'),(90135,'Nakoa','Nizzar Mizzukane',4,'2 tahun lalu','NAKOA CAFE SUHAT • Nakoa Cafe Suhat terletak di JI. Puncak Borobudur No. G502, Mojolangu, Kec. Lowokwaru, Kota Malang, Jawa Timur 65142 • Parkiran Luas, tempat Luas • Tempatnya modern banget Futuristik • Cafe Shop, sekalian tempat Unoan terbaek • Randomnya masyarakat Malang tua muda ngumpul, • Ngerjain tugas ya okay bagi anak Perantau bosen di kosan, • Menunya Bevarege kurang perkopianya, tapi ada Maggo itu yang enak • Main Course walaupun cuman Sandwch dan Roti Rotian tergolong enak • Harga masih boleh lah dengan tempat yang ditawarkanya • Buat yang renuian sama temen Kuliah di Malang rekomendasi banget','letak puncak borobudur mojolangu kec lowokwaru jawa timur parkir luas luas modern futuristik unoan terbaek randomnya masyarakat tua muda nongkrong ngerjain tugas okay anak rantau bosen kosan menu bevarege perkopianya maggo nikmat main course sandwch roti roti golong nikmat harga ditawarkanya renuian teman kuliah rekomendasi'),(90136,'Nakoa','Andre Leonardo',3,'6 bulan lalu','Pelayan cepat, tempat bersih, minuman kopi gula aren nya oke, tapi untuk snack / kue nya kurang enak untuk yang manis atau pun donatnya','layan cepat bersih minum gula snack kue nikmat manis donat'),(90137,'Nakoa','L Gaol',5,'2 tahun lalu','Tempatnya luas, adem, tenang dan sangat nyaman.  Dari luar sudah kelihatan megah. Tapi tenang, harga aman dikantong.  Indoor & outdoor sangat kece.','luas adem tenang nyaman megah tenang harga aman kantong indoor outdoor kece'),(90138,'Nakoa','Fitri Indah Permata',5,'5 bulan lalu','Seriuss nyobain kesini ternyata tempatnya nyaman pwol, cocok buat wfc dan nugasable banget, trus pas cobain teh nya juga premium pwol, kemasannya cakep .','seriuss nyobain nyaman cocok kerja nugasable cobain teh premium kemas cakep'),(90139,'Nakoa','Benny Thama',5,'Diedit 11 bulan lalu','Tempat nongkrong yang recommended ni.. lokasi mudah ditemukan.. tempatnya luas ada outdoor maupun indoors yg tentunya instagramable.. pelayanan juga cepat.. tersedia menu kopi dan non kopi kue2 juga ada dengan harga yg bersahabat.. pembayaran juga gampang bisa pake qris.. tersedia colokan buat hp/laptop.. toilet bahkan musola.. parkiran juga luas.. recomanded dah pokoknya','nongkrong rekomendasi mudah temu luas outdoor indoors indah layan cepat menu kue harga sahabat bayar gampang pakai qris colok laptop toilet musola parkir luas recomanded dah pokok'),(90140,'Nakoa','Auryno Nagata',5,'setahun lalu','Suasanya nyaman bnaget buat nugas music nya bikin relax, mushola sama kamar mandi nya juga nyaman harganya pun affordable Langganan buat nugas mah klo di nakoa suhat','suasa nyaman bnaget tugas music relax mushola kamar mandi nyaman harga affordable langgan tugas'),(90141,'Nakoa','AMIRUDDIN FARID MUKHTADI',4,'3 tahun lalu','tmpat bnyak, menu ok, tp toiletnya cm 1 bilik aja jd klo ke toilet antri bgt','tmpat bnyak menu toilet bilik toilet antri'),(90142,'Nakoa','Okta Saskia Dwi Putri',5,'2 tahun lalu','Tempatnya luas, cocok untuk nongkrong sama temen atau keluarga ataupun pacar, tersedia wifi yang cocok untuk mahasiswa mengerjakan tugas di tempat ini, makanan dan minumannya ramah kantong mahasiswa, banyak colokan juga, rekomen pokoknya buat mahasiswa, kalo ke malang jangan lupa mampir ke Nakoa Cafe Suhat ya🤏🏻','luas cocok nongkrong teman keluarga pacar wifi cocok mahasiswa tugas makan minum ramah kantong mahasiswa colok rekomendasi pokok mahasiswa lupa mampir'),(90143,'Nakoa','carissa klaire',5,'4 tahun lalu','sering kesini, menunya murah murah, tempat luas, enak buat nugas, harus cepet cepetan cari bangku karna cepet bgt fullnya','menu murah murah luas nikmat tugas cepat cepetan cari bangku cepat fullnya'),(90144,'Nakoa','Irfan Aufa',5,'3 tahun lalu','Minuman tastenya OK, standard coffee shop umumnya. Saya pesan Kopi Gula Aren, rasanya pas untuk saya yg bukan penikmat kopi harian. Saya pernah coba di tempat lain Kopi Gula Aren tapi tingkat keasamannya cukup tinggi dan pengaruh ke kesehatan saya. Di nakoa, saya baik2 saja setelah menenggak menu tsb. Suasana cafe nya cozy, enak untuk nongkrong santai dan tidak berisik. Minus nya mungkin agak bingung jika sendirian saat menunggu pesanan selesai karena sambil berdiri dan belum dapat tempat duduk.','minum tastenya standard pesan gula nikmat gula tingkat asam pengaruh sehat tenggak menu tsb suasana nyaman nikmat nongkrong santai berisik minus bingung tunggu pesan selesai duduk'),(90145,'Nakoa','Yulia Yuyun',4,'3 tahun lalu','Tempatnya luas ada outdoor dan indoor yg sejuk, minuman yg bervariasi. Lokasinya Mudah diakses dan tempat parkir yg lumayan luas juga','luas outdoor indoor sejuk minum variasi mudah akses parkir lumayan luas'),(90146,'Nakoa','Fathi Aidiya Farisa',5,'2 tahun lalu','kafe yang estetik sekaligus fungsional banget imo. cocok buat yg mau nugas, ngantor wfa, cocok untuk yg mau kerja sendirian bisa mojok, yg mau ramai-ramai juga ada meja panjang untuk banyak orang. kopinya hampir semuanya enak (belum semuanya dicoba) dan snack nya enak semua terutama yg manis2 😭💕  (-) kadang-kadang AC nya kebesaran jd terlalu dingin 🥶','indah fungsional imo cocok tugas ngantor kerja cocok kerja mojok ramai ramai meja orang nikmat snack nikmat manis kadang kadang dingin'),(90147,'Nakoa','Dewi Wijayanti',5,'setahun lalu','tempat nongki yg cocok bagi semua umur, tempatnya nyaman suasana sore hari sangat cocok utk bersantai sambil bekerja','nongkrong cocok umur nyaman suasana sore cocok santa'),(90148,'Nakoa','QQ Febri',4,'setahun lalu','Makanan kurang sip...minuman yg enak coffe nya saja yg non coffe kurang mantep...','makan sip minum nikmat coffe coffe mantep'),(90149,'Nakoa','yoseph dio',5,'3 tahun lalu','salah satu tempat cozy di malang,, sangat cocok untuk mahasiswa yg demen ngopi manja sambil ngerjain skripsi indoor nya dingin, nyaman, harga menu nya juga terjangkau','nyaman cocok mahasiswa demen manja ngerjain tugas indoor dingin nyaman harga menu murah'),(90150,'Nakoa','Anastasia Zulkarnain',4,'3 tahun lalu','Rame banget, full. Walaupun parkiran sdh cukup luas. Tapi masih tetap saja susah kebagian tempat parkir kalau lagi bawa mobil. Antrian pesanan juga kurleb 10-20 menit. Kalau 2 org atau lebih. Sebaiknya 1 org antri, yg lainnya cari tempat. Karena disini full banget. Kalau suasananya memang enak dan nyaman.','ramai full parkir sdh luas susah parkir bawa mobil antri pesan kurleb menit org org antri cari full suasana nikmat nyaman'),(90151,'Nakoa','Silmina Silmina',5,'setahun lalu','Ga tau ya seneng aja kalo ngopi dsni, udh langganan lama, mulai buka di jl bondowoso, sampe punya bbrpa cabang. Menu enak2, selama ini ga ada yg zonk sih. Sama yg paling ptg tuh ada mushola, mau ngopi lama pun aman','tau neng dsni udh langgan bondowoso bbrpa cabang menu nikmat zonk ptg tuh mushola aman'),(90152,'Nakoa','sekar',4,'4 tahun lalu','Untuk harga cukup terjangkau baik buat mahasiswa pun keluarga.. buat ngobrol2 vibe nya enak dan bersih.. Untuk rasa makan dan minum so so lah.. biasa.. Kalau kesini kudu pakai hang out kece krn buat spot spot foto cukup bagus. Cashiernya kurang cak cek, kurang cekatan dan terlalu banyak ngobrol. Sepertinya juga kurang bantuan cashier krn kalau pas in line.. antri... Wah lamaaa banget selesainya ..','harga murah mahasiswa keluarga ngobrol vibe nikmat bersih makan minum kudu pakai hang kece spot spot bagus cashiernya cak cek cekat ngobrol bantu cashier line antri lamaaa selesai'),(90153,'Nakoa','Just Ndy',5,'3 tahun lalu','Asik buat nongkrong rame“... Kurangnya dikamar mandi cuman ada 1 buat masing² gender. Jadi klo ada yg boker antri nya bisa mayan lama... Usahakan buat yg dah krasa belet BAK lgsg aja...','nyaman nongkrong ramai kamar mandi gender boker antri mayan usaha dah krasa bet bak lgsg'),(90154,'Nakoa','Gufron Santoso',5,'4 tahun lalu','Tempat nongkrong yg nyaman luas+bersih...ada smoking area outdoor...nongkrong bisa berjam2 sambil ngerjakn tugas campus maupun kantor...anak2 betah dsini..harga sbanding dg fasilitas yg diterima','nongkrong nyaman luas bersih smoking area outdoor nongkrong jam ngerjakn tugas campus kantor anak betah dsini harga sbanding fasilitas terima'),(90155,'Nakoa','Afrilia Nahumarury',4,'2 tahun lalu','Kopinya okee, tapi bukan yg enak banget. Lebih ke kopi yg manis semacam kopi kekinian. Pesen hot cappucino dg biji kopi yg strong, no sugar, rasanya oke, mantap. Tapi buat kopi susunya terlalu manis. Bomboloninya empuuukk enakk  Tempat dan ambiencenya oke banget!! Juara! Colokan melimpah, enak buat nongkrong dan kerja. Tempatnya modern, bersih, instagramable. AC dingin, space outdoornya juga oke punya.','okee nikmat manis pesan hot cappucino biji strong sugar bagus susu manis bomboloninya empuuukk nikmat ambiencenya juara colok limpah nikmat nongkrong kerja modern bersih indah dingin outdoornya'),(90156,'Nakoa','Cakim uCi',5,'4 tahun lalu','Nyaman, tempatnya luas, pilihan kopinya juga banyak, cocok ngajak anak kecil Kalo saya sih suka pas pagi2 masih sepi enak 😊 …','nyaman luas pilih cocok ngajak anak suka sepi nikmat'),(90157,'Nakoa','Gold De Edyson',5,'8 bulan lalu','Cozy dan ada ruangan outdoor di dlm nya','nyaman ruang outdoor dlm'),(90158,'Nakoa','Dennis Hartanto',5,'setahun lalu','Tempat ngopi yang Cozy dan harga bersahabat. Cocok juga sebagai working space','nyaman harga sahabat cocok working'),(90159,'Nakoa','Putri Candra',4,'2 tahun lalu','Tempatnya cozy, cocok buat nongkrong sama temen atau ngerjain tugas. Kopinya juara, enak banget rasanya. Varian dessertnya juga beragam, dari yang manis sampe yang gurih. Pelayanannya ramah, fasilitas ada tempat parkir, musholla, dan toilet.','nyaman cocok nongkrong teman ngerjain tugas juara nikmat varian dessertnya agam manis gurih layan ramah fasilitas parkir musholla toilet'),(90160,'Nakoa','baby adelia',5,'2 tahun lalu','udh jdi tempat langganan aku waktu jugas bgt sih. walaupun rame disini sangat mendukung untuk mengerjakan tugas karna disediakan banyak stop kontak pokoknya best banget deh','udh jdi langgan jugas ramai dukung tugas sedia stop kontak pokok'),(90161,'Nakoa','Rendy Akbar Wicaksono',5,'setahun lalu','Menurutku cafe yang sangat nyaman untuk di kunjungi. Wifi, Colokan, Musholla 👍','nyaman kunjung wifi colok musholla'),(90162,'Nakoa','Dimas Alifandra',4,'4 tahun lalu','Datang ke sini 4 Januari. Rameee antri ga abis abis. Makanan yaa seperti nakoa cabang lainnya lah, mayan, es kopi juga ttp enak, tempat cozy, adem. Plus plus nya di sini ada Mushola nya. Alhamdulillah. Di nakoa yg lain (sejauh yg saya tau waktu kesana) tidak ada. Mantap lah','januari rameee antri abis abis makan yaa cabang mayan ttp nikmat nyaman adem plus plus mushola alhamdulillah tau kesana bagus'),(90163,'Nakoa','Reiny Lukitasari',5,'3 tahun lalu','Tempatnya nyaman, area cukup luas...indoor dan outdoor di halaman belakang, cukup enak kalo untuk yg suka ngopi sambil ngerjain tugas, menu kopi lumayan dan cukup beragam dan yang terpenting tersedia jalan untuk kursi roda 👍','nyaman area luas indoor outdoor halaman nikmat suka ngerjain tugas menu lumayan agam kursi roda'),(90164,'Nakoa','Retno Ayu S',4,'2 tahun lalu','Tempat oke. Pesan harus di kasir. Pesanan harus ambil sendiri juga. Menunya terbatas.','pesan kasir pesan ambil menu batas'),(90165,'Nakoa','Ismail Fahmi',5,'2 tahun lalu','paling enak nongki disini, luas dan suasananya outdoornya bikin betah, makanan dan minumannya juga variatif, cocok buat mahasiswa untuk nugas (wifi kenceng+banyak colokan)','nikmat nongkrong luas suasana outdoornya betah makan minum variatif cocok mahasiswa tugas wifi kenceng colok'),(90166,'Nakoa','Embun Jiwa',4,'3 tahun lalu','Selalu ramai tiap mlm. Harga makanan normal seperti di cafe2 kota pada umumnya. Ada indoor & outdoor area. Rasa minuman alhamdulillah ok lah','ramai mlm harga makan normal indoor outdoor area minum alhamdulillah'),(90167,'Nakoa','D purnomo',5,'setahun lalu','Tempat luas, cozy, cocok utk ngerjain tugas atau sambil berdiskusi. Ada indoor dan outdoor','luas nyaman cocok ngerjain tugas diskus indoor outdoor'),(90168,'Nakoa','Alberto',5,'2 tahun lalu','Hal kecil yang tidak diperhatikan cafe lain tapi ada di nakoa: toilet bersih dan selalu ada tisu. Sabun cuci tangan juga ga pernah abis. Kakak barista/kasir yang namanya Dhava juga ramah banget. Ini semua jadi bikin balik terus ke nakoa di era gempuran coffee shop lain karena emang senyaman itu.','perhati toilet bersih tisu sabun cuci tangan abis kakak barista kasir nama dhava ramah era gempur emang nyaman'),(90169,'Nakoa','Sherly Kesuma',4,'2 tahun lalu','Tempatnya luas, nyaman dan adem walau di luar panas. Parkir lumayan. Minuman oke walau buatku kemanisan tapi ya bisa di adjust. Makanan pesen beef croffle biasa aja','luas nyaman adem panas parkir lumayan minum manis adjust makan pesan beef croffle'),(90170,'Nakoa','Miftah Faridl',5,'Diedit 3 tahun lalu','Dekorasi, menu, & suasananya oke banget. Untuk nugas oke, buat nongkrong jg oke ☺','dekorasi menu suasana tugas nongkrong'),(90171,'Nakoa','Khoirotun Nissak',5,'2 tahun lalu','All fasilitas good dan bersih, untuk harga masio oke bgt dan enak\" juga makanannya mantap dah pokoknya nakoa Silahkan berkunjung kakaq','fasilitas bagus bersih harga masio nikmat makan bagus dah pokok silah kunjung kakaq'),(90172,'Nakoa','Dian Purwanto',5,'Diedit 3 tahun lalu','Enak banget buat nongkrong sambil nugas atau hanya sekedar refreshing. Paling favorit sama es kopi susu gula aren dan donat green teanya 👍👍👍👍👍','nikmat nongkrong tugas dar refreshing favorit susu gula donat green teanya'),(90173,'Nakoa','mirza viona',4,'2 tahun lalu','outdoornya comfy bgt, disini nyaman soalnya meja satu sm lain ga keganggu kl lg  nongki. tenang suasananya','outdoornya nyaman nyaman meja ganggu nongkrong tenang suasana'),(90174,'Nakoa','Ratna Tri Maharani',5,'2 tahun lalu','Satu-satunya tempat ternyaman untuk laptopan siih nakoa ini. Disini menyediakan banyak colokan listrik dengan meja kursi yang memadai untuk bekerja atau mengerjakan tugas.  Selain itu minuman disini belum ada yg fail siiih. Tapi tetep yg paling favorit caramel lattenya dan bisa request extra ice dan less sugar looh. Sayangnya disini tuh gaada makanan berat kyk nasi2an gitu. Tapi gpp karena ada sandwich yang mengenyangkan.','nyaman laptop siih sedia colok listrik meja kursi tugas minum fail siiih tetep favorit caramel lattenya request extra ice less sugar looh sayang tuh gaada makan berat kyk nasi sandwich kenyang'),(90175,'Nakoa','yaya anastasia',5,'Diedit 2 tahun lalu','Salah satu tempat WFC sendirian terbaik di Malang. Meja nyaman buat laptopan, parkir luas, tempat duduk banyak dan areanya luas, ada indoor dan outdoor, dan ada Musholla juga!  Jajanannya banyak, murah2. Tapi, minusnya disini ga ada makanan berat 🥹','kerja bagus meja nyaman laptop parkir luas duduk area luas indoor outdoor musholla jajan murah minus makan berat'),(90176,'Nakoa','Cut Febrinahps',5,'2 tahun lalu','2x coba caramel macciato nya enak pas sesuai request, dan nyoba beef sandwichnya juga enak, tapi mungkin kurang panas dikit. Tpi keseluruhan enak dan harga nya juga worthit banget. Enak','caramel macciato nikmat request nyoba beef sandwichnya nikmat panas dikit nikmat harga layak nikmat'),(90177,'Nakoa','Kelas Manajemen L',5,'2 tahun lalu','enak banget makanan sama minumannya, tempatnya juga oke bangett!! bisa buat nongki dan nugas. cafenya asthetic, suka bgt!! kamar mandi sama mushollanya juga bersih banget. keren.','nikmat makan minum nongkrong tugas cafenya indah suka kamar mandi mushollanya bersih keren'),(90178,'Nakoa','Gusti Fachrul Ardiansyah',5,'2 tahun lalu','masukan aja, jika minta review minimal ada benefit apa gt dong gan, diskon 10% untk snack atau minuman minim pembelian brp kan lumayan ada omset lagi','minimal benefit gan diskon untk snack minum minim beli brp lumayan omset'),(90179,'Nakoa','One7 Nine5',5,'3 tahun lalu','Tempat nyaman, makanan enak, wifi cepat, fasilitas mushola, toilet, suka bgt nugas disini maupun nongkrong','nyaman makan nikmat wifi cepat fasilitas mushola toilet suka tugas nongkrong'),(90180,'Nakoa','Enggar Ambari Laksmi',4,'3 tahun lalu','Suasana nyaman, tempat luasa .. Sayang camilannya cm donat, roti, croisan .. ga ada yg asin2 🤤','suasana nyaman luasa sayang camil donat roti croisan asin'),(90181,'Nakoa','Ririh Widayati',4,'setahun lalu','Tempatnya luas dan nyaman, cocok untuk mengerjakan tugas berlama2 terutama pelajar/mahasiswa. Cocok utk penikmat kopi ringan dan susana yg nyaman','luas nyaman cocok tugas ajar mahasiswa cocok nikmat ringan susana nyaman'),(90182,'Nakoa','Netflixku Hehehehe',5,'2 tahun lalu','Hari ke hari kalau mau wfc pasti pindah2 kofisyop, tapi tetep comfort placenya ke Nakoa hahaha. Colokan banyak, harga minumannya affordable, ac dingin, wc bersih, wifi kuencengg, dan nyaman aja karena yg kesini rata2 laptopan semua. Jadi selalu ngerasa ada temennya.','kerja pindah kofisyop tetep comfort placenya hahaha colok harga minum affordable dingin bersih wifi kuencengg nyaman laptop ngerasa temennya'),(90183,'Nakoa','Mohammed Emrany',4,'Diedit 2 tahun lalu','Kafe yang tenang, indah, bersih, berkelas..Bisa duduk di lorong atau di luar ruangan. Pekerjanya ramah. Makanan penutupnya enak dan ada beberapa pilihan...','tenang indah bersih kelas duduk lorong ruang kerja ramah makan nikmat pilih'),(90184,'Nakoa','Ziyaany Naavilah',5,'setahun lalu','Tempat luas, cocok buat nugas/nongkrong/nyantai','luas cocok tugas nongkrong nyantai'),(90185,'Nakoa','Lilian Gan',5,'3 tahun lalu','Can i give a 7 stars? Ternyata tempat ini sangat ramah anak. Walau belum disediakan baby chair, tetapi lokasinya so good buat anak. Bisa di indoor ataupun di outdoor. They can enjoy the place. Snack yang disediakan juga acceptable sama anakku yg usia 1th dan 2.5th. Walau banyak menu kopi, ada juga menu2 non coffee yg tentu bs buat anak2. Ada juga anak2 SD yang diajak ksini oleh orang tuanya. Pelayanannya? Sangat sangat sangat baik. Mereka mengerti kerempongan mama2, dibantu potong2kan crofflenya. Ditanya apakah bisa bawa sendiri atau perlu dibantu. Yang awalnya ragu untuk bawa anak, jadi merasa nyaman disini. Thank you nakoa Suhat! U deserve a 7 stars... or ten? 😄  IG @liliangandawidjaja','give stars ramah anak sedia baby chair bagus anak indoor outdoor enjoy snack sedia acceptable anak usia menu menu anak anak ajak ksini orang tua layan erti rempong mama bantu potong crofflenya bawa bantu ragu bawa anak nyaman thank deserve stars ten liliangandawidjaja'),(90186,'Nakoa','Riris Hartanti',5,'2 tahun lalu','Cozy, and simply lovely. Cocok banget buat nugas, ada menu paketan juga yang ramah di kantong. Recommended deh 👍','nyaman simply lovely cocok tugas menu paket ramah kantong rekomendasi'),(90187,'Nakoa','Putri Agustin Dwi Ningrum',4,'4 bulan lalu','Tempatnya luas, ada indoor dan outdoor di outdoor pun juga banyak tempat duduk yang disediakan','luas indoor outdoor outdoor duduk sedia'),(90188,'Nakoa','Vicha Berliana',5,'3 tahun lalu','tempat ngopi kekinian.ramai pengunjung bgt! jadi cocok untuk destinasi bersua dengan kawan dan keluarga. tempatnya juga nyaman juga estetik. untuk minumamnya juga enak, donatnya empuk pula🙌🏻 untuk harga sih worth bgt👍🏼','ramai unjung cocok destinasi sua teman keluarga nyaman indah minumamnya nikmat donat empuk harga layak'),(90189,'Nakoa','Inas Arwina',5,'2 tahun lalu','JUARAAKK!!! cafe tempat aku ngerjain skripsi xixi. sekarang dah lulus tiap ke malang selalu nyempetin ke sini. Tempat outdoor yg di belakang itu tuh enak bgt apa lagi klo hujan duduk deket toilet, sama minuman yg aku suka caramel latte','juaraakk ngerjain tugas xixi dah lulus nyempetin outdoor tuh nikmat hujan duduk deket toilet minum suka caramel latte'),(90190,'Nakoa','Niken Ayu',5,'2 tahun lalu','tempatnya cocok bgt buat yang mau nugas karena banyak colokannya, harga standar, snacknya enak minus gaada makanan berat, acnya dingin pake banget tapi masih oke','cocok tugas colok harga standar snacknya nikmat minus gaada makan berat acnya dingin pakai'),(90191,'Nakoa','Jenn An',5,'3 tahun lalu','Tempat nongkrong yang luas dan nyaman. Tempatnya adem. Ada outdoor dan indoor. Lahan parkir terbatas. Caramel macchiato 27rb. Payment by ovo. Tersedia croissant dan sedikit snack waktu tiba disana. Rasa kopinye nikmat dan harum. Pokoknya tempatnya enak buat nongki2.','nongkrong luas nyaman adem outdoor indoor lahan parkir batas caramel macchiato payment ovo croissant snack kopinye nikmat harum pokok nikmat nongkrong'),(90192,'Nakoa','puspita rahayu',4,'Diedit 2 tahun lalu','Tempatnya luas, nyaman wifi agak lemot ya say, antrian kasir panjang sekali, mbk2 kasirnya lumayan tidak ramah ya untuk suasana asik','luas nyaman wifi lot say antri kasir mbk kasir lumayan ramah suasana nyaman'),(90193,'Nakoa','Usy Firdausy',5,'2 tahun lalu','Outstanding service commitment!  Awalnya dine in, dan karena puas dengan rasa kuenya, memutuskan take away 4 makanan dan 1 minuman untuk keluarga di rumah. 3 jam kemudian saya baru menyadari bahwa pesanan saya kurang 1 (sepotong kue strawberry cream swiss roll). Saat saya sampaikan di WA Nakoa cafe, admin lgsg meminta alamat untuk mengantarkan pesanan. Dan, voila! Betulan diantar. Prosedur ini mungkin lazim untuk restoran2 fastfood besar, tapi baru kali ini mendapati sebuah Cafe menerapkannya.  Well, Nakoa berhasil membuat saya terkesan, karena membuktikan komitmen layanan mereka yang jauh tinggi dibandingkan harga sepotong strawberry cream swiss roll dan jarak 25 km, (Yup, Jarak pengiriman 25 km!).  Minuman di gambar diluar pesanan saya, namun diberikan cuma2 sebagai ungkapan permohonan maaf.  Terima kasih Nakoa Cafe. Semoga banyak restoran lain yang juga memiliki komitmen pelayanan yang tinggi seperti ini.  Notes: Sejujurnya saya agak merasa bersalah karena tim Nakoa harus menempuh jarak cukup jauh, namun saya sangat menghormati prosedur serta komitmen yg dimiliki Nakoa. Dan, semoga petugas yang lalai tidak diberi punishment, namun dibimbing menjadi lebih baik lagi ❤.','outstanding service commitment dine puas kue putus take away makan minum keluarga rumah jam sadar pesan potong kue strawberry cream swiss roll admin lgsg alamat pesan voila prosedur lazim restoran fastfood terap well hasil kes bukti komitmen layan banding harga potong strawberry cream swiss roll jarak yup jarak kirim minum gambar pesan mohon maaf terima kasih moga restoran milik komitmen layan notes jujur tim tempuh jarak hormat prosedur komitmen milik moga tugas lalai punishment bimbing'),(90194,'Nakoa','ananda marchella',5,'2 tahun lalu','Tempat nyaman bgt, menunya enak” semuaaa mau makan ditempat / pesan antar oke banget.  Harganya affordable bgt apalagi buat pelajar / mahasiswa. Top bgt 👍🏻','nyaman menu nikmat semuaaa makan pesan harga affordable ajar mahasiswa top'),(90195,'Nakoa','Septian Lestari Santoso',4,'4 tahun lalu','Tempat Luas dan Nyaman,Kecepatan Wifi Ok. Tempat yang Instragamable buat foto foto dan nongkrong.  untuk menu minuman Ok.','luas nyaman cepat wifi instragamable nongkrong menu minum'),(90196,'Nakoa','Jessica Putri',5,'3 tahun lalu','Enak buat nugas , outdornya sejuk banget indoor nyaman ada AC minuman dan makanannya worth it banget ❤️','nikmat tugas outdornya sejuk indoor nyaman minum makan layak'),(90197,'Nakoa','Evita Safitri',5,'3 tahun lalu','Salah satu tempat untuk nugas, colokan juga available di setiap tempat. Minuman bervariasi tetapi gabegitu banyak bgt dan lumayan. Minuman paling murah 15k. Untuk cake si yang lumayan bervariasi. Tapi kayaknya kemarin nggak liat makanan berat si, jadi cuman camilan dan minuman aja','tugas colok available minum variasi gabegitu lumayan minum murah cake lumayan variasi kemarin liat makan berat camil minum'),(90198,'Nakoa','Muhammad Rosa Sya\'Roni',5,'4 tahun lalu','Tempatnya asik, luas, bagus buat spot foto 👍 rekomended lah','nyaman luas bagus spot rekomended'),(90199,'Nakoa','Rahma Aaa',5,'setahun lalu','Ini cafe udah kayak basecampku sama bestiku kalo udah bingun mau ngopi dimana ujung”nya selalu nakoa sampe mas”nya pada hafal good food, good coffee, good place, good vibes','basecampku bestiku bingun ujung mas hafal bagus bagus bagus bagus vibes'),(90200,'Nakoa','Dhita Lelly Anastasya',5,'Diedit 3 tahun lalu','Enak tempat dan rasa minumnya. Harga termasuk murah untuk tempat yg bagus begini. Indoor juga banyak tempat, outdoor juga banyak. Colokan juga banyak. Wifi aman gais','nikmat minum harga murah bagus indoor outdoor colok wifi aman gais'),(90201,'Nakoa','Cakra Palimai',4,'Diedit 2 tahun lalu','Untuk bersantai, berbincang ataupun untuk ngerjain tugas tugas kuliah atau Kerjaan mungkin salah satu tempat yang rekomemded meskipun ramai akan tetapi desain Ruangan indor maupun outdoor yang memberikan nuansa ketenangan.','santa bincang ngerjain tugas tugas kuliah kerja rekomemded ramai desain ruang indor outdoor nuansa tenang'),(90202,'Nakoa','Nano Nona',5,'2 tahun lalu','Tempat nya baguss, estetik , nyaman untk nongki, bersih rapi  . Cm mau saranin utk makanan ringan nya ada menu yang asin2 yaa 😁','baguss indah nyaman untk nongkrong bersih rapi saranin makan ringan menu asin yaa'),(90203,'Nakoa','Moch Ichwan Wahyudi Yusri',5,'3 tahun lalu','pelayanan ramah, harga relatif, kebersihan oke, cocok untuk mengerjakan tugas, dating, atau bertemu dengan klien, ovrl perfect','layan ramah harga relatif bersih cocok tugas dating temu klien ovrl perfect'),(90204,'Nakoa','Neisa Rasyidi',4,'3 tahun lalu','Butter croisantnya ga ada obat, enak banget. Suasananya cocok buat nugas. Colokan banyak','butter croisantnya obat nikmat suasana cocok tugas colok'),(90205,'Nakoa','Retno Nur Fadilah',5,'3 tahun lalu','Pertama kali ngopi disini sama temen\" kuliah. Enak tempatnya luas banget, bisa dapet tempat duduk meskipun rame parah. Sayangnya toilet cuma ada 1 cowok 1 cewek. Jadi kalo mau ke toilet harus antri dulu lumayan lama. Hazelnut lattenya enak, meskipun tadi pesan panas, tapi datangnya udah hangat, cenderung suhu biasa..','teman kuliah nikmat luas dapet duduk ramai jelek sayang toilet cowok cewek toilet antri lumayan hazelnut lattenya nikmat pesan panas hangat cenderung suhu'),(90206,'Nakoa','Dewi Intan MPW',5,'Diedit 2 tahun lalu','Cocok banget buat nugas. Bisa me-time jugaa. Untuk FnBnya cukup affordable ya, apalagi di awal bulan, mwehe. ACnya dingin banget. Tempatnya bersih, dan yang jadi nilai plus, musalanya nyaman.','cocok tugas time jugaa fnbnya affordable mwehe acnya dingin bersih nilai plus musala nyaman'),(90207,'Nakoa','Datyo Widharto',5,'2 tahun lalu','Wah ini cocok buat rapat kecil, makanan enak. Kopi enak , suasana enak...mantap...','cocok rapat makan nikmat nikmat suasana nikmat bagus'),(90208,'Nakoa','Aida Fauziah',5,'4 tahun lalu','tempatnya enak tapi ya gitu, rame hehe. kalo bisa kamar mandinya ditambah biar ga antri lamaa🌟 …','nikmat ramai hehe kamar mandi antri lamaa'),(90209,'Nakoa','Donersean Galulien',5,'8 bulan lalu','Udah muter muter semalang raya, tetep nakoa yang suasananya paling ciamik buat wfc, ga berisik, ceiling tinggi, big big window, mejanya gede2 jadi ga bingung antara naruh device, buku, makanan minuman, sayangnya cuma ga ada makanan berat aja.','muter muter raya tetep suasana ciamik kerja berisik ceiling big big window meja gede bingung naruh device buku makan minum sayang makan berat'),(90210,'Nakoa','Silvia Wela Vionika',5,'4 bulan lalu','kalo kesini wajib pesen pastry-nya sih tempatnya enak banget','wajib pesan pastry nikmat'),(90211,'Nakoa','faris deny',5,'5 bulan lalu','Kebanyakan mahasiswa mahasiswi pengunjungnya. Tp nyaman kalau buat ngobrol...','mahasiswa mahasiswi unjung nyaman ngobrol'),(90212,'Nakoa','Hanung Permata Putri',5,'setahun lalu','makan minum nya enak enak. penyajian makanannya juga cepet. dan suasana comfortable. bisa banget buat nugas mahasiswa wifi jg kenceng. overall notbad lahh ✌🏻✌🏻✌🏻','makan minum nikmat nikmat saji makan cepat suasana comfortable tugas mahasiswa wifi kenceng notbad lahh'),(90213,'Nakoa','Atikah Fatmawati',5,'3 tahun lalu','Tempatnya luass banget dan nyaman sih. cocok buat yang nongkrong banyakan atau dikit atau cuman sendiri pun mendukung ya. tempat indoornya enak bgt buat nugas ✨✨ minumanya enak enak jugaa','luass nyaman cocok nongkrong dikit dukung indoornya nikmat tugas minumanya nikmat nikmat jugaa'),(90214,'Nakoa','Dzikri Huszein',5,'2 tahun lalu','worth it untuk menugas, meeting dan nongkrong dengan suasana yang nyaman. Harga sesuai dengan rasa yg diberikan. Avocado Choco Caramel is may fav! thanks!!','layak tugas kerja nongkrong suasana nyaman harga avocado choco caramel may fav thanks'),(90215,'Nakoa','debora kristinawati',5,'2 tahun lalu','Tempat nyaman dan luas, kopi enak, disediakan air mineral yg bisa di ambil di counter pengambilan order. Toilet bersih, pelayannya ramah dan membantu sekali, makanannya enak. HARGA terjangkau','nyaman luas nikmat sedia air mineral ambil counter ambil order toilet bersih layan ramah bantu makan nikmat harga murah'),(90216,'Nakoa','Kurnia Shobrina M.',5,'Diedit setahun lalu','Tempat nyaman, cocok untuk kerja atau nugas. Wifi oke. Ada mushola juga.','nyaman cocok kerja tugas wifi mushola'),(90217,'Nakoa','Evitri Sulistia Ningsih',4,'2 tahun lalu','Temapatnya nyaman banget, super cozy cocok buat kumpul-kumpul sama teman, kerkel, ngerjain tugas, metime. Nyaman banget pokoknya.','temapatnya nyaman super nyaman cocok kumpul kumpul teman kerkel ngerjain tugas metime nyaman pokok'),(90218,'Nakoa','Evitri Sulistia Ningsih',4,'2 tahun lalu','Temapatnya nyaman banget, super cozy cocok buat kumpul-kumpul sama teman, kerkel, ngerjain tugas, metime. Nyaman banget pokoknya.','temapatnya nyaman super nyaman cocok kumpul kumpul teman kerkel ngerjain tugas metime nyaman pokok'),(90219,'nowhere coffee','Nuurul Ula',4,'3 bulan lalu','Cukup enak...pilihan tempat luas, cocok buat SFC/WFC Sayang kmrn pas duduk , colokan listrik enggak berfungsi Makanan cukup enak...saat kami ke sana ada bbrp yg blm ready','nikmat pilih luas cocok sfc kerja sayang kmrn duduk colok listrik fungsi makan nikmat ready'),(90220,'nowhere coffee','Laila Afiata',5,'9 bulan lalu','Area outdoor luas. Cozy. Ada sofa, kolam kecil. Banyak tanaman. Sangat nyaman','area outdoor luas nyaman sofa kolam tanam nyaman'),(90221,'nowhere coffee','Jinnie Hyunn',5,'setahun lalu','Kesini karena tempatnya super luas buat nongkrong dan ambiencenya cozy untuk nugas. Banyak colokan juga disetiap sudut meja. Menu yang ditawarkan juga semua premium.','super luas nongkrong ambiencenya nyaman tugas colok sudut meja menu tawar premium'),(90222,'nowhere coffee','Human Strong',5,'5 bulan lalu','suasananya nyaman banget siii disinii. buat nugas pw.','suasana nyaman siii tugas nyaman'),(90223,'nowhere coffee','Dini Lestari',5,'2 bulan lalu','Tempat nongkrong sambil mengerjakan tugas anak kuliahan. Ngopi dan bersantai juga bisa. Tempat duduk banyak karena luas dari depan teras sampai belakang.','nongkrong tugas anak kuliah santa duduk luas teras'),(90224,'nowhere coffee','Rosana Oktaviani',3,'setahun lalu','Desain interiornya baguss bangett, suhu AC pas tidak terlalu dingin, musholla dan toilet bersih dan wangi, tapi wifinya kurang stabil dan tidak disediakan kabel olor sehingga kurang nyaman untuk customer yang ingin wfc 🙏🏻','desain interior baguss suhu dingin musholla toilet bersih wangi wifi stabil sedia kabel olor nyaman customer kerja'),(90225,'nowhere coffee','Bambang Hariyanto',5,'Diedit 8 bulan lalu','staffnya ramah, makanan dan minumannya enak semua','staffnya ramah makan minum nikmat'),(90226,'nowhere coffee','Fly High',5,'4 bulan lalu','Tempat favorit untuk nugas, suasana sangat tenang','favorit tugas suasana tenang'),(90227,'nowhere coffee','delisa',5,'8 bulan lalu','tempatnya nyaman dan dingin cocok buat nugas, minumannya juga enak','nyaman dingin cocok tugas minum nikmat'),(90228,'nowhere coffee','Amelia Margono',5,'9 bulan lalu','Produk nya oke, cozy, colokan banyak, cocok buat wfc','produk nyaman colok cocok kerja'),(90229,'nowhere coffee','andi',3,'5 bulan lalu','Tempatnya luas, ada banyak pilihan tempat duduk di indoor maupun outdoor. Area parkirnya juga luas, baik untuk mobil dan motor.  Ambiencenya bagus dan memang cocok untuk WFC. Namun, pemilihan musiknya agak kurang cocok di saya. Kemarin pas kesana, pemilihan playlistnya dominan edm dengan bass yang kencang. Selain itu, order saya juga sempat terlewat dan belum dibuatkan dengan baristanya.  Mungkin akan cocok untuk yang suka bekerja dengan suasana ramai.','luas pilih duduk indoor outdoor area parkir luas mobil motor ambiencenya bagus cocok kerja pilih musik cocok kemarin kesana pilih playlistnya dominan edm bass kencang order baristanya cocok suka suasana ramai'),(90230,'nowhere coffee','audrya nasywa',5,'setahun lalu','comfort placeee untuk skripsiaan, makanan dan minumannya enak\", tempatnya juga comfy, speed wifi oke, will go back again and again 😁','comfort placeee skripsiaan makan minum nikmat nyaman speed wifi back'),(90231,'nowhere coffee','Gabriellaalfa Huwae',5,'setahun lalu','Tempatnya nyaman banget,, makannya ok.. cocok banget buat tempat nongkrong sama temen-teman 😊','nyaman makan cocok nongkrong teman teman'),(90232,'nowhere coffee','Maryam Maryam',5,'setahun lalu','Tempatnya luas ada indoor dan outdoor, pilihan menunya juga banyakk dan overall enak kok. Poin plus karena deket banget dari kampus serta ada musholla yang lumayan proper','luas indoor outdoor pilih menu banyakk nikmat poin plus deket kampus musholla lumayan proper'),(90233,'nowhere coffee','Khaishia',4,'9 bulan lalu','ambience nya enak banget adem, spot duduk nya juga banyak klo makanannya enak sih cuma pastry nya kurang worth it dengan price segitu','ambience nikmat adem spot duduk makan nikmat pastry layak price segitu'),(90234,'nowhere coffee','Yatnaz Tasya',5,'7 bulan lalu','nyaman nongkrong disini, bisa buat laptopan juga. pelayanan oke banget','nyaman nongkrong laptop layan'),(90235,'nowhere coffee','Firda Fatmalla Hapsari',5,'2 bulan lalu','Enak nyaman murah','nikmat nyaman murah'),(90236,'nowhere coffee','Fanny michel Kowaas',5,'setahun lalu','pelayanannya baik dan ramah, tempatnya luas dan nyaman, banyak varian menunya ada makanan berat dan snack jugaa, dan yang paling penting sangat cocok buat nugas😊🤩 …','layan ramah luas nyaman varian menu makan berat snack jugaa cocok tugas'),(90237,'nowhere coffee','Ardhan Sidqi Priandayani',5,'setahun lalu','makanannya enak, minumannya jg enak jg. trs tempatnya nyaman banget buat nugas, pokoknya debestt','makan nikmat minum nikmat nyaman tugas pokok debestt'),(90238,'nowhere coffee','Hantaran Amira',5,'setahun lalu','Best cafe ever, menunya enak, lokasinya cozy banget, strategis, Wifi-nya oke, ada musholla juga yang nyaman banget.','ever menu nikmat nyaman strategis wifi musholla nyaman'),(90239,'nowhere coffee','James Bond',5,'9 bulan lalu','Tempatnya nyaman, bersih & dilengkapi baby chair untuk keluarga yg bawa baby, Cappuccino nya enak','nyaman bersih lengkap baby chair keluarga bawa baby cappuccino nikmat'),(90240,'nowhere coffee','RIS 406',5,'setahun lalu','suasana enak banget, cuma tolong banget saya kena prank sama tempat duduk outdoor yang busa…kalo musim hujan jangan di taruh outdoor, jadinya celana saya basah deh😭','suasana nikmat tolong kena prank duduk outdoor busa musim hujan taruh outdoor celana basah'),(90241,'nowhere coffee','Aan Prastya',5,'6 bulan lalu','Tempat luas, vibe santai banget.','luas vibe santai'),(90242,'nowhere coffee','sherin maudri asy\'ari',5,'setahun lalu','Tempatnya nyaman, buka sampe malem, banyak pilihan menu, red velvetnya lembut, pelayanannya cepet dan ramah 🥰🥰','nyaman malem pilih menu red velvetnya lembut layan cepat ramah'),(90243,'nowhere coffee','Dimas Alief Pratama',5,'5 bulan lalu','Nyaman dan makanannya enak 🤤','nyaman makan nikmat'),(90244,'nowhere coffee','Achmad Ziddanial Muqodash Badryy',5,'setahun lalu','Udah berkali kali kesini, tempatnya nyaman enak buat me time ataupun ngobrol, baristanya gercep gercep banget. Warga malang sini yukk','nyaman nikmat time ngobrol baristanya gercep gercep warga yukk'),(90245,'nowhere coffee','gaby felicia',5,'9 bulan lalu','Tempatnya nyaman banget buat nugas dan makanannya enakk🤩','nyaman tugas makan nikmat'),(90246,'nowhere coffee','kartika amelia',5,'9 bulan lalu','tempatnya nyaman banget,bersih,pelayanan cepat dan ramah.makanan dan minuman enak','nyaman bersih layan cepat ramah makan minum nikmat'),(90247,'nowhere coffee','indah utami',3,'setahun lalu','Lokasi ok, vibesnya juga. Kalau kopinya B aja menurutku. Yang agak mengecewakan adl saat mau pesan makanan. Kami datang sekitar jam 9.40, pas mau pesan makan dibilang kalau kitchen baru akan buka jam 10.00. Ya sudahlah, kami tunggu. Lalu sekitar jam 10.18, kami ke kasir lagi mau pesan makanan, eh dibilang kalau kitchen baru akan buka jam 11.00. Akhirnya aku protes dan menyampaikan kalau kasir sebelumnya bilang kitchen buka jam 10.00. Akhirnya ditanyakanah e temannya, dan bilang kitchen akan buka jam 10.30.  At the end of the day, gak jadi pesan makanan karena udah terlanjur bete di-PHP. 🥲  Mohon dikasih info yg jelas ttg hal ini, kalau perlu ditulis di menu atau apalah ya, biar gak mengecewakan pelanggan.','vibesnya kecewa adl pesan makan jam pesan makan bilang kitchen jam tunggu jam kasir pesan makan bilang kitchen jam protes kasir bilang kitchen jam ditanyakanah teman bilang kitchen jam end day pesan makan lanjur bete php mohon kasih info ttg tulis menu kecewa langgan'),(90248,'nowhere coffee','Putri Amalia',5,'setahun lalu','Tempatnya cozy dan pewe buat nugas lama, kopi nya enak dan makanannya porsinya banyak','nyaman nyaman tugas nikmat makan porsi'),(90249,'nowhere coffee','Putri Ayudya',3,'setahun lalu','Nachos 45rb dengan kripik singkong yg tdk crunchy. Kripik singkong ya emang judulnya cassava nachos. Agak laen konsep nachos ini. Dan dagingnya main petak umpet. Overall menunya \"unik\" harganya. Nasi goreng dibandrol 25rb sdgkan banana bite,corn rib >30rb. 😅😅😅','nachos kripik singkong tdk crunchy kripik singkong emang judul cassava nachos laen konsep nachos daging main petak umpet menu unik harga nasi goreng dibandrol sdgkan banana bite corn rib'),(90250,'nowhere coffee','bianca alexa',5,'4 bulan lalu','Cafe Nowhere selalu jadi pilihan pertama aku untuk WFC. Tempatnya super comfy, wifi kenceng, pelayanannya bagus, dan AC-nya juga dingin. Pokoknya nyaman banget buat nugasss bareng teman-teman🫰🏻','nowhere pilih kerja super nyaman wifi kenceng layan bagus dingin pokok nyaman nugasss bareng teman teman'),(90251,'nowhere coffee','Deya Refionika',5,'8 bulan lalu','cocok si buat yg mau wfc-an, makanannya jg enak-enak, kasirnya ramah, pengetahuan tntang produknya juga bagus bgt! dan lg.. ice macchiato.nya best bgt!!','cocok kerja makan nikmat nikmat kasir ramah tntang produk bagus ice macchiato'),(90252,'nowhere coffee','debbiie debo',5,'setahun lalu','Saladnya Freshhh seger sayuran ndak pahit. sangat cocok untuk udara malang yang sedang panas. Jus Detoxnya isinya pepaya milky gitu bikin lancar pencernaan dan rasanya wenaaak. Lychee Tea enak berasa pekat tehnya dan wangi manis lecinya, ada buah lecinya besar besar Suegerrrr','saladnya freshhh segar sayur pahit cocok udara panas jus detoxnya isi pepaya milky lancar cerna wenaaak lychee tea nikmat asa pekat teh wangi manis leci buah leci suegerrrr'),(90253,'nowhere coffee','Riya Tanjung - 081',5,'setahun lalu','Makanannya enak dan harganya menurut saya pas, suasananya juga tdk terlalu noise, tempatnya luas dan banyak pilihan tempat duduk','makan nikmat harga suasana tdk noise luas pilih duduk'),(90254,'nowhere coffee','Winndy alfira',5,'4 bulan lalu','tempat nya nyaman , bersih dan syahdu .','nyaman bersih syahdu'),(90255,'nowhere coffee','Ananda Ricky Fauzi',5,'setahun lalu','Ambience nya sangat nyaman, servicesnya sangat ramah serta sangat membantu, terlebih minumannya juga cocok di lidah.','ambience nyaman servicesnya ramah bantu minum cocok lidah'),(90256,'nowhere coffee','Atika Fitria Arifiana',5,'setahun lalu','Suka  banget ada musholla nya, adem, pintu dibukain mas nya act of service bgt, ramahh bintang 5 service nya kasir maupun barista nya🤗❤️','suka musholla adem pintu dibukain mas act service ramahh service kasir barista'),(90257,'nowhere coffee','GERALDA DESINTHA RISA PUTRI',5,'9 bulan lalu','tempatnya very cozy dan sangat cocok untuk me time maupun spend time dengan teman, sangat recommendes','nyaman cocok time spend time teman recommendes'),(90258,'nowhere coffee','Reza Wildan',3,'3 bulan lalu','Parkir ga jelas, katanya bayar wajib pake online. Waktu keluar, bukannya karcis yg di scan tapi harus nyodorin bukti transaksi di aplikasi hp','parkir bayar wajib pakai online karcis scan nyodorin bukti transaksi aplikasi'),(90259,'nowhere coffee','RATIH PUSPITASARI',5,'setahun lalu','Suasana baru tempat makan siang. Suasananya nyaman. Tempatnya luas. Tempat parkirnya juga luas. Rasa makanannya enak. Harganya standart untuk ukuran cafe. Wajib di coba untuk anak gaul zaman now dan para pekerja sekitar UM...','suasana makan suasana nyaman luas parkir luas makan nikmat harga standart ukur wajib anak gaul zaman kerja'),(90260,'nowhere coffee','Habel Gani',5,'setahun lalu','Lokasi mudah ditemukan karena di jalan raya, parkiran luas, pelayanan ramah. Harga ok sesuai dengan kualitas','mudah temu raya parkir luas layan ramah harga kualitas'),(90261,'nowhere coffee','Putri Charmilia',5,'6 bulan lalu','Tempatnya enak banget buat nongkrong bareng temen atau buat kerja','nikmat nongkrong bareng teman kerja'),(90262,'nowhere coffee','Melanie Angela',5,'setahun lalu','Tempatnya cozy buat nugas, makanannya enak, pelayanannya ramah, worth it!!!!','nyaman tugas makan nikmat layan ramah layak'),(90263,'nowhere coffee','Yolanda Rahelmi',5,'setahun lalu','tempatnya baguss dan nyaman cocok buat wfh, servicenya juga oke, makanannya enakk, mantapp👌🏻','baguss nyaman cocok kerja servicenya makan nikmat mantapp'),(90264,'nowhere coffee','Anggieta Ratuyustiarany',5,'setahun lalu','sowww cozy here, enak banget buat nugas disiniiiiii tiap hari selalu kesini, the food, the ambience, the service all perfect🤩💗','sowww nyaman nikmat tugas disiniiiiii ambience service perfect'),(90265,'nowhere coffee','Farah Hardina',5,'9 bulan lalu','Enak banget tempatnya dingin, mau kerja  sambil minum kopi bikin mood bgt','nikmat dingin kerja minum mood'),(90266,'nowhere coffee','Rizka Agustin',5,'setahun lalu','tempat nyaman, makan dan minum nya enak . harga afrodablle','nyaman makan minum nikmat harga afrodablle'),(90267,'nowhere coffee','Daniah',4,'11 bulan lalu','Pesen nasi goreng. Nasinya keras😔 ntah gak mateng atau emang teksturnya sengaja dibuat kerasnya seperti itu. Padahal rasanya udah pas, minus disitu aja sih','pesan nasi goreng nasi keras ntah mateng emang tekstur sengaja keras minus situ'),(90268,'nowhere coffee','Azzahrah Ricma Putri',5,'5 bulan lalu','Kerenn..tempatnya enak buat nugas','kerenn nikmat tugas'),(90269,'nowhere coffee','Hana Shafiyyah',5,'9 bulan lalu','tempat comfy buat nugass, makanannya oke juga ada banyak promo kalo kalian ikutin ignyaaa, masih kantong mahasiswa dengan tempat yg okee','nyaman nugass makan promo ikutin ignyaaa kantong mahasiswa okee'),(90270,'nowhere coffee','Arik Luvian',4,'setahun lalu','lokasi enak, tengah kota, makanan minuman oke, service ok, yg pasti toiletbdan tempat ibadahnya bersih dan nyaman.. next bisa mampir kesini lg','nikmat makan minum service toiletbdan ibadah bersih nyaman next mampir'),(90271,'nowhere coffee','Muhammad Azri Ismail',5,'setahun lalu','Tempatnya nyaman makanannya enak pelayanannya ramah dan baik','nyaman makan nikmat layan ramah'),(90272,'nowhere coffee','Daffa Arghana',5,'setahun lalu','Caffe area malang,enak banget tempatnya kekinian. makanan minumannya enak bang murah murah lagi. recomended polll','caffe area nikmat makan minum nikmat bang murah murah recomended polll'),(90273,'nowhere coffee','Yovita Kanaya',5,'9 bulan lalu','tempatnya aesthetic and sangat pw untuk nugas! pilihan makanannya juga banyak jd pasti nyaman','indah nyaman tugas pilih makan nyaman'),(90274,'nowhere coffee','ferdiana rafikasari',3,'setahun lalu','Overall sih oke buat pelayanan dan minuman, cuman kurang rekom buat wfc karena internetnya lemot banget sampe pake hotspot pribadi. Next mungkin bisa lebih diperbaiki buat internetnya.','layan minum rekom kerja internetnya lot pakai hotspot pribadi next internetnya'),(90275,'nowhere coffee','madaley',5,'6 bulan lalu','bagus bgt nyaman pelayanan ramah, kasirnya ramah','bagus nyaman layan ramah kasir ramah'),(90276,'nowhere coffee','Ahmad Bagus',5,'setahun lalu','Tempatnya nyaman buat anak muda dan keluarga. Bisa buat kerja. Luas, ada indoor dan outdoor. Bersih.','nyaman anak muda keluarga kerja luas indoor outdoor bersih'),(90277,'nowhere coffee','Kiky Rezky Thea',5,'8 bulan lalu','Tempatnya oke luas nyaman.. Dan makanan dan minumannya jg enak2 💯','luas nyaman makan minum nikmat'),(90278,'nowhere coffee','362_ Tyas Ayu Putri K',5,'setahun lalu','Cafenya nyaman banget dan estetik.. minumnya enak banget sukaaa','cafenya nyaman indah minum nikmat sukaaa'),(90279,'nowhere coffee','Dian Raharsari',5,'setahun lalu','Suka sekali ke Nowhere. Tempatnya luas, AC dingin, tersedia juga area outdoor yg luas, beserta ruangan AC smooking area. Suasananya nyaman dan cocok sekali untuk mengerjakan tugas atau WFC. Jaringan wifinya sangat bagus dan tidak lemot. Harga makanan sangat terjangkau range harga rata2 25ribu - 50ribu. Rasa makanan enak dan kopinya juga enak. Suasananya sangat homey dan tiap minggu hampir kesini.','suka nowhere luas dingin area outdoor luas ruang smooking area suasana nyaman cocok tugas kerja jaring wifi bagus lot harga makan murah range harga ribu ribu makan nikmat nikmat suasana homey minggu'),(90280,'nowhere coffee','Herdita Caprina',5,'Diedit 9 bulan lalu','Saya pesan Oxtail Soup, karena hujan, cocok saat dingin, dan bisa dimakan bersama. Foto di menu dengan yang saya dapat berbeda jauh… Saya bahkan tidak selera untuk komplain langsung, karena capek. Anw, ini bukan pertama kali saya kesini, tapi kecewanya dapet si. And its overprice just for a ‘bone soup’.  Updated review June 18th, 2025 Ga lama dari reviewnya, langsung di reach out via dm instagram. Dan ada tindakan langsung dengan mengirimkan komplimen ke rumah. Dengan menu yg sama, dan sesuai dengan SOP nya.  Terima Kasih atas komplimennya, semoga terus menjadi lebih baik kedepannya','pesan oxtail soup hujan cocok dingin makan menu beda selera komplain capek anw kecewa dapet overprice bone soup updated june reviewnya reach via instagram tindak kirim komplimen rumah menu sop terima kasih komplimen moga'),(90281,'nowhere coffee','Jajan suka-suka Feni Arbi',5,'4 bulan lalu','Suasana nya nyaman... Makanannya enak enak, minumnya juga segerr Banyak anak anak sering kesini buat nugas','suasana nyaman makan nikmat nikmat minum segerr anak anak tugas'),(90282,'nowhere coffee','Yunita Fera Rahmawati',3,'setahun lalu','Untuk tempatnya oke, outdoornya yang luas. Yg paling nyaman di indor sebenarnya. Parkir luas banget. Pelayanannya baik. Saya kecewa dg waktu tunggu utk 2 menu nasi goreng dan mie saja 35 menit, sangatttt lama. Dan sorry to say untuk rasanya biasa aja. Mohon ditingkatkan pelayanannya.','outdoornya luas nyaman indor parkir luas layan kecewa tunggu menu nasi goreng mie menit sangatttt sorry say mohon tingkat layan'),(90283,'nowhere coffee','Modesttt',4,'setahun lalu','Order makan dan minum g sempet foto. Menu yg aq order beef sandwich, tuna sandwich , hot matcha , iced lychee tea , frechfries.  Hot matcha menurutku kurang berasa matcha nya kurang pekat dan cenderung kerasa susu nya, aku suka matcha yg ada rasa pahitnya dan bau matchanya  kerasa. Kalo ini kurang menurutku.  Sandwich tuna nya kalo seasoningnya lebih strong pasti lebih enak.  Frechfries aman datang panas, lychee tea ok.  Utk suasana enak nyaman, pelayanan bagus, bagian handle pesenan jg komunikasi dan pelayananya bagus.  Tempat luas bersih, Ok utk nongki/ nugas mahasiswa. Next klo kesana cobain menu makanan berat lain nya.','order makan minum sempet menu order beef sandwich tuna sandwich hot matcha iced lychee tea frechfries hot matcha asa matcha pekat cenderung susu suka matcha pahit bau matchanya sandwich tuna seasoningnya strong nikmat frechfries aman panas lychee tea suasana nikmat nyaman layan bagus handle sen komunikasi pelayananya bagus luas bersih nongkrong tugas mahasiswa next kesana cobain menu makan berat'),(90284,'nowhere coffee','AGNIA NAYLA NADINE S',5,'5 bulan lalu','makanan dan minumannya enak enakkk, mie nyemek strawberry cheesecake terfav, minumann. pelayannya ramahh dann peka. tempat favorit buat nugass','makan minum nikmat enakkk mie nyemek strawberry cheesecake terfav minumann layan ramahh dann peka favorit nugass'),(90285,'nowhere coffee','Momossa',5,'11 bulan lalu','Udah dua kali kesini dan rame nya minta ampun. Wajar sih deket kampus soalnya. Hampir semua kursi indoor full.  Makanan dan minuman beneran enak donk. Worth the money!','ramai ampun wajar deket kampus kursi indoor full makan minum beneran nikmat donk layak money'),(90286,'nowhere coffee','n. yuliandani',4,'8 bulan lalu','jam makan siang mampir kesini karena penasaran, vibe tempatnya cozy dan banyak tempat duduk karena luas, cocok buat nugas, wfc atau gathering, nyobain ice americanonya enak, untuk menu kopi dan makan beratnya kurang variatif, pastrynya juga engga banyak, tapi worth to try eniwei next time mau nyobain menu lain','jam makan mampir penasaran vibe nyaman duduk luas cocok tugas kerja gathering nyobain ice americanonya nikmat menu makan berat variatif pastrynya layak try eniwei next time nyobain menu'),(90287,'nowhere coffee','Reris Vashti',3,'setahun lalu','Tempatnya luas, enak aja sih buat ngopi sama makan, kalau untuk meeting dan wfc kurang recommend buat saya, karena berisik sekali ketika banyak orang.  Plus nya lagi di sini ada meeting room, kurang tau untuk harganya berapa.  Rasa kopinya biasa aja, belum ada yang  spesial buat saya. Coba picollo, katanya kopinya lebih dominan arabika, tapi menurut saya acidity nya gak keluar. Untuk harganya lumayan pricey juga.','luas nikmat makan kerja kerja recommend berisik orang plus kerja room tau harga spesial picollo dominan arabika acidity harga lumayan mahal'),(90288,'nowhere coffee','AY Herlien',3,'setahun lalu','Nowhere, penasaran ke sini karena berada di area kampus ku dulu kuliah. Berharap nuansa kampusnya dapat, ternyata tidak juga 🤭 cuma ada tumpukan buku2 di belakang kasir. Tempatnya nyaman dan luas. Bebas bisa pilih indoor atau outdoor.  Termasuk cafe yg pricy. Mereka juga mengenakan biaya service, tapi kenapa yaa customer masih harus membawa minumannya sendiri setelah bayar? Kebetulan td ke sini sama temen2. Pas temen pesen sendiri, datang2 bawa minuman di nampan sendirian. Bukan gamau atau gabisa, tp seharusnya dibantu ketika melihat customer kesulitan. Aku yg terlanjur duduk di outdoor kaget melihat teman tergopoh membawa sendirian. Lebih baik tidak perlu ada biaya service kalau servicenya hanya membereskan piring/gelas di meja.  Cuma pesan camilan. Enoki friesnya enak. Corn ribsnya juga lumayan. Sayang greenteanya mode syrup jadi gabisa pesan less sugar. Affogatonya oke.  Perlu diperhatikan lagi terkait tempat duduk, khususnya kursi yg sofa. Tadi duduk disitu ternyata bagian di bawah bantal basah, airnya juga menetes ke bawah. Sepertinya bekas kehujanan dan tidak dilap. 2 jam duduk disitu g terasa celana jadi basah.  Mohon ditingkatkan lagi khususnya pelayanannya yaa. Sayang kan sudah menambahkan biaya service tp pelayanan kurang maksimal 😊','nowhere penasaran area kampus kuliah harap nuansa kampus tumpu buku kasir nyaman luas bebas pilih indoor outdoor mahal kena biaya service yaa customer bawa minum bayar teman teman pesan bawa minum nampan gamau gabisa bantu customer sulit lanjur duduk outdoor kaget teman gopoh bawa biaya service servicenya beres piring gelas meja pesan camil enoki friesnya nikmat corn ribsnya lumayan sayang greenteanya mode syrup gabisa pesan less sugar affogatonya perhati kait duduk kursi sofa duduk situ bantal basah air tetes bekas hujan lap jam duduk situ celana basah mohon tingkat layan yaa sayang biaya service layan maksimal'),(90289,'nowhere coffee','Fanny Tantoyo',5,'setahun lalu','Nice place Tempat yang indah, nyaman, bersih dan wangi. Makanan dan minuman nya enak Nasi goreng nya enak sekali, salad fresh Kopi 👍 Details ruangan sangat cantik. Banyak tanaman hidup di dalam ruangan. Nuansa kayu kayu yg cantik memberikan kesan yg manis. Tempat duduknya banyak sekali. Indoor dan outdoor. Tempat parkir cukup luas.','bagus indah nyaman bersih wangi makan minum nikmat nasi goreng nikmat salad fresh details ruang cantik tanam hidup ruang nuansa kayu kayu cantik kesan manis duduk indoor outdoor parkir luas'),(90290,'nowhere coffee','Ahmed syariefm',3,'setahun lalu','Service nya sudah lumayan baik, saran saya Bake Pastry nya di perbaiki karena Pastry tidak renyah/panas sampai dalam. Saran untuk harga menu di POS dan Buku Menu di cek lagi (Lebih Aware) ya karena ada perbedaan Harga yang menurut Saya lumayan tapi tadi sudah di Refund Sama Staff nya. Atmosphere enak buat nugas dan nongkrong. Terimakasih','service lumayan saran bake pastry pastry renyah panas saran harga menu pos buku menu cek aware beda harga lumayan refund staff atmosphere nikmat tugas nongkrong terimakasih'),(90291,'nowhere coffee','hengky Vivoy100',5,'setahun lalu','Tempatnya nyaman banget, banyak pilihan tempat duduknya, cocok banget buat semua kaum ekstrovert sampai ke introvert bisa nyaman disini. Makanannya enak dan minumannya banyak pilihannya. Cocok banget buat yang lagi nyari tempat nongkrong, santai, dan yang mau wfc juga.','nyaman pilih duduk cocok kaum ekstrovert introvert nyaman makan nikmat minum pilih cocok nyari nongkrong santai kerja'),(90292,'nowhere coffee','ara',5,'setahun lalu','Tempat nyaman, banyak colokan, minuman makanan bervariasi, banyak pilihan.🍜 Banyak varian cake dan patry.🥐 Ada outdoor dan indoor, ada smoking ac juga. Pegawainya nya ramah, ganteng & cantik².😚 Toilet bersih dan ada musholla juga. Banyak pilihan tempat duduk. Ada spot untuk printer juga. Hommy, dan workplace banget! 🥳✨  .  .  . Saya juruwang nye.','nyaman colok minum makan variasi pilih varian cake patry outdoor indoor smoking pegawai ramah ganteng cantik toilet bersih musholla pilih duduk spot printer hommy workplace juruwang nye'),(90293,'nowhere coffee','Naura Mustika',5,'4 bulan lalu','suasananya bagus bangett enak buat WFC, menunya juga enak enakk. bakal balik lagi sihh 🫶','suasana bagus nikmat kerja menu nikmat nikmat sihh'),(90294,'nowhere coffee','Delvinda Pinda',5,'8 bulan lalu','cozy bgt tempatnya apalagi buat nugas, service nya juga oke bgt, makanan dan minumannya juga enak. cuman di toiletnya sering bgt hampir jatuh soalnya tinggi bgt tangganya(cm masukan aja si)😭','nyaman tugas service makan minum nikmat toilet jatuh tangga'),(90295,'nowhere coffee','puput dewiamelia',5,'4 bulan lalu','pelayanan baik dan cepat, kasir ramah, tempat nyaman dan kamar mandi bersih banget👍','layan cepat kasir ramah nyaman kamar mandi bersih'),(90296,'nowhere coffee','Sindi P. Minanda',4,'setahun lalu','review timeee!  makanan pesen spagetti enak dg harga segitu, nasi goreng juga porsinya banyak, minumnya oke terumataja kopinya hehe  pelayanan self service, all the team was very nice  ambience nyaman untuk ngobrol bareng2 temen atau meeting sama temen kerja, kesini waktu malem jd outdoor pun rasanya seger ga engap dan panas hehe','timeee makan pesan spagetti nikmat harga segitu nasi goreng porsi minum terumataja hehe layan self service team bagus ambience nyaman ngobrol bareng teman kerja teman kerja malem outdoor segar engap panas hehe'),(90297,'nowhere coffee','M. Rizki Trianto',5,'9 bulan lalu','Kopi ini tempatnya asik banget buat nongkrong! Suasananya nyaman dan cozy, cocok buat ngobrol santai bareng teman atau nugas.','nyaman nongkrong suasana nyaman nyaman cocok ngobrol santai bareng teman tugas'),(90298,'nowhere coffee','inna',3,'setahun lalu','Tempatnya luas banget. Parkirannya juga luas. Tempatnya pas di depan Transmart, masih kawasan UM.  Ruangan Indoornya ada dua, bagian depan dan tengah. Yang bagian tengah, ACnya dingin (ga nyoba yang indoor di depan). Di belakang ada area outdoor yang luas. Ada 2 ruangan meeting room. WCnya bersih, ada mushollanya juga. Cuman mushollanya agak bau dan mukenahnya juga bau hehehehe  WFC: Internetnya belum dicoba. Tapi, sepertinya nyaman untuk WFC. Colokannya ga di semua tempat ada, tapi masih tergolong banyak. Terus aku lihat, dipojokan ada printer. Sepertinya bisa ngeprint juga.  Makan: Pesan makanan beratnya, disuruh nunggu 40 menitan. Tapi sepertinya ga sampe 40 menit udah datang sih. - Saladnya ga worth it dengan harga segitu. [2/5] - Beli Korean Soup Noodles, dapat sepanci-pancinya (ditambahin air, karena keasinan) 👍😆 [3.5/5] - Pastanya juga keasinan sih. Kalau garamnya dikurangin, mungkin enak. [3/5] Saran: Cutlerynya better dilapisi tissue daripada plastik.  Mba kasirnya saat ditanya terkait menu-menunya clueless banget. Jadi, yang mesan juga ikutan bingung. Semoga bisa ditingkatkan 🙏','luas parkir luas transmart kawasan ruang indoornya acnya dingin nyoba indoor area outdoor luas ruang kerja room wcnya bersih mushollanya mushollanya bau mukenahnya bau hehehehe kerja internetnya nyaman kerja colok golong lihat pojok printer ngeprint makan pesan makan berat suruh nunggu menit menit saladnya layak harga segitu beli korean soup noodles panci panci ditambahin air asin pasta asin garam rangin nikmat saran cutlerynya better lapis tissue plastik mba kasir kait menu menu clueless mesan bingung moga tingkat'),(90299,'nowhere coffee','Ini Ferliana Maysaroh',5,'setahun lalu','Udah ke 3x kesini, dari pelayanan kakak\"nya ramah poul, makanannya recomend apalagi suasanya, bisa menyesuaikan nugas, santai, family time. Recommend banget pokok deh','layan kakak ramah poul makan rekomendasi suasa tugas santai family time recommend pokok'),(90300,'nowhere coffee','Gebby Eren',5,'setahun lalu','Tempatny nyaman, banyak space ada outdoor di depan, outdoor belakang dan indoor. Parkir mobil luas. Makanannya cobain nasi goreng enak bgt dan harganya jg nggak mahal. Cobain menu burger juga, enaaakk, ada salad lettuce nya. Kopi nya jg enak','tempatny nyaman outdoor outdoor indoor parkir mobil luas makan cobain nasi goreng nikmat harga mahal cobain menu burger enaaakk salad lettuce nikmat'),(90301,'nowhere coffee','Bilqis Firiya',4,'setahun lalu','• aa happy bgt di cafe ini tp pas dpt kursi di sofa belakang deket pohon *banyak nyamuk kalo udh malemㅠㅠ • luas bgt dr depan - belakang, prkirannya masuk area UM • pelayanannya jg gercep & bagus, attitudenya okee • harga yah lil bit pricey tp jg standar soalnya untuk cafe tp 25k up standar sih tp ya tp tp untuk aku yg jarang ngafe skrng wkwk • minuman jus biasa yah ok aja, makanan oke bgt sih pastanya 28-29 porsi banyak! mau kesini lg visit cobain menu lainnya><','happy dpt kursi sofa deket pohon nyamuk udh malem luas prkirannya area layan gercep bagus attitudenya okee harga yah lil bit mahal standar standar jarang ngafe skrng wkwk minum jus yah makan pasta porsi visit cobain menu'),(90302,'nowhere coffee','Kevin H C F',5,'7 bulan lalu','Tempat nyaman, cocok kalau buat nugas atau nongkrong. Makanan dan minuman juga lumayan oke sesuai selera. Harga lumayan mahal untuk mahasiswa','nyaman cocok tugas nongkrong makan minum lumayan selera harga lumayan mahal mahasiswa'),(90303,'nowhere coffee','Alex Rahman',5,'10 bulan lalu','Tempat nongkrong Di kota malang persis depan Matos, tempat parkir luas, vibes ok banget, untuk eatery ok banget but kopinya kl 1-10 nilai 7 lah overall bisa dijadikan tempat nongkrong kl ke Malang','nongkrong persis matos parkir luas vibes eatery nilai nongkrong'),(90304,'nowhere coffee','Hibatulloh Zaki Ardiansyah',4,'Diedit setahun lalu','Mungkin salah satu tempat cafe yang ada di jalan Veteran.  Tempatnya bagus, rapi, aman, nyaman, terawat, bersih.  Kamar mandi terawat, bersih juga. Dari menu juga enak, tempat strategis dan parkiran cukup luas. Sayangnya ada kang parkir yang wajib dibayar tapi untungnya tanggung jawab jika hujan dikasih kresek.  Sekian terimakasih.','veteran bagus rapi aman nyaman awat bersih kamar mandi awat bersih menu nikmat strategis parkir luas sayang kang parkir wajib bayar untung tanggung hujan kasih kresek sekian terimakasih'),(90305,'nowhere coffee','adib jauhari',3,'10 bulan lalu','Tempatnya nyaman dan bersih, tapi makanannya nggak enak. Kopinya standar lah rasanya dan lebih mahal dari tempat lain. Pelayanan lama tadi, nunggu makanan diantar. Sampai harus ditanyain lagi.','nyaman bersih makan nikmat standar mahal layan nunggu makan ditanyain'),(90306,'nowhere coffee','Marchel Edgar',5,'Diedit 9 bulan lalu','Malang kota cafe, muncul lagi pendatang baru \"Nowhere Malang\". Boleh buat WFC, nge chill santai, dating pun cocok aja kok. First, parkiran disini luas, tempatnya juga aesthetic, luas dan banyak pilihan seat di outdoor maupun indoor.  Untuk varian menu, Nowhere menyediakan beverage yang cukup lengkap, maincourse dari asian food, western, snack dan salad juga ada. Mungkin sedikit saran, seat outdoor sebelah kolam, alas bisa diganti waterproof, karena setelah hujan tidak bisa ditempati karena basah.  Overall, Nowhere good enough, good place, good ambience, tasty food with reasonable price.','muncul nowhere kerja nge chill santai dating cocok first parkir luas indah luas pilih seat outdoor indoor varian menu nowhere sedia beverage lengkap maincourse asi western snack salad saran seat outdoor belah kolam alas ganti waterproof hujan basah nowhere bagus enough bagus bagus ambience tasty reasonable price'),(90307,'nowhere coffee','diprana',5,'setahun lalu','tempatnya strategis samping asrama UM pas, tempatnya comfyy, cocok buat kumpul atau study from cafe, menunya lengkapp, recommended dehh','strategis samping asrama comfyy cocok kumpul study menu lengkapp rekomendasi dehh'),(90308,'nowhere coffee','I\'m Afi',5,'setahun lalu','Beli chocolate ice sama french fries (french friesnya tidak kefoto)... Enak semuaaa... Tempat nyaman pol... Hargaa, sesuai sama kualitas dan pelayanan kok.... Cocok buat nugas yang lama sih kalau kataku hahahahahah..','beli chocolate ice french fries french friesnya nikmat semuaaa nyaman hargaa kualitas layan cocok tugas hahahahahah'),(90309,'nowhere coffee','Ardhina Finzia',3,'Diedit setahun lalu','Tempat enak, bagus, bersih, toilet oke, ada mushola. Hanya saja saat saya datang ber6, waktu di dalam kesusahan cari tempat duduk, adanya kursi utk 2 org jd di gabung jd 6, pdhl ada sofa yg jelas di mejanya ada tulisan kalau di sofa minimal 4 orang tp di situ ada yg duduk hanya 2 orang dan sy tanyakan ke karyawan tapi kurang tegas dalam hal ini. Mohon di perhatikan agar karyawan lebih tegas.  Saya pindah duduk di luar utk ber4, saya tarik kursi sebelah, sama karyawan ngga boleh padahal sebelah kosong, boleh nya pakai kursi kayu. Untuk harga lumayan pricey dengan self service. Saya membawa 3 minuman di mug dan 3 minuman cup plastik yg cukup berat, dan tidak di bantu padahal ada 3 karyawan yg berdiri dekat pintu.','nikmat bagus bersih toilet mushola ber susah cari duduk kursi org gabung sofa meja tulis sofa minimal orang situ duduk orang karyawan mohon perhati karyawan pindah duduk ber tarik kursi belah karyawan belah kosong pakai kursi kayu harga lumayan mahal self service bawa minum mug minum cup plastik berat bantu karyawan pintu'),(90310,'nowhere coffee','Ghost Arkunc',4,'10 bulan lalu','Salah satu coffee yg nyaman di downtown malang. Luas tempatnya ada indoor dan outdoor. Makanan dan minumannya cukup cepat dlm penyajiannya. Affordable price buat semua','nyaman downtown luas indoor outdoor makan minum cepat dlm saji affordable price'),(90311,'nowhere coffee','Amelia Intan D',5,'setahun lalu','Cafe ini vibes-nya nyaman banget! Desain interiornya minimalis, dengan dominasi kayu yang bikin suasana hangat dan cozy. Penerangan lampunya pas, nggak terlalu terang tapi tetap enak buat kerja atau nongkrong santai. Stafnya ramah dan cekatan, meski lagi ramai, pelayanan tetap cepat dan rapi. Tanaman-tanaman hijau yang ada di beberapa sudut ruangan juga menambah kesegaran di dalam cafe. Plus, seating area-nya luas, jadi nggak perlu khawatir rebutan tempat.','vibes nyaman desain interior minimal dominasi kayu suasana hangat nyaman terang lampu terang nikmat kerja nongkrong santai staf ramah cekat ramai layan cepat rapi tanam tanam hijau sudut ruang segar plus seating area luas khawatir rebut'),(90312,'nowhere coffee','Siti Nurabidah',5,'setahun lalu','akhirnyaaaa bisa cobain dessert dan milk basednya, enak banget! aku sukaaa! walaupun datang kepagian dan belum ready utk makanan berat tp gpp, yg penting bisa nongki sebentar, my first wishlist checked in 2025! semoga bisa kembali ke Malang lg utk cobain menu nowhere lainnyaaa, thank you atas pelayanan yg sangat ramah🤗','akhirnyaaaa cobain dessert milk basednya nikmat sukaaa ready makan berat nongkrong sebentar first wishlist checked moga cobain menu nowhere lainnyaaa thank layan ramah'),(90313,'nowhere coffee','Hafidzatuz Zuhriatin',5,'setahun lalu','Tempatnya luas dan menyenangkan, minumannya juga enak. Pelayanannya juga bagus, kakaknya ramah. Terima kasih🥰','luas senang minum nikmat layan bagus kakak ramah terima kasih'),(90314,'nowhere coffee','Shafa Marwah m',5,'6 bulan lalu','tempatnya enak, makanan dan minuman juga variatif dan cocok untuk belajar nongkrong','nikmat makan minum variatif cocok ajar nongkrong'),(90315,'nowhere coffee','Alvira Chairunnisa',5,'8 bulan lalu','Tepat ngopi paling enak,nyaman dan nyantai. Karyawannya humble baik super ramah, makanan dan minumannya enak bgt💫','nikmat nyaman nyantai karyawannya humble super ramah makan minum nikmat'),(90316,'nowhere coffee','Haqqi Annazily',5,'setahun lalu','So far suasana di ruang ber ac cozy dan juga buat nugas atau kerja lebih sans, untuk makanannya kebanyakan enak\" mungkin bisa lebih diempukin dagingnya, untuk bali mixnya enak parahh dan afogatonya yg ga pait gitu kopinya, enak deh pokoknyaa','far suasana ruang ber nyaman tugas kerja sans makan nikmat diempukin daging bal mixnya nikmat parahh afogatonya pait nikmat pokoknyaa'),(90317,'nowhere coffee','Vale’s trace',5,'Diedit 4 bulan lalu','Ambiencenya oke, cocok buat nugas dan makan bareng','ambiencenya cocok tugas makan bareng'),(90318,'nowhere coffee','Brilliant A.',4,'11 bulan lalu','tempatnyaaa lucuusw dan comfyy banget, adem kalo kesini(walaupun outdoor) disini bs area tenang sm rame jg, soalnya di belakang (area outdoor)ada anak sekolh kalo istirahaat ramee pwooll 😩😩🚹🙏🏻 minumannya jg enaaak enak sigg+++ harganya ga semurah itu tp worth for buy it terus juga arsitekturnya manTAAAPP POL💙🤍🩶🩵 KAMAR MANDINYAA WANGII DAN BERSIHHH (ada kresek hitam jg disitu hihi) aestetik bangeEETTT&@$&&&','tempatnyaaa lucuusw comfyy adem outdoor area tenang ramai area outdoor anak sekolh istirahaat ramai pwooll minum enaaak nikmat sigg harga murah layak buy arsitektur mantaaapp kamar mandinyaa wangi bersihhh kresek hitam situ hihi aestetik bangeeettt'),(90319,'nowhere coffee','Dhamar Syawal',5,'4 bulan lalu','Tempatnya nyaman dan comfy, cocok buat nugas','nyaman nyaman cocok tugas'),(90320,'nowhere coffee','Muhammad Wahyu Shafrul Hidayat',5,'setahun lalu','Pertama kali dateng kesini setelah beberapa kali lewat. Tempatnya bagus, comfy, dan banyak colokan. Cocok untuk nongkrong bahkan wfc.','bagus nyaman colok cocok nongkrong kerja'),(90321,'nowhere coffee','Mamira',3,'setahun lalu','Tmpny strategis d pgir jln raya, dpn mall matos dan samping UM, luas, parkir mobil & motor memadai. Sygnya ketika kesana menu beratnya kosong ktnya ad nya siang, pdhl sya dtg jam 10.30 sedangkan cafe buka jam 9. Trs cake2 juga tdk ada, alsan waitres ketika sya tny ktnya sdh dr kemarin habis. Lucu ya koq tdk d restock pdhl cafe. Yg ad hny donat shrga 15K/pcs. Dan rsnya B aj. Utk minumanny oke lah. Sya psn americano & juice.','tmpny strategis pgir jln raya dpn mall matos samping luas parkir mobil motor sygnya kesana menu berat kosong ktnya sya jam jam cake tdk alsan waitres sya tny ktnya sdh kemarin habis lucu koq tdk restock hny donat shrga pcs rsnya minumanny sya psn americano juice'),(90322,'nowhere coffee','MVP House',5,'7 bulan lalu','Sering banget kesini.. Apalagi mie nyemeknya juaraaa🤤🤤udah nyoba banyak menu pokoknya,, recomended.. Buat nugas juga ok','mie nyemeknya juaraaa nyoba menu pokok recomended tugas'),(90323,'nowhere coffee','Rida Rizki R',3,'setahun lalu','service nya bagus, tempatnya juga comfy banget buat nugas maupun nongkrong. tp makanannya (sorry to say) gaenak banget. baru kali ini makan di cafe yg rasanya wow zonk. maaf… kita pesen aglio mushroom 4, dan smua nya rasanya anyep, hambar, gaada rasa, cuman kaya pasta dipakein air. padahal looks dari makanannya tempting banget tapi ternyata makanannya kurang enak.. sedih banget sih, mungkin bisa dijadiin bahan evaluasi lagi','service bagus nyaman tugas nongkrong makan sorry say gaenak makan wow zonk maaf pesan aglio mushroom smua anyep hambar gaada kaya pasta dipakein air looks makan tempting makan nikmat sedih dijadiin bahan evaluasi'),(90324,'nowhere coffee','Diana Nur Utami',5,'11 bulan lalu','Cafe yg nyaman. Tempat nugas yg asyik. Paling suka iced coffee latte nya... Rasa kopinya mantap. Mie nyemeknya terlalu manis bagi saya. Paling enak saladnya. Selalu rame dan kursi diindoor terbatas. Pricenya standar cafe di Malang. Beverage di kisaran 25k ke atas. Main coursenya 35k keatas, side dish dikisaran 18k keatas, pastry donat cheese cake mulai di 18k.','nyaman tugas nyaman suka iced latte bagus mie nyemeknya manis nikmat saladnya ramai kursi diindoor batas pricenya standar beverage kisar main coursenya side dish kisar pastry donat cheese cake'),(90325,'nowhere coffee','Etika Yustiningsih',5,'setahun lalu','Dari luar kaya biasa aja, tapi pas masuk ambience nya oke banget. Suasananya warm dan nyaman. Harga makanan dan minuman terjangkau. Tapi sayangnya kalau cuma dtg berdua ga bisa pilih duduk di sofa (ruangan ber ac). Tempat duduk yg untuk berdua kebanyakan dari kayu jadi agak kurg nyaman kalau mau ngobrol agak lama . Padahal betah banget lama2 duduk di cafe ini. But overall cafe ini wajib jd destinasi klo kamu lagi ke Malang 🤗','kaya ambience suasana warm nyaman harga makan minum murah sayang pilih duduk sofa ruang ber duduk kayu kurg nyaman ngobrol betah duduk wajib destinasi'),(90326,'nowhere coffee','Neny Maulidya',5,'10 bulan lalu','Tempatnya nyaman, kebetulan udah sarapan jadi cuma order americano. Sangat luas dan cukup ramai tapi masih cocok buat chill. Toilet bersih dan wangi, next InsyaAllah balik lagi mau cobain menu makanannya. Deket juga sama sekolah anakku,  bisa jadi tempat favorit nunggu anak pulang sekolah.','nyaman sarap order americano luas ramai cocok chill toilet bersih wangi next insyaallah cobain menu makan deket sekolah anak favorit nunggu anak pulang sekolah'),(90327,'nowhere coffee','Mukhamad Hidayat',5,'10 bulan lalu','Tempatnya nyaman untuk WFC, nongkrong & kumpul keluarga. Area bar bersih enak dipandang customer saat pesan maupun ambil pesanan','nyaman kerja nongkrong kumpul keluarga area bar bersih nikmat pandang customer pesan ambil pesan'),(90328,'nowhere coffee','Antasena Antasena',5,'4 bulan lalu','kasir ramah, servernya yang antar makanan juga rama banget,','kasir ramah servernya makan rama'),(90329,'nowhere coffee','Evan Hutomo',4,'setahun lalu','pastri donat enak, kopi enak, cma pesen makan nunggu 1 jam. Semoga bisa ditingkatkan biar bsa receive order heavy mealnya lbh cpat 🙏','pastri donat nikmat nikmat cma pesan makan nunggu jam moga tingkat bsa receive order heavy mealnya cpat'),(90330,'nowhere coffee','Dewi Puspitasari',5,'3 bulan lalu','Cari tempat nongkrong yg cozy g tll.rame banget...bisa disini','cari nongkrong nyaman tll ramai'),(90331,'nowhere coffee','khusnul fatimah',5,'setahun lalu','Cafe yg nyaman buat nugas atau working sih, toilet nya sangat lengkap cewe frendly dan bersih puol. Porsi makan jg banyak','nyaman tugas working toilet lengkap cewe frendly bersih puol porsi makan'),(90332,'nowhere coffee','Nasywa Azizah',5,'9 bulan lalu','sukaaa banget sm ambiencenya,  cocok juga buat dipake me time sambil nugas, minuman makananannya juga oke','sukaaa ambiencenya cocok dipake time tugas minum makananannya'),(90333,'nowhere coffee','Denny Adie Absoni',5,'4 bulan lalu','Rekomendasi buat WFC, cozy, enjoy, stafnya ramah, makanannya enak enak','rekomendasi kerja nyaman enjoy staf ramah makan nikmat nikmat'),(90334,'nowhere coffee','Chyta Work',5,'7 bulan lalu','Overall oke, tempt nyaman, pelayanan ramah, makanan mantap.  Hanya kurang 1, semoga menyediakan air mineral gratis free refill spt cafe2 tetangga.  Success nowhere!','tempt nyaman layan ramah makan bagus moga sedia air mineral gratis free refill spt tetangga success nowhere'),(90335,'nowhere coffee','angel',3,'setahun lalu','enak sebenernya, tapi wifinya kurengg banget dan colokannya termasuk sedikit dan tadi tiba2 mati (tpi ga lama idup lagi sih). untuk porsi makananannya sesuai dengan harganya. tadi pesen nasgor sama sesame chicken rice. untuk rasa semua template aja sih ga ada yg special, tpi entah kenapa nasgornya dingin ya..apa karna ga langsung disajiin alias masih nunggu2 gitu atau entahlah. ++++kamar mandinya bersih, wangi dan disediakan kantong plastik hitam yg kecil!!!','nikmat sebenernya wifi kurengg colok mati idup porsi makananannya harga pesan nasgor sesame chicken rice template special nasgornya dingin disajiin alias nunggu kamar mandi bersih wangi sedia kantong plastik hitam'),(90336,'nowhere coffee','debby bakhtiyar',5,'2 bulan lalu','Tempat nunggu anak2 pulskul... suka suasananya tenang...','nunggu anak pulskul suka suasana tenang'),(90337,'nowhere coffee','Erwin Nugroho',5,'4 bulan lalu','Suasananya enak buat ngerjain tugas','suasana nikmat ngerjain tugas'),(90338,'nowhere coffee','Nur citra Anggraini',5,'setahun lalu','Dengan tempat sebagus ini, harga makanan dan minumannya cukup terjangkau, dan gong banget sih nasi gorengnya porsi kuli kenyang banget dan enakkkkkkkkk😍😍😍','bagus harga makan minum murah gong nasi goreng porsi kuli kenyang enakkkkkkkkk'),(90339,'nowhere coffee','Dinithea',4,'3 bulan lalu','Cafe ini keliatan mencolok dari jalan karena berwarna kuning. Di bagian depan terdapat ruangan perpustakaan kecil dan di halaman ada beberapa meja dan kursi untuk pengunjung yang merokok  Bangunan utama cukup luas dengan berbagai pilihan meja dan kursi.  Ada juga yang berbentuk soda melingkar dengan minimal pembelian jika ingin duduk disitu.  Harga agak pricy tapi rasanya enak Toilet dan mushola ada di bagian belakang dekat taman','liat colok warna kuning ruang pustaka halaman meja kursi unjung rokok bangun utama luas pilih meja kursi bentuk soda lingkar minimal beli duduk situ harga mahal nikmat toilet mushola taman'),(90340,'nowhere coffee','Adios Amigo Zikri',5,'setahun lalu','Tempat yang bagus buat nugas dan ngumpul bareng keluarga. makanan dan minuman enak dan harga terjangkau. tempat bersih, pelayanan ramah dan murah senyum. ada toilet dan kamar mandi bersih juga. recommended bgtt.','bagus tugas nongkrong bareng keluarga makan minum nikmat harga murah bersih layan ramah murah senyum toilet kamar mandi bersih rekomendasi'),(90341,'nowhere coffee','frida frido',5,'setahun lalu','Tempat cozy dan luas banget outdoor nya, harga ga trlalu mahall','nyaman luas outdoor harga trlalu mahall'),(90342,'nowhere coffee','Eka surya Wijayanti',5,'7 bulan lalu','Sangat nyaman tempat nya, terlebih lagi malam hari, dan pelayanan sangat cepat.','nyaman layan cepat'),(90343,'nowhere coffee','Tsalits Syafa\'atun Nashiroh',5,'8 bulan lalu','Vibesnya nyaman untuk nugas maupun nongki2 santai. Bisa outdoor maupun indoor, ada vip meeting room juga. Makanan minuman banyak pilihannya. Mantap','vibesnya nyaman tugas nongkrong santai outdoor indoor vip kerja room makan minum pilih bagus'),(90344,'nowhere coffee','Mawaddatul Rohimah',5,'setahun lalu','Nowhere memiliki konsep yang menarik dengan suasana yang tenang. Pilihan minuman dan makanan cukup beragam, meskipun harganya sedikit lebih tinggi dibanding tempat lain. Pelayanannya cukup baik, dan cepat menurut saya. Tempat nya juga enak buat wfc, nongkrong, dll.','nowhere milik konsep tarik suasana tenang pilih minum makan agam harga banding layan cepat nikmat kerja nongkrong dll'),(90345,'nowhere coffee','hadi susanto',5,'setahun lalu','Tempatnya luas dan nyaman buat nongkrong, makan, ataupun kerja. Menunya variatif, stafnya sangat helpfull','luas nyaman nongkrong makan kerja menu variatif staf helpfull'),(90346,'nowhere coffee','Diana Dian',5,'6 bulan lalu','Cozyyyy bagus nyaman kopinya enakk makanan enakkkk','cozyyyy bagus nyaman nikmat makan enakkkk'),(90347,'nowhere coffee','Febby Filan',4,'10 bulan lalu','Makananya lumayan, coffee nya terlalu pahit, kayak americano padahal pesan mocha, untuk makanannya 7/10 lah, tempatnya riuh banget full terus, tapi nyaman banget, next kesini lagi','makananya lumayan pahit americano pesan mocha makan riuh full nyaman next'),(90348,'nowhere coffee','Trilisa',5,'setahun lalu','Kafe yang sangat besar & cukup luas Saking besarnya kebersihan kurang cukup terjaga Karena dibagian teras terlihat sedikit sampah dilantai Suasana oke Rasa kopi oke Harga standard kafe medium-high','luas saking bersih jaga teras sampah lantai suasana harga standard medium high'),(90349,'nowhere coffee','Fransiska Aprodite',5,'setahun lalu','Kafe ini memiliki suasana yang nyaman dan cocok untuk bekerja (WFC) atau sekadar bersantai. Dengan pilihan area indoor yang estetik dan outdoor yang dikelilingi tanaman hijau, tempat ini menawarkan udara sejuk yang menenangkan. WiFi kencang dan suasana tenang membuatnya ideal untuk produktivitas. Selain itu, pelayanan ramah dan menu kopi yang enak semakin menambah pengalaman menyenangkan. Baik untuk kerja, nongkrong, atau menikmati me time, kafe ini jadi pilihan yang pas!','milik suasana nyaman cocok kerja santa pilih area indoor indah outdoor keliling tanam hijau tawar udara sejuk tenang wifi kencang suasana tenang ideal produktivitas layan ramah menu nikmat alam senang kerja nongkrong nikmat time pilih'),(90350,'nowhere coffee','Annisa Rizky',5,'5 bulan lalu','i realli like this cafee, ambiencenya mantap banget, cocok untuk wfc/wfa dan meeting','realli like cafee ambiencenya bagus cocok kerja kerja kerja'),(90351,'nowhere coffee','Ellen Royan',5,'setahun lalu','Tempat cozy, enak buat nugas atau ngumpul sama teman2 . Vibesnya asik dan lumayan rame . Ada outdoor yg bener2 nyaman . Untuk menu dan harga worth it lah . Goodjob','nyaman nikmat tugas nongkrong teman vibesnya nyaman lumayan ramai outdoor bener nyaman menu harga layak goodjob'),(90352,'nowhere coffee','Nindielese',5,'Diedit setahun lalu','Ambients mantap banget, tempatnya luas, enak buat nugas, harga sepadan dengan rasa, pelayanan, dan fasilitas.','ambients bagus luas nikmat tugas harga padan layan fasilitas'),(90353,'nowhere coffee','zia caca',5,'setahun lalu','makanan dan minumannya enakk! chocolate iced favoo🤩 tempat nyaman, cocok buat nugas sama nongkrong! layanannya juga oke bangett semuanya ramahh🙌🏼','makan minum nikmat chocolate iced favoo nyaman cocok tugas nongkrong layan ramahh'),(90354,'nowhere coffee','Anita Siska',5,'setahun lalu','Lumayan sih, buat harga makanan+minuman standar cafe, buat rasanya standar juga, mie nyemeknya agak keasinan, pelayanannya lebih ke self service.','lumayan harga makan minum standar standar mie nyemeknya asin layan self service'),(90355,'nowhere coffee','Salma Rosalia',5,'8 bulan lalu','Udah langganan ke sini, recommended bgt apalagi choco donutnya. Tempatnya nyaman, WiFi kenceng, ada musholla juga, toilet bersih','langgan rekomendasi choco donutnya nyaman wifi kenceng musholla toilet bersih'),(90356,'nowhere coffee','148_Ghaitsa Zahira Shofa',5,'9 bulan lalu','Tempat cozy, harga terjangkau, worthit, jangan lupa datangg ke nowhere','nyaman harga murah layak lupa datangg nowhere'),(90357,'nowhere coffee','Christian Christian',5,'9 bulan lalu','Tempat luas, terutama outdoor belakang, minuman enak dan cepet bgt keluar nya, dan yang paling penting parkir nya bisa QRIS 👍🏻👍🏻👍🏻','luas outdoor minum nikmat cepat parkir qris'),(90358,'nowhere coffee','Raqayya Gayathri',5,'setahun lalu','Coffee latte nya enak banget!! tipe coffee yang bold strong gituuu! :D tempatnya juga comfy, wifi nya lumayan cepet jugaa worth it buat nugas','latte nikmat tipe bold strong gituuu nyaman wifi lumayan cepat jugaa layak tugas'),(90359,'nowhere coffee','Nuurul Ula',4,'3 bulan lalu','Cukup enak...pilihan tempat luas, cocok buat SFC/WFC Sayang kmrn pas duduk , colokan listrik enggak berfungsi Makanan cukup enak...saat kami ke sana ada bbrp yg blm ready','nikmat pilih luas cocok sfc kerja sayang kmrn duduk colok listrik fungsi makan nikmat ready'),(90360,'nowhere coffee','Laila Afiata',5,'9 bulan lalu','Area outdoor luas. Cozy. Ada sofa, kolam kecil. Banyak tanaman. Sangat nyaman','area outdoor luas nyaman sofa kolam tanam nyaman'),(90361,'nowhere coffee','Jinnie Hyunn',5,'setahun lalu','Kesini karena tempatnya super luas buat nongkrong dan ambiencenya cozy untuk nugas. Banyak colokan juga disetiap sudut meja. Menu yang ditawarkan juga semua premium.','super luas nongkrong ambiencenya nyaman tugas colok sudut meja menu tawar premium'),(90362,'nowhere coffee','Human Strong',5,'5 bulan lalu','suasananya nyaman banget siii disinii. buat nugas pw.','suasana nyaman siii tugas nyaman'),(90363,'nowhere coffee','Dini Lestari',5,'2 bulan lalu','Tempat nongkrong sambil mengerjakan tugas anak kuliahan. Ngopi dan bersantai juga bisa. Tempat duduk banyak karena luas dari depan teras sampai belakang.','nongkrong tugas anak kuliah santa duduk luas teras'),(90364,'nowhere coffee','Rosana Oktaviani',3,'setahun lalu','Desain interiornya baguss bangett, suhu AC pas tidak terlalu dingin, musholla dan toilet bersih dan wangi, tapi wifinya kurang stabil dan tidak disediakan kabel olor sehingga kurang nyaman untuk customer yang ingin wfc 🙏🏻','desain interior baguss suhu dingin musholla toilet bersih wangi wifi stabil sedia kabel olor nyaman customer kerja'),(90365,'nowhere coffee','Bambang Hariyanto',5,'Diedit 8 bulan lalu','staffnya ramah, makanan dan minumannya enak semua','staffnya ramah makan minum nikmat'),(90366,'nowhere coffee','Fly High',5,'4 bulan lalu','Tempat favorit untuk nugas, suasana sangat tenang','favorit tugas suasana tenang'),(90367,'nowhere coffee','delisa',5,'8 bulan lalu','tempatnya nyaman dan dingin cocok buat nugas, minumannya juga enak','nyaman dingin cocok tugas minum nikmat'),(90368,'nowhere coffee','Amelia Margono',5,'9 bulan lalu','Produk nya oke, cozy, colokan banyak, cocok buat wfc','produk nyaman colok cocok kerja'),(90369,'nowhere coffee','andi',3,'5 bulan lalu','Tempatnya luas, ada banyak pilihan tempat duduk di indoor maupun outdoor. Area parkirnya juga luas, baik untuk mobil dan motor.  Ambiencenya bagus dan memang cocok untuk WFC. Namun, pemilihan musiknya agak kurang cocok di saya. Kemarin pas kesana, pemilihan playlistnya dominan edm dengan bass yang kencang. Selain itu, order saya juga sempat terlewat dan belum dibuatkan dengan baristanya.  Mungkin akan cocok untuk yang suka bekerja dengan suasana ramai.','luas pilih duduk indoor outdoor area parkir luas mobil motor ambiencenya bagus cocok kerja pilih musik cocok kemarin kesana pilih playlistnya dominan edm bass kencang order baristanya cocok suka suasana ramai'),(90370,'nowhere coffee','audrya nasywa',5,'setahun lalu','comfort placeee untuk skripsiaan, makanan dan minumannya enak\", tempatnya juga comfy, speed wifi oke, will go back again and again 😁','comfort placeee skripsiaan makan minum nikmat nyaman speed wifi back'),(90371,'nowhere coffee','Gabriellaalfa Huwae',5,'setahun lalu','Tempatnya nyaman banget,, makannya ok.. cocok banget buat tempat nongkrong sama temen-teman 😊','nyaman makan cocok nongkrong teman teman'),(90372,'nowhere coffee','Maryam Maryam',5,'setahun lalu','Tempatnya luas ada indoor dan outdoor, pilihan menunya juga banyakk dan overall enak kok. Poin plus karena deket banget dari kampus serta ada musholla yang lumayan proper','luas indoor outdoor pilih menu banyakk nikmat poin plus deket kampus musholla lumayan proper'),(90373,'nowhere coffee','Khaishia',4,'9 bulan lalu','ambience nya enak banget adem, spot duduk nya juga banyak klo makanannya enak sih cuma pastry nya kurang worth it dengan price segitu','ambience nikmat adem spot duduk makan nikmat pastry layak price segitu'),(90374,'nowhere coffee','Yatnaz Tasya',5,'7 bulan lalu','nyaman nongkrong disini, bisa buat laptopan juga. pelayanan oke banget','nyaman nongkrong laptop layan'),(90375,'nowhere coffee','Firda Fatmalla Hapsari',5,'2 bulan lalu','Enak nyaman murah','nikmat nyaman murah'),(90376,'nowhere coffee','Fanny michel Kowaas',5,'setahun lalu','pelayanannya baik dan ramah, tempatnya luas dan nyaman, banyak varian menunya ada makanan berat dan snack jugaa, dan yang paling penting sangat cocok buat nugas😊🤩 …','layan ramah luas nyaman varian menu makan berat snack jugaa cocok tugas'),(90377,'nowhere coffee','Ardhan Sidqi Priandayani',5,'setahun lalu','makanannya enak, minumannya jg enak jg. trs tempatnya nyaman banget buat nugas, pokoknya debestt','makan nikmat minum nikmat nyaman tugas pokok debestt'),(90378,'nowhere coffee','Hantaran Amira',5,'setahun lalu','Best cafe ever, menunya enak, lokasinya cozy banget, strategis, Wifi-nya oke, ada musholla juga yang nyaman banget.','ever menu nikmat nyaman strategis wifi musholla nyaman'),(90379,'nowhere coffee','James Bond',5,'9 bulan lalu','Tempatnya nyaman, bersih & dilengkapi baby chair untuk keluarga yg bawa baby, Cappuccino nya enak','nyaman bersih lengkap baby chair keluarga bawa baby cappuccino nikmat'),(90380,'nowhere coffee','RIS 406',5,'setahun lalu','suasana enak banget, cuma tolong banget saya kena prank sama tempat duduk outdoor yang busa…kalo musim hujan jangan di taruh outdoor, jadinya celana saya basah deh😭','suasana nikmat tolong kena prank duduk outdoor busa musim hujan taruh outdoor celana basah'),(90381,'nowhere coffee','Aan Prastya',5,'6 bulan lalu','Tempat luas, vibe santai banget.','luas vibe santai'),(90382,'nowhere coffee','sherin maudri asy\'ari',5,'setahun lalu','Tempatnya nyaman, buka sampe malem, banyak pilihan menu, red velvetnya lembut, pelayanannya cepet dan ramah 🥰🥰','nyaman malem pilih menu red velvetnya lembut layan cepat ramah'),(90383,'nowhere coffee','Dimas Alief Pratama',5,'5 bulan lalu','Nyaman dan makanannya enak 🤤','nyaman makan nikmat'),(90384,'nowhere coffee','Achmad Ziddanial Muqodash Badryy',5,'setahun lalu','Udah berkali kali kesini, tempatnya nyaman enak buat me time ataupun ngobrol, baristanya gercep gercep banget. Warga malang sini yukk','nyaman nikmat time ngobrol baristanya gercep gercep warga yukk'),(90385,'nowhere coffee','gaby felicia',5,'9 bulan lalu','Tempatnya nyaman banget buat nugas dan makanannya enakk🤩','nyaman tugas makan nikmat'),(90386,'nowhere coffee','kartika amelia',5,'9 bulan lalu','tempatnya nyaman banget,bersih,pelayanan cepat dan ramah.makanan dan minuman enak','nyaman bersih layan cepat ramah makan minum nikmat'),(90387,'nowhere coffee','indah utami',3,'setahun lalu','Lokasi ok, vibesnya juga. Kalau kopinya B aja menurutku. Yang agak mengecewakan adl saat mau pesan makanan. Kami datang sekitar jam 9.40, pas mau pesan makan dibilang kalau kitchen baru akan buka jam 10.00. Ya sudahlah, kami tunggu. Lalu sekitar jam 10.18, kami ke kasir lagi mau pesan makanan, eh dibilang kalau kitchen baru akan buka jam 11.00. Akhirnya aku protes dan menyampaikan kalau kasir sebelumnya bilang kitchen buka jam 10.00. Akhirnya ditanyakanah e temannya, dan bilang kitchen akan buka jam 10.30.  At the end of the day, gak jadi pesan makanan karena udah terlanjur bete di-PHP. 🥲  Mohon dikasih info yg jelas ttg hal ini, kalau perlu ditulis di menu atau apalah ya, biar gak mengecewakan pelanggan.','vibesnya kecewa adl pesan makan jam pesan makan bilang kitchen jam tunggu jam kasir pesan makan bilang kitchen jam protes kasir bilang kitchen jam ditanyakanah teman bilang kitchen jam end day pesan makan lanjur bete php mohon kasih info ttg tulis menu kecewa langgan'),(90388,'nowhere coffee','Putri Amalia',5,'setahun lalu','Tempatnya cozy dan pewe buat nugas lama, kopi nya enak dan makanannya porsinya banyak','nyaman nyaman tugas nikmat makan porsi'),(90389,'nowhere coffee','Putri Ayudya',3,'setahun lalu','Nachos 45rb dengan kripik singkong yg tdk crunchy. Kripik singkong ya emang judulnya cassava nachos. Agak laen konsep nachos ini. Dan dagingnya main petak umpet. Overall menunya \"unik\" harganya. Nasi goreng dibandrol 25rb sdgkan banana bite,corn rib >30rb. 😅😅😅','nachos kripik singkong tdk crunchy kripik singkong emang judul cassava nachos laen konsep nachos daging main petak umpet menu unik harga nasi goreng dibandrol sdgkan banana bite corn rib'),(90390,'nowhere coffee','bianca alexa',5,'4 bulan lalu','Cafe Nowhere selalu jadi pilihan pertama aku untuk WFC. Tempatnya super comfy, wifi kenceng, pelayanannya bagus, dan AC-nya juga dingin. Pokoknya nyaman banget buat nugasss bareng teman-teman🫰🏻','nowhere pilih kerja super nyaman wifi kenceng layan bagus dingin pokok nyaman nugasss bareng teman teman'),(90391,'nowhere coffee','Deya Refionika',5,'8 bulan lalu','cocok si buat yg mau wfc-an, makanannya jg enak-enak, kasirnya ramah, pengetahuan tntang produknya juga bagus bgt! dan lg.. ice macchiato.nya best bgt!!','cocok kerja makan nikmat nikmat kasir ramah tntang produk bagus ice macchiato'),(90392,'nowhere coffee','debbiie debo',5,'setahun lalu','Saladnya Freshhh seger sayuran ndak pahit. sangat cocok untuk udara malang yang sedang panas. Jus Detoxnya isinya pepaya milky gitu bikin lancar pencernaan dan rasanya wenaaak. Lychee Tea enak berasa pekat tehnya dan wangi manis lecinya, ada buah lecinya besar besar Suegerrrr','saladnya freshhh segar sayur pahit cocok udara panas jus detoxnya isi pepaya milky lancar cerna wenaaak lychee tea nikmat asa pekat teh wangi manis leci buah leci suegerrrr'),(90393,'nowhere coffee','Riya Tanjung - 081',5,'setahun lalu','Makanannya enak dan harganya menurut saya pas, suasananya juga tdk terlalu noise, tempatnya luas dan banyak pilihan tempat duduk','makan nikmat harga suasana tdk noise luas pilih duduk'),(90394,'nowhere coffee','Winndy alfira',5,'4 bulan lalu','tempat nya nyaman , bersih dan syahdu .','nyaman bersih syahdu'),(90395,'nowhere coffee','Ananda Ricky Fauzi',5,'setahun lalu','Ambience nya sangat nyaman, servicesnya sangat ramah serta sangat membantu, terlebih minumannya juga cocok di lidah.','ambience nyaman servicesnya ramah bantu minum cocok lidah'),(90396,'nowhere coffee','Atika Fitria Arifiana',5,'setahun lalu','Suka  banget ada musholla nya, adem, pintu dibukain mas nya act of service bgt, ramahh bintang 5 service nya kasir maupun barista nya🤗❤️','suka musholla adem pintu dibukain mas act service ramahh service kasir barista'),(90397,'nowhere coffee','GERALDA DESINTHA RISA PUTRI',5,'9 bulan lalu','tempatnya very cozy dan sangat cocok untuk me time maupun spend time dengan teman, sangat recommendes','nyaman cocok time spend time teman recommendes'),(90398,'nowhere coffee','Reza Wildan',3,'3 bulan lalu','Parkir ga jelas, katanya bayar wajib pake online. Waktu keluar, bukannya karcis yg di scan tapi harus nyodorin bukti transaksi di aplikasi hp','parkir bayar wajib pakai online karcis scan nyodorin bukti transaksi aplikasi'),(90399,'nowhere coffee','RATIH PUSPITASARI',5,'setahun lalu','Suasana baru tempat makan siang. Suasananya nyaman. Tempatnya luas. Tempat parkirnya juga luas. Rasa makanannya enak. Harganya standart untuk ukuran cafe. Wajib di coba untuk anak gaul zaman now dan para pekerja sekitar UM...','suasana makan suasana nyaman luas parkir luas makan nikmat harga standart ukur wajib anak gaul zaman kerja'),(90400,'nowhere coffee','Habel Gani',5,'setahun lalu','Lokasi mudah ditemukan karena di jalan raya, parkiran luas, pelayanan ramah. Harga ok sesuai dengan kualitas','mudah temu raya parkir luas layan ramah harga kualitas'),(90401,'nowhere coffee','Putri Charmilia',5,'6 bulan lalu','Tempatnya enak banget buat nongkrong bareng temen atau buat kerja','nikmat nongkrong bareng teman kerja'),(90402,'nowhere coffee','Melanie Angela',5,'setahun lalu','Tempatnya cozy buat nugas, makanannya enak, pelayanannya ramah, worth it!!!!','nyaman tugas makan nikmat layan ramah layak'),(90403,'nowhere coffee','Yolanda Rahelmi',5,'setahun lalu','tempatnya baguss dan nyaman cocok buat wfh, servicenya juga oke, makanannya enakk, mantapp👌🏻','baguss nyaman cocok kerja servicenya makan nikmat mantapp'),(90404,'nowhere coffee','Anggieta Ratuyustiarany',5,'setahun lalu','sowww cozy here, enak banget buat nugas disiniiiiii tiap hari selalu kesini, the food, the ambience, the service all perfect🤩💗','sowww nyaman nikmat tugas disiniiiiii ambience service perfect'),(90405,'nowhere coffee','Farah Hardina',5,'9 bulan lalu','Enak banget tempatnya dingin, mau kerja  sambil minum kopi bikin mood bgt','nikmat dingin kerja minum mood'),(90406,'nowhere coffee','Rizka Agustin',5,'setahun lalu','tempat nyaman, makan dan minum nya enak . harga afrodablle','nyaman makan minum nikmat harga afrodablle'),(90407,'nowhere coffee','Daniah',4,'11 bulan lalu','Pesen nasi goreng. Nasinya keras😔 ntah gak mateng atau emang teksturnya sengaja dibuat kerasnya seperti itu. Padahal rasanya udah pas, minus disitu aja sih','pesan nasi goreng nasi keras ntah mateng emang tekstur sengaja keras minus situ'),(90408,'nowhere coffee','Azzahrah Ricma Putri',5,'5 bulan lalu','Kerenn..tempatnya enak buat nugas','kerenn nikmat tugas'),(90409,'nowhere coffee','Hana Shafiyyah',5,'9 bulan lalu','tempat comfy buat nugass, makanannya oke juga ada banyak promo kalo kalian ikutin ignyaaa, masih kantong mahasiswa dengan tempat yg okee','nyaman nugass makan promo ikutin ignyaaa kantong mahasiswa okee'),(90410,'nowhere coffee','Arik Luvian',4,'setahun lalu','lokasi enak, tengah kota, makanan minuman oke, service ok, yg pasti toiletbdan tempat ibadahnya bersih dan nyaman.. next bisa mampir kesini lg','nikmat makan minum service toiletbdan ibadah bersih nyaman next mampir'),(90411,'nowhere coffee','Muhammad Azri Ismail',5,'setahun lalu','Tempatnya nyaman makanannya enak pelayanannya ramah dan baik','nyaman makan nikmat layan ramah'),(90412,'nowhere coffee','Daffa Arghana',5,'setahun lalu','Caffe area malang,enak banget tempatnya kekinian. makanan minumannya enak bang murah murah lagi. recomended polll','caffe area nikmat makan minum nikmat bang murah murah recomended polll'),(90413,'nowhere coffee','Yovita Kanaya',5,'9 bulan lalu','tempatnya aesthetic and sangat pw untuk nugas! pilihan makanannya juga banyak jd pasti nyaman','indah nyaman tugas pilih makan nyaman'),(90414,'nowhere coffee','ferdiana rafikasari',3,'setahun lalu','Overall sih oke buat pelayanan dan minuman, cuman kurang rekom buat wfc karena internetnya lemot banget sampe pake hotspot pribadi. Next mungkin bisa lebih diperbaiki buat internetnya.','layan minum rekom kerja internetnya lot pakai hotspot pribadi next internetnya'),(90415,'nowhere coffee','madaley',5,'6 bulan lalu','bagus bgt nyaman pelayanan ramah, kasirnya ramah','bagus nyaman layan ramah kasir ramah'),(90416,'nowhere coffee','Ahmad Bagus',5,'setahun lalu','Tempatnya nyaman buat anak muda dan keluarga. Bisa buat kerja. Luas, ada indoor dan outdoor. Bersih.','nyaman anak muda keluarga kerja luas indoor outdoor bersih'),(90417,'nowhere coffee','Kiky Rezky Thea',5,'8 bulan lalu','Tempatnya oke luas nyaman.. Dan makanan dan minumannya jg enak2 💯','luas nyaman makan minum nikmat'),(90418,'nowhere coffee','362_ Tyas Ayu Putri K',5,'setahun lalu','Cafenya nyaman banget dan estetik.. minumnya enak banget sukaaa','cafenya nyaman indah minum nikmat sukaaa'),(90419,'Pesenkopi Plus Betek','justheorgCC',4,'2 bulan lalu','super cooOZyy, but kinda cold at night cuz its rooftop, tapi kalo dapet view secakep ini udara dingin mah gaada apa apanya wkwk, but for the dessert better dipanasin or di oven dulu deh sebelum disajiin, enak kokk cuma keras banget 😞🤏, but so far soo gewdd ❤️ …','super cooozyy kinda cold night cuz rooftop dapet view cakep udara dingin gaada wkwk dessert better dipanasin oven disajiin nikmat kokk keras far soo gewdd'),(90420,'Pesenkopi Plus Betek','gnt',5,'sebulan lalu','Kafe ini gila sih. Lokasinya di tengah kota, ada di rooftop hotel dengan view city lights yang parah bagusnya. Malem-malem duduk di sini tuh vibes-nya dapet banget, anginnya enak, lampu kota keliatan semua. Auto bikin betah… sama auto galau …','gila rooftop hotel view city lights jelek bagus malem malem duduk tuh vibes dapet angin nikmat lampu liat auto betah auto galau'),(90421,'Pesenkopi Plus Betek','hello ladyladyd_',5,'6 bulan lalu','Tempat buat chill santai sambil liat view kota Malang, rekomen sore yaa bagus bangettt enak buat ngobrol. Untuk minuman over all ok lah pelayanannya jg sat set, disini ga jual cemilan yaa guys,kalo mau pesen cemilan di cafe bawah. Untuk …','chill santai liat view rekomendasi sore yaa bagus bangettt nikmat ngobrol minum layan sat set jual cemilan yaa guys pesan cemilan'),(90422,'Pesenkopi Plus Betek','Achmad Lubis',5,'6 bulan lalu','Pesenkopi Plus Betek adalah salah satu tempat ngopi dengan pemandangan terbaik di Kota Malang. Terletak di lantai 6 Hotel Syariah 99 by VRV, di Jl. Mayjend Panjaitan No.191, Penanggungan, Klojen, tempat ini menawarkan suasana yang memadukan …','plus pandang bagus letak lantai hotel syariah vrv mayjend panjaitan tanggung klojen tawar suasana madu'),(90423,'Pesenkopi Plus Betek','Sabilah Mudrikah',3,'sebulan lalu','Kalau buka puasa disini kurang recommended makanannya keras dan udah dingin bgt #izinnn','puasa rekomendasi makan keras dingin izinnn'),(90424,'Pesenkopi Plus Betek','Rafalda Nabila Azhalya',5,'6 bulan lalu','tempat e bagus poll, pelayanan ramah bangett terus minumnya cepet jadiii. viewnya juga bagussss','bagus layan ramah minum cepat jadiii viewnya bagussss'),(90425,'Pesenkopi Plus Betek','Oktavia wnd',5,'5 bulan lalu','Suasana yang sangat asri, enak, nyaman, aesthetic dan pelayanan yang sangat super duper baik makanan dan minuman juga enak poll worth itt','suasana asri nikmat nyaman indah layan super duper makan minum nikmat layak itt'),(90426,'Pesenkopi Plus Betek','Berliani Ganda',5,'6 bulan lalu','Tempatnya bagus rooftop gitu, pesennya scan langsung barcode di meja. Minumannya enak enak tapi kalo ngga suka manis pesannya less sugar ya.','bagus rooftop sen scan barcode meja minum nikmat nikmat suka manis pesan less sugar'),(90427,'Pesenkopi Plus Betek','Achmad HM Lubis UINSA',5,'6 bulan lalu','Tempat ini dibilang hidden gem, terletak di dalam Hotel 99 di Jalan Mayjen Panjaitan. Berada di lantai 6 membuat view pegunungan sekaligus kota Malang terlihat indah. Syukurnya kami pergi kesana saat cuaca sedang mendukung. Mulai dari siang hari sampai malam. Cafe mulai ramai menjelang sunset tiba karena pemandangan yang menjadi incaran para pengunjung.  Kami memesan Dirty Matcha dan Matcha Lemon, overall untuk rasa minumannya 8,5/10. Recommended banget buat yang ingin bersantai','bilang hidden gem letak hotel mayjen panjaitan lantai view gunung indah syukur pergi kesana cuaca dukung ramai jelang sunset pandang incar unjung mes dirty matcha matcha lemon minum rekomendasi santa'),(90428,'Pesenkopi Plus Betek','Kharisma layar',4,'6 bulan lalu','Cafe masuk hotel di lantai atas. Ada Indoor dan outdoor, ada tempat sholat dan toilet bersih, makanan minuman ok, harga lumayan tapi ok karna tempatnya bersihh. Bisa untuk wfc karena cukup banyak colokan. Area outdoor atas agak ramai orang ngobrol karena mostly dipakai nongkii + musiknya radak kenceng.','hotel lantai indoor outdoor sholat toilet bersih makan minum harga lumayan bersihh kerja colok area outdoor ramai orang ngobrol mostly pakai nongkii musik radak kenceng'),(90429,'Pesenkopi Plus Betek','nurul fitria',5,'3 bulan lalu','Kebetulan nginep di hotel yg rooftopnya ada pesen kopi plus, viewnya dapet banget sih mau sunset atau sunrise.','nginep hotel rooftopnya pesan plus viewnya dapet sunset sunrise'),(90430,'Pesenkopi Plus Betek','Vanessa',5,'6 bulan lalu','Tempatnya nyaman, berangin tapi seger kok, oke banget buat nugas sambil nongkrong. Pelayanannya cepet, baristanya juga ramah pas ditanyain menu rekomendasi. Viewnya kalo sore-malem bagus banget, bisa liat sunset. Menunya juga masih terhitung affordable. Ada musholah juga dilantai bawah.','nyaman angin segar tugas nongkrong layan cepat baristanya ramah ditanyain menu rekomendasi viewnya sore malem bagus liat sunset menu hitung affordable musholah lantai'),(90431,'Pesenkopi Plus Betek','Sandradita Priyono',5,'5 bulan lalu','rekomend bgtt buat yang mau nongkrong chill sambil liat sunset, makanan nya juga oke apalagi kopinya pokok ini termasuk cafe rooftop rekomended','rekomend nongkrong chill liat sunset makan pokok rooftop rekomended'),(90432,'Pesenkopi Plus Betek','chewy windy',5,'5 bulan lalu','Overall semuanya bagus. Dari makan, pelayanan, dan suasananya. Bagian rooftop cocok buat nongkrong sore.','bagus makan layan suasana rooftop cocok nongkrong sore'),(90433,'Pesenkopi Plus Betek','Nadiyah Neswari',5,'setahun lalu','Overall semuanya bagus. Dari makan, pelayanan, dan suasananya. Bagian rooftop cocok buat nongkrong sore.  Sayangnya kalo pas di rooftop mau order makan harus ke lantai bawahnya.  Parkirnya luas.','bagus makan layan suasana rooftop cocok nongkrong sore sayang rooftop order makan lantai parkir luas'),(90434,'Pesenkopi Plus Betek','Arif Wibowo',5,'3 bulan lalu','Nyaman buat ngobrol dan santai menikmati sore/malam','nyaman ngobrol santai nikmat sore'),(90435,'Pesenkopi Plus Betek','Natiqa Mutafania',4,'11 bulan lalu','Sunset spot buat nyore cocok sih ini. Lokasinya di rooftop salah satu hotel di sekitar UB, view kota Malang dan Batu. Dateng malam minggu penuh banget, tempat duduknya penuh. Pesennya lewat QR yang ada di meja jadi harus dapet tempat duduk dulu baru bisa pesen. Sempet pindah meja dan pesanan nyampe di meja awal, trus info ke waiters kalo pindah meja. Makin malam angin di atas cukup kenceng. Tempatnya oke banget adem view 360. Servicenya cukup baik. Tapi menunya ya gitu-gitu aja, mereka jual minuman dan snack aja yg ala kadarnya bahkan bisa dibilang kureng. Please ayo diimprove menu2nya. Sebenernya kalo mau makan berat ada resto sebelahnya . Kalo dikasih pilihan balik apa engga tergantung mau cari suasana atau minumnya, kalo cari suasana bakal balik, tp kalo untuk minum cukup sekali saja. 🙏🏻','sunset spot nyore cocok rooftop hotel view batu minggu penuh duduk penuh sen meja dapet duduk pesan sempet pindah meja pesan nyampe meja info waiters pindah meja angin kenceng adem view servicenya menu jual minum snack ala kadar bilang reng please ayo diimprove menu sebenernya makan berat resto belah kasih pilih gantung cari suasana minum cari suasana minum'),(90436,'Pesenkopi Plus Betek','Ja Ki',5,'sebulan lalu','Tempatnya sangat nyamann, pelayanan juga top bgttt, tempat favorit akuuu🫰❤️','nyamann layan top bgttt favorit akuuu'),(90437,'Pesenkopi Plus Betek','Dianaclaraag',5,'4 bulan lalu','tempat nongkrong santai dan asik, parkiran motor dan mobil sangat luas. pelayanan best bgt 🙌🏻✨','nongkrong santai nyaman parkir motor mobil luas layan'),(90438,'Pesenkopi Plus Betek','Andi Afifah Abiyyah Luthfi',5,'sebulan lalu','Viewnya bagus, tempatnya nyaman dan luas','viewnya bagus nyaman luas'),(90439,'Pesenkopi Plus Betek','Aldi Wahyu',4,'2 tahun lalu','Ini salah satu Coffee Shop yang pertumbuhannya cepet banget di Malang. Yang awalnya cuman stall kecil, bisa jadi sebesar ini. Jadi peskop plus yang di betek ini collab menu sama Tastery gitu ya? Saya kurang tahu. Dari segi tempat sangat-sangat perfect, mulai dari tempat parkir yang luas, dinning area yang luas, bersih dan cukup fancy, ada area roof top yang sangat keren, bisa menikmati angin sejuk kota Malang dan pemandangan kota Malang haha. Lalu untuk service saya suka banget, karena cepat, dan pelayanannya super ramah! Kemudian untuk menu makanannya menurut saya ada beberapa menu yang worthy dan ada yang kurang. Saya pesan Chicken Caesar Salad, menurut saya Grilled Chicken nya enak banget! Tapi sayang terlalu sedikit, dan variasi sayurnya hanya ada selada dan tomat, jadi agak kurang sih, but it\'s okay soalnya enak! Teksturnya saya suka soalnya ada roti panggangnya yang crunchy, dengan mayo dressing yang pas. Tapi untuk porsi menu lainnya agak sedikit kurang. Kemudian untuk minumannya sendiri hampir sama seperti pesen kopi pada umumnya, dan itu enak! Mungkin selisih harganya ada perbedaan sedikit. Overall, saya cukup puas bisa makan dan ngopi dengan view kota Malang dari ketinggian. Good job! Ps: next time bakal nyobain menu pastanya :D','tumbuh cepat stall skop plus collab menu tastery segi perfect parkir luas dinning area luas bersih fancy area roof top keren nikmat angin sejuk pandang haha service suka cepat layan super ramah menu makan menu worthy pesan chicken caesar salad grilled chicken nikmat sayang variasi sayur selada tomat okay nikmat tekstur suka roti panggang crunchy mayo dressing porsi menu minum pesan nikmat selisih harga beda puas makan view bagus job next time nyobain menu pasta'),(90440,'Pesenkopi Plus Betek','Alia Fathiyah',5,'setahun lalu','View nya cakep banget, apalagi pas sore. Selalu ramai ada di roof top hotel lantai 6. Makanannya enak jg, kopi nya juga. Kebanyakan anak gen Z yg nongki','view cakep sore ramai roof top hotel lantai makan nikmat anak gen nongkrong'),(90441,'Pesenkopi Plus Betek','Selaras',5,'2 bulan lalu','Tempatnya cozy, nyaman, banyak pilihan menu, stafnya ramah','nyaman nyaman pilih menu staf ramah'),(90442,'Pesenkopi Plus Betek','Pralampita Pita',5,'4 bulan lalu','Tempatnya nyaman banget buat nugas, kopinya enak pelayanannya juga baik, bintang 5 deh wajib kesini lagi','nyaman tugas nikmat layan wajib'),(90443,'Pesenkopi Plus Betek','Nandyan Ayu',4,'2 tahun lalu','Cocok bgt nongki di sini buat nyunset atau pas habis hujan. Ada indoor, balkon, dan rooftop. Makanan dan minuman standar rasa dan harganya. Cuma agak ribet dalam pemesanannya (makan dan minum terpisah). Overall, okelah','cocok nongkrong nyunset habis hujan indoor balkon rooftop makan minum standar harga ribet mesan makan minum pisah'),(90444,'Pesenkopi Plus Betek','Brilliana Fakhriha R.',5,'2 tahun lalu','Atmospherenya kayak di batu banget, padahal ini di tengah kota khususnya di tengah hiruk pikuk kesibukan kotaa. cantik banget pemandangan sore sampai malem, tempat duduknya juga comfort jadi bisa betah berlama2 disini. Menunya juga macem2 enak2 juga','atmospherenya batu hiruk pikuk sibuk kotaa cantik pandang sore malem duduk comfort betah menu macem nikmat'),(90445,'Pesenkopi Plus Betek','Firza Zahra Amanda',4,'2 tahun lalu','Cafe yang unik karena lokasinya di hotel. Viewnya bagus khusus di lantai indoor, rooftopnya enak kalo sore-malem dan order menunya pake scan menu gitu. Harganya ya standart kaya cafe-cafe gitu, cocok buat nongkrong sama kelompok. 👍🏻👍🏻','unik hotel viewnya bagus khusus lantai indoor rooftopnya nikmat sore malem order menu pakai scan menu harga standart kaya cocok nongkrong kelompok'),(90446,'Pesenkopi Plus Betek','Ahmad Bachtiar Arif',5,'2 tahun lalu','Kafe yang memiliki nuansa berbeda dari kafe pada umumnya karena kafe ini terletak di roof top hotel, tepatnya di lantai 6. View pemandangan di kafe ini cukup indah dan udaranya cukup dingin. Saya sarankan untuk memakai jaket ketika berkunjung ke sini. Rasa minumannya enak dan pelayanannya ramah. Fasilitasnya cukup lengkap dan ada mushollanya. Yang saya sukai dari pesen kopi adalah tempat parkirnya yang luas. Kafe ini gabung dengan restoran di lantai 5, jadi jika ingin memesan makanan tinggal turun satu lantai dan bisa dimakan di lantai 5 atau lantai 6.','milik nuansa beda letak roof top hotel lantai view pandang indah udara dingin saran pakai jaket kunjung minum nikmat layan ramah fasilitas lengkap mushollanya suka pesan parkir luas gabung restoran lantai mes makan tinggal turun lantai makan lantai lantai'),(90447,'Pesenkopi Plus Betek','Khoiri Kevanu',5,'3 bulan lalu','Tempat terbaik menikmati keindahan kota malang dan tempat terbaik untuk kumpul bersama temen terbaik 🥰','bagus nikmat indah bagus kumpul teman bagus'),(90448,'Pesenkopi Plus Betek','Yas',5,'2 tahun lalu','Nih tempat ternyata diatas hotel. Jadi ga begitu terlihat. Cuma pas kesini ternyata rame juga. Tempat outdoornya bagus. Bisa keliat pemandangan kota malang. Harga dan rasa juga sebanding. Tempatnya bersih, toilet bersih, mushola juga ada. Pelayanan juga ramah.. niceeee','nih hotel ramai outdoornya bagus liat pandang harga banding bersih toilet bersih mushola layan ramah niceeee'),(90449,'Pesenkopi Plus Betek','Aruna Wisnu Ardana',5,'9 bulan lalu','Suka banget nongkrong di Pesenkopi Plus Betek! Tempatnya nyaman, vibes-nya tenang, cocok buat me time atau nugas. Kopinya enak, harganya sesuai tempatnya, dan pelayanannya juga ramah. Fix bakal sering balik lagi ke sini','suka nongkrong plus nyaman vibes tenang cocok time tugas nikmat harga layan ramah fix'),(90450,'Pesenkopi Plus Betek','radha afika',5,'setahun lalu','Kesini gara-gara mau liat citylight malang hehehe . Tempatnya recommended banget untuk nongki2 cantik. Dan makanannya enak-enak juga, pelayanannya juga ok banget. Kemarin yang yang minus cuma muffinnya yah gak bisa kemakan heheheh 😌, tapi gpp karena sesuai harga 10 rb an','gara gara liat citylight hehehe rekomendasi nongkrong cantik makan nikmat nikmat layan kemarin minus muffinnya yah makan heheheh harga'),(90451,'Pesenkopi Plus Betek','Noval',5,'3 tahun lalu','My go-to space untuk WFC dan nongkrong.  Sightseeing kota Malang, dan UB paling cocok disini no debat!  Buka sampai jam 12 malam, banyak view gunung. Tempat rapih tertata, bersih! Might bawa jaket kesini karena jelas berangin.  Menu cukup pricey, di atas 25 hingga up to 40rb. Lokasi nya ada di lantai rooftop teratas, untuk kesini bisa naik lift yg ada di dalam hotel. Mau kesini pake celana pendek juga gak apa😃  Parkiran di sebelah hotel, pas saya kesana sih pengalaman parkir nya kurang menyenangkan karena sudah jelas terpampang “parkir gratis” tapi ditagih sama kang parkir, yah biasa orang lokal🤣','kerja nongkrong sightseeing cocok debat jam view gunung rapih tata bersih might bawa jaket angin menu mahal lantai rooftop lift hotel pakai celana pendek parkir belah hotel kesana alam parkir senang pampang parkir gratis tagih kang parkir yah orang lokal'),(90452,'Pesenkopi Plus Betek','KEMAL SAVERO',5,'4 bulan lalu','Ngopi di rooftop paling worth di kota malang. Ada musholah juga','rooftop layak musholah'),(90453,'Pesenkopi Plus Betek','Brilliant A.',4,'10 bulan lalu','tempatnyaa gede lumayan luas gitu, parkiran e ya luaas terus minumannya tuh gak yg enak banget tapi enak!! terus biasanya kesini buat liat sunset atau apapun😵‍💫😵‍💫 tempatnya ramee tp masih banyak kursinya kok','tempatnyaa gede lumayan luas parkir luaas minum tuh nikmat nikmat liat sunset ramai kursi'),(90454,'Pesenkopi Plus Betek','Verocha Lia',4,'2 tahun lalu','Ini mah yg juara Rooftopnya... view nya kota malang indah Menunya unk pesan kopi cuma minuman saja.. unk makanan bisa pesan di bawahnya..kolaborasi dgn apa ya.. lupa... Parkir juga aman.. sebelahnya... Toilet bersih....','juara rooftopnya view indah menu unk pesan minum unk makan pesan kolaborasi lupa parkir aman belah toilet bersih'),(90455,'Pesenkopi Plus Betek','Vania Nafeeza',4,'3 tahun lalu','Untum tempat parkir luas, tempat ngopi ada di lantai 5 dan 6 hotel. Untuk lantai 5 ada indoor dan outdoor. Lantai 6 full outdooor dan bisa melihat pemandangan kota malang, biasanya juga ada live musik. Tempatnya nyaman.. harga juga masih terjangkau. Asik banget biat sekedar ngobrol maupun mengerjalan tugas kuliah ataupun kantor. Dari segi makanan lumayan enak, pizza tipis bumbu juga terasa. Minuman juga enak','untum parkir luas lantai hotel lantai indoor outdoor lantai full outdooor pandang live musik nyaman harga murah nyaman biat dar ngobrol mengerjalan tugas kuliah kantor segi makan lumayan nikmat pizza tipis bumbu minum nikmat'),(90456,'Pesenkopi Plus Betek','Firda Fortuna',5,'4 bulan lalu','Tempatnya nyaman, sejuk, pelayanannya oke, cepat. Pegawainya juga ramah. Kopinya enak dan sangat affdorable.','nyaman sejuk layan cepat pegawai ramah nikmat affdorable'),(90457,'Pesenkopi Plus Betek','Wiji Dwi Prasetyo',5,'2 bulan lalu','Tempatanya bagus banget, kakaknya ramah-ramah. Kopinya pun enak. Mantab poll','tempatanya bagus kakak ramah ramah nikmat mantab'),(90458,'Pesenkopi Plus Betek','Maria Ulfa',4,'3 tahun lalu','Tempatnya nyaman, ada pilihan indoor n outdoor seating, ada di lt 5 n rooftopnya hotel, masuk lewat lobby hotel belok kiri lgsg naik lift. Rasa makanan lumayan, dori sambal matahnya enak, porsi ngenyangin, spaghetti oglio olio rasanya lite, kurang menurutku, pelayanan utk minuman cepat tapi utk makanannya cukup lamaa. Harga standar, tempatnya bersih, fasilitas lgkap, ada toilet, musholla, free parking bagi pengunjung.','nyaman pilih indoor outdoor seating rooftopnya hotel lobby hotel belok kiri lgsg lift makan lumayan dor sambal matahnya nikmat porsi ngenyangin spaghetti oglio olio lite layan minum cepat makan lamaa harga standar bersih fasilitas lgkap toilet musholla free parking unjung'),(90459,'Pesenkopi Plus Betek','Salsabillah aw',5,'Diedit setahun lalu','Bagus banget ada outdoor dan indoor, parkir sangat aman. Bisa lihat citylight malang dan cocok buat liat sunset juga. Wort it. Wifi juga lumayan kenceng','bagus outdoor indoor parkir aman lihat citylight cocok liat sunset wort wifi lumayan kenceng'),(90460,'Pesenkopi Plus Betek','Fira',5,'4 bulan lalu','Tempatnya bagus dan makanannya sesuai ekspektasi Terimakasih','bagus makan ekspektasi terimakasih'),(90461,'Pesenkopi Plus Betek','Dzikrina Istigfaroh',5,'setahun lalu','parkirannya luas ada disebelah hotel 99 syariah, untuk ke pesenkopi nya masuk ke hotel 99 terus naik lift dilobby dan ke lantai 5, abistu naik tangga satu lantai untuk ke rooftopnya. cafe ini buka dari jam 11.00 pagi - 23.45 malam. kursinya ada banyak bisa nongkrong di rooftop ataupun di lantai 5 nya. view nya juara disini bisa liat kota malang dari atas, apalagi kalau sore bisa liat senja dan gunung-gunung.  untuk makanan dan minuman terpisah pembeliannya, untuk makanan ada di lantai 5 Tastery, disini pesenkopinya hanya menjual minumannya saja. varian minumannya banyak, dari coffee, non coffee, manual brew, cinnamon series, butter series, frappe, tea and moctail, ada menu baru juga kayak choco crack dan cloud series. pesenkopi banyak promonya jugaa  pemesanan minuman bisa langsung scan barcode di meja dan paymentnya bisa bayar dikasir (cash, qris, debit) dan bisa pembayaran online (gopay, ovo, spay), kalau untuk makanan langsung pesan di kasir tastery lt 5.  dari segi rasa minumannya enak-enak, apalagi kopinya. bisa request less sugar buat yang ga terlalu suka manis. pelayanannya juga baik dan ramah-ramah:)','parkir luas belah hotel syariah hotel lift dilobby lantai abistu tangga lantai rooftopnya jam kursi nongkrong rooftop lantai view juara liat sore liat senja gunung gunung makan minum pisah beli makan lantai tastery pesenkopinya jual minum varian minum manual brew cinnamon series butter series frappe tea moctail menu choco crack cloud series promonya jugaa mesan minum scan barcode meja paymentnya bayar kasir cash qris debit bayar online gopay ovo spay makan pesan kasir tastery segi minum nikmat nikmat request less sugar suka manis layan ramah ramah'),(90462,'Pesenkopi Plus Betek','AULIYA FITHRI',5,'4 bulan lalu','tempatnya cozy, pelayanannya mantepp bintang 5, rasanya enakk☝🏻☝🏻','nyaman layan mantepp nikmat'),(90463,'Pesenkopi Plus Betek','N Ulfi',5,'3 tahun lalu','Tempatnya bagus poool. Ada di lantai 5 dan rooftop jadi view kota malang sekitarnya plus gunung arjuno dan gunung putri tidur kelihatan. Apalagi kalau datangnya sore, viewnya mantap banget. Harganya agak mahal dikit sih ya tapi sebanding kok sama rasanya yang cukup enak dan view yang cakep. Buat laptopan, ngobrol, atau sekedar cari spot foto yang instagramable. Hanya saja mungkin karena baru opening dan sempat viral juga jadi waktu kesana ruame. Antriny panjaang. Oh ya. Kasir untuk pesan makan ada di lt 5 dan minumnya ada di lt 6.','bagus poool lantai rooftop view plus gunung arjuno gunung putri tidur sore viewnya bagus harga mahal dikit banding nikmat view cakep laptop ngobrol dar cari spot indah opening viral kesana ruame antriny panjaang kasir pesan makan minum'),(90464,'Pesenkopi Plus Betek','zara',3,'11 bulan lalu','first time kesini, overall enak semua ko pelayanan dan makanan, tapiiii kesel bgt baru duduk beberapa menit, tbtb mati lmpu. dari jam 8 sampe set 10 ga nyala2 lampunya :/ sampe ngantuk dan jenuh karena ga keliatan dan bkin ngantuk hufttt','first time nikmat layan makan tapiiii kesel duduk menit tbtb mati lmpu jam set nyala lampu ngantuk jenuh liat bkin ngantuk hufttt'),(90465,'Pesenkopi Plus Betek','Rena Kharisma',5,'2 tahun lalu','Suasana rooftop yang menyenangkan dibuat nongkrong, disuguhkan pemandangan kota Malang dari atas. Berada satu gedung dengan hotel 99 syariah dan Tastery. Jadi untuk menuju ke pesen kopi plus menggunakan lift dari lobby hotel. Untuk pemesanan melalui barcode di tiap meja secara online. Pelayanan cukup baik, kebersihan cukup baik. Harga cukup terjangkau. Cita rasa minuman juga enak.','suasana rooftop senang nongkrong suguh pandang gedung hotel syariah tastery pesan plus lift lobby hotel mesan barcode meja online layan bersih harga murah cita minum nikmat'),(90466,'Pesenkopi Plus Betek','Annisa Ayu',5,'4 bulan lalu','Peskop+, ada di lt 6 hotel syariah 99.','skop hotel syariah'),(90467,'Pesenkopi Plus Betek','Fatimah Nurharisaa',5,'3 tahun lalu','Kesini waktu lagi rame-rame nya,alhasil mau parkir mobil susah bgt 2x muter baru dapet. Untuk tempat nya cozy bgt apalagi kalau malem pemandangannya city light, untuk menu minuman nya varian nya banyak dan rasa nya okelah untuk harga segitu, untuk makanan nyaa di jual terpisah di lt bawahnya. Standart lah ya untuk rasa nya Jadi pesen minum sendiri dan makan sendiri👍🏼','ramai ramai alhasil parkir mobil susah muter dapet nyaman malem pandang city light menu minum varian harga segitu makan nyaa jual pisah standart pesan minum makan'),(90468,'Pesenkopi Plus Betek','Billioner',4,'Diedit 3 tahun lalu','Tempatnya ada di rooftop hotel, daerah mayjend panjaitan, sebelah kanan jika dari arah Batu. Dulunya pesen kopi ada disini, di bagian depan bangunan ini. Tapi sekarang berubah menjadi hotel, termasuk restaurant dan pesenkopi plus ini. Karena ini viral, baru, dan inovasi baru dari pesenkopi, saya sebagai pecinta pesenkopi “dulu” patut berkunjung. Pilih di area sini daripada begawan apartment, karena di rooftop dan tempat duduknya lebih luas dan banyak. Area parkir gratis, lalu dari lobby hotel ambil sebelah kiri dan lift. Pilih lt 5, nanti nya ada tastery, lalu naik lagi melalui tangga, barulah sampai di pesenkopi plus. Pesenkopi plus menurutku membawa inovasi lebih banyak varian minumannya, packagignya lebih bagus dan safety, rasanya lebih mantab, dan harganya lebih mahal dari pesenkopi biasa. Pelayanannya oke ( cuma kebetulan beberapa org termasuk saya disuru untuk mengambil kembalian nanti pas pulang), apakah kasir tdk memiliki uang pecahan cadangan? Mohon dievaluasi. Tempatnya bisa yang tanpa atap atau dibawah atap. Kalian bisa melihat pemandangan kota malang dari berbagai sisi. Saat itu kami datang pukul 2 siang, alhamdulillah tdk panas karena mendung, dan tempat duduk masih banyak yg kosong. Setelah jam 4 sore, antriannya banyak dan kebanyakan ga dapat tempat duduk. Untuk makanan, kalian bisa pesan di tastery di lantai bawahnya. Dan sekian, thanks Untuk tastery, numpang review. Tempatnya bersih dan luas. Cuma rasa masakannya kurang nendang, contohnya salted egg chicken (ayamnya cuma 3 potong kecil), sphagetti carbonara dan brullenya. Platting nya 9/10','rooftop hotel daerah mayjend panjaitan belah kanan arah batu dulunya pesan bangun ubah hotel restaurant plus viral inovasi cinta patut kunjung pilih area begawan apartment rooftop duduk luas area parkir gratis lobby hotel ambil belah kiri lift pilih tastery tangga plus plus bawa inovasi varian minum packagignya bagus safety mantab harga mahal layan org disuru ambil pulang kasir tdk milik uang pecah cadang mohon evaluasi atap atap pandang sisi alhamdulillah tdk panas mendung duduk kosong jam sore antri duduk makan pesan tastery lantai sekian thanks tastery numpang bersih luas masakan nendang contoh salted egg chicken ayam potong sphagetti carbonara brullenya platting'),(90469,'Pesenkopi Plus Betek','Izza Isma',5,'3 tahun lalu','Cozy place buat me-time maupun hangout bareng temen. Tempatnya ada di lantai 5 yaa. Selain varian menu, kita disajikan view sekitar kota malang yg tentunya manjain mata. Kalau kesini jangan lupa ke rooftopnya yaa ✨ banyak spot foto yg instagramable','nyaman time hangout bareng teman lantai yaa varian menu saji view manjain mata lupa rooftopnya yaa spot indah'),(90470,'Pesenkopi Plus Betek','Muhd Sigit Firmansyah',5,'setahun lalu','Adem karena berada di rooftop lt.5, minumannya enak tapi makanannya b aja.  Cocok buat nugas dan nongki, minusnya wifi terbatas, jadi teman2 kemarin beberapa gabisa akses.','adem rooftop minum nikmat makan cocok tugas nongkrong minus wifi batas teman kemarin gabisa akses'),(90471,'Pesenkopi Plus Betek','prima hakim',5,'4 bulan lalu','Pertama kali kesini.. suasana luar biasa keren.','suasana keren'),(90472,'Pesenkopi Plus Betek','Ridho Hardiansyah',5,'2 tahun lalu','Paling saya suka disini suasananya, tenang, tidak terlalu ramai, ada tempat buat outdoor juga. Outdoor nya ada di tingkat 5, jadinya view nya oke.  Untuk harga lumayan. Standart berkisar 20 rb an keatas.','suka suasana tenang ramai outdoor outdoor tingkat view harga lumayan standart kisar'),(90473,'Pesenkopi Plus Betek','Mskputri',4,'6 bulan lalu','Kesini buat ngupi ngupi sambil ngliatin UB ✨🫰🏻','ngupi ngupi ngliatin'),(90474,'Pesenkopi Plus Betek','Ivan Salowok',4,'10 bulan lalu','Pelayanan nya bagus banget🥰 minuman ku ada hewan kecil ntah semut atau apa langsung diganti dan dikasih free ice lemon tea😍','layan bagus minum hewan ntah semut ganti kasih free ice lemon tea'),(90475,'Pesenkopi Plus Betek','Maulan Ayu',5,'8 bulan lalu','Bagi yang ingin merasakan vibes pesen kopi lebih elit, bisa datang ke pesenkopi plus betek yang satu tempat dengan hotel syariah 99. Lokasinya sangat strategis, parkir luas, untuk bisa masuk kesini, dapat melalui lift hotel. Nanti langsung saja masuk ke rooftop. Karena aku datangnya malem, kondisinya cerah, langitnya bagus dan pemandangan citylightnya juara. Hanya saja, yang tidak betah dingin, lebih baik membawa jaket dan berkaos kaki. Untuk rasanya, kurasa semua outlet sama aja. Memang, harganya lebih mahal dibanding pesenkopi yang outlet biasa (secara tempatnya juga ada di hotel). Jadi, untuk experience boleh lah dicoba. Buat nugas, okesih, karena banyak stop kontaknya. Oiya, pemesanan bisa melalui kasir, bisa juga dengan scan barcode dan bayar melalui aplikasi shopeepay/gopay.','vibes pesan elit plus hotel syariah strategis parkir luas lift hotel rooftop malem kondisi cerah langit bagus pandang citylightnya juara betah dingin bawa jaket kaos kaki outlet harga mahal banding outlet hotel experience tugas okesih stop kontak oiya mesan kasir scan barcode bayar aplikasi shopeepay gopay'),(90476,'Pesenkopi Plus Betek','Chandra Fahris Sandimas',5,'3 bulan lalu','Ada di lt5 masuk hotel. Pelayanan ramahhh okee banget','hotel layan ramahhh okee'),(90477,'Pesenkopi Plus Betek','Lita Prikas',4,'2 tahun lalu','Lokasinya di lantai paling atas hotel 99 syariah, untuk view nya terbaik sih. Bisa liat kota malang dari rooftop Tapi yg agak ribet pesan makanan sama minuman terpisah ya. Gak jadi satu kasirnya Tempatnya bersih dan minumannya enak²','lantai hotel syariah view bagus liat rooftop ribet pesan makan minum pisah kasir bersih minum nikmat'),(90478,'Pesenkopi Plus Betek','Dwi Adinda',4,'3 tahun lalu','Untuk menu lumayan bervariasi seperti biasanya,  Layanannya cukup baik, pelayannya ramah\" juga, dan menunggu pesanan tidak terlalu lama.  Suasana nya enaak banget apalagi kalo malem jadi bagus banget liat citylight dari atas','menu lumayan variasi layan layan ramah tunggu pesan suasana enaak malem bagus liat citylight'),(90479,'Pesenkopi Plus Betek','tessa leonica',5,'5 bulan lalu','Tempatnya cozy dan makanan minumannya enak','nyaman makan minum nikmat'),(90480,'Pesenkopi Plus Betek','Ike Dwi Lestari',4,'setahun lalu','Untuk kamu yang mau nongki with view citylight oke banget sih disini, cuman menurutku untuk menu di pesen kopi kurang oke, suamik pesen kopi butter tapi rasanya aneh banget, dan tidak ada pilihan hot or cold  Lalu tidak ada menu snack nya, dibawah hanya menu per-kue-an dan makanan berat','nongkrong view citylight menu pesan suamik pesan butter aneh pilih hot cold menu snack menu kue makan berat'),(90481,'Pesenkopi Plus Betek','Maruf Khudori',5,'2 tahun lalu','Parkiran luas. Naik ke lantai 5 ada lift yg bagus dan cepat. Pemandangan bagus kota malang. Harga makanan dan minuman terjangkau.','parkir luas lantai lift bagus cepat pandang bagus harga makan minum murah'),(90482,'Pesenkopi Plus Betek','Zamzabila Abdillah',5,'3 tahun lalu','Terletak di rooftop sebuah hotel, pesen kopi ini menyajikan tempat nongkrong dengan view Kota Malang yang indah.  Menu minumannya beragam, harga standar. Untuk pesan makanan bisa pesan di lantai dibawahnya.','letak rooftop hotel pesan saji nongkrong view indah menu minum agam harga standar pesan makan pesan lantai'),(90483,'Pesenkopi Plus Betek','Fatma Muthia',5,'2 tahun lalu','KESINI PAS SORE BAGUS POL. peskop ini gabung sama hotel syariah 99. masuk resepsionis lgsg ke lift ya. naik ke lantai 5. di lt 5 merupakan indoor dan letak mushola. beli cemilan disibi ya! naik ke lantai 6 pake tangga and welcome to outdoor dimana kita bisa masuk angin! WKWK. iya dingin. jadi usahain pake baju tebal atau bawa jaket. pesen minum disini ya!  aku suka banget menu rosellanya yang aga asem tp masih bisa diterima lidah. ada colokan banyak kok tenang aja. bisa bengong atau nugas dengan syahdu','sore bagus skop gabung hotel syariah resepsionis lgsg lift lantai indoor letak mushola beli cemilan disibi lantai pakai tangga welcome outdoor angin wkwk iya dingin usahain pakai baju tebal bawa jaket pesan minum suka menu rosellanya aga asem terima lidah colok tenang bengong tugas syahdu'),(90484,'Pesenkopi Plus Betek','Yesy Nadilla',4,'3 tahun lalu','frappucinonya kemanisan, oreo frappe-nya lumayan.  lokasinya bagus karena dapet view malang yg di kelilingin gunung. tempatnya juga luas, bersih, dan ada live musik mulai sore. harganya termasuk standar buat cafe di tengah kota yang ngejual view.','frappucinonya manis oreo frappe lumayan bagus dapet view kelilingin gunung luas bersih live musik sore harga standar ngejual view'),(90485,'Pesenkopi Plus Betek','natzwa carisdyah',5,'4 bulan lalu','pelayanannya okee, tempatnya jg nyaman','layan okee nyaman'),(90486,'Pesenkopi Plus Betek','Nia Gorden',5,'setahun lalu','Pas banget buat nongkrong di sore hari apalagi cuaca cerah, kopi enak bgt fav yg creamy, cakenya juga worth to try guys, kamar mandi juga bersih 🥰','nongkrong sore cuaca cerah nikmat fav creamy cakenya layak try guys kamar mandi bersih'),(90487,'Pesenkopi Plus Betek','Face Genius08',5,'3 tahun lalu','Pertama kali kesini baru tau klo ada cafe diatas hotel syariah , ya walaupun tutupnya jam 12 malem ngikut jam hotelnya tapi jujur disini enak banget sih apalagi bisa liat pemandangan dari atas , trus untuk menunya ya wajar diharga 15 keatas lah . Parkirnya luas banget trus pelayananya mantab , ya walaupun tadi temenku pesen tapi ndak dibikinin  sampe stengah jam karna lupa tapi sama mas² pelayan dikasih lemon tea sebagai perminta maaf an . Pelayananya manteb² sih jadi nggak kecewa sama tempat ini','tau hotel syariah jam malem ngikut jam hotel jujur nikmat liat pandang menu wajar harga parkir luas pelayananya mantab temenku pesan dibikinin stengah jam lupa mas layan kasih lemon tea maaf pelayananya manteb kecewa'),(90488,'Pesenkopi Plus Betek','yara elvianaa',5,'5 bulan lalu','Tempatnya bagus, lumayan untuk rasa minumannya','bagus lumayan minum'),(90489,'Pesenkopi Plus Betek','Alivia Salsabila',4,'3 tahun lalu','Makanan, minuman, dan snack beragam. Tempat bagus, ada yg indoor maupun outdoor. Cocok untuk mengerjakan tugas (ada colokan) maupun sekedar nongkrong. Bisa melihat pemandangan kota malang dari atas','makan minum snack agam bagus indoor outdoor cocok tugas colok dar nongkrong pandang'),(90490,'Pesenkopi Plus Betek','Thoriq Amrullah',4,'setahun lalu','Saya berkunjung ke sini pada bulan Juli 2024 -Tempatnya berada di rooftop hotel, dari sini kita bisa melihat pemandangan kota Malang yang dikelilingi oleh gunung-gunung -Mungkin waktu terbaik berkunjung ke sini adalah saat sore hari -Harga menu sebanding dengan fasilitas yang diberikan','kunjung juli rooftop hotel pandang keliling gunung gunung bagus kunjung sore harga menu banding fasilitas'),(90491,'Pesenkopi Plus Betek','Doni Irawan',5,'4 bulan lalu','Service sangat helpful, viewnya mantap banget','service helpful viewnya bagus'),(90492,'Pesenkopi Plus Betek','Nur Lailatul F UPT Bojonegoro',4,'setahun lalu','Gak tahu tempatnya klo gak di request anak sy, krn tempatnya msk ke hotel, naik lift di lt. 3 Tempatnya nyaman dan ada rooftoopnya, menunya bnyak pilihan dan rasanya mantab.. klo ke mlg pasti mampir lagi, insyaallah','request anak msk hotel lift nyaman rooftoopnya menu bnyak pilih mantab mlg mampir insyaallah'),(90493,'Pesenkopi Plus Betek','Muhammad Rosa Sya\'Roni',5,'3 tahun lalu','Menu semua kayak pesen kopi kayak biasanya, bagus tempatnya viewnya, nasi goreng iga rekomended, mantap lah pokoknya sesuai harga 👌👌👌','menu pesan bagus viewnya nasi goreng iga rekomended bagus pokok harga'),(90494,'Pesenkopi Plus Betek','Dhita Lelly Anastasya',5,'3 tahun lalu','Tempatnya asik. Oiya krn outdoor, kalo malem dingin bgttt. Anginnya kenceng pake bangttttttt. Menunya enak, snack dr tastery enak banget apalagi yg onion ring. Harganya mayan bgt kalo masih minta ke ortu wkwkkw, tapi enak kok','nyaman oiya outdoor malem dingin bgttt angin kenceng pakai bangttttttt menu nikmat snack tastery nikmat onion ring harga mayan ortu wkwkkw nikmat'),(90495,'Pesenkopi Plus Betek','Tsalsabilla Alvianita',5,'setahun lalu','Cocok buat tempat nugas dgn pemandangan yg bagus dari rooftop, adem bgt, buat nongki atau kumpul keluarga juga recommended sekali. Pelayanannya juga top deh.','cocok tugas pandang bagus rooftop adem nongkrong kumpul keluarga rekomendasi layan top'),(90496,'Pesenkopi Plus Betek','Kumalasari Dewi Purnama',4,'3 tahun lalu','Mencoba tempat nongki baru. Tempatnya luas. Ada rooftop yg cocok buat kawula muda menghabiskan waktu sambil mengasap di tempat terbuka. Utk makanan dan minuman menurut sya \"STD\".','nongkrong luas rooftop cocok kawula muda habis asap makan minum sya std'),(90497,'Pesenkopi Plus Betek','ulfa annisa',4,'3 tahun lalu','Tempatnya di dalam hotel, parkir luas, ada outdoor  di rooftop, aku beli spaghetti aglio olio rasanya hambar dan berminyak.','hotel parkir luas outdoor rooftop beli spaghetti aglio olio hambar minyak'),(90498,'Pesenkopi Plus Betek','Prita Dewi',5,'5 bulan lalu','mantull.. tempat ngafe ternyaman dan minuman enak2 dam seger 😍','mantull ngafe nyaman minum nikmat dam segar'),(90499,'Pesenkopi Plus Betek','Cavilla Anggie Falljack',5,'4 bulan lalu','Ok banget si buat nongs, nugas, view ok layanan mantul. Trims ya peskop plus, yokla lebih byk buka cabang Sby Sda kali ya','nongs tugas view layan bagus trims skop plus yokla cabang sby sda'),(90500,'Pesenkopi Plus Betek','Isymayati AS',5,'3 tahun lalu','Pasta, dessert dan matcha lattenya enak sih overall, harga jga standar sma cafe lainnya. Karna menurut aku ga cuma tempatnya aja yang harus nyaman tapi menu2nya jga worth it.','pasta dessert matcha lattenya nikmat harga standar sma nyaman menu layak'),(90501,'Pesenkopi Plus Betek','Adit Mf',5,'8 bulan lalu','Ada di roof top, Kalo mau nyore sambil liat suasana malang bisa nih kesini….','roof top nyore liat suasana nih'),(90502,'Pesenkopi Plus Betek','Syahrizal Azzuri',5,'5 bulan lalu','Tempat cozy dan nyaman buat hangoutt☺️','nyaman nyaman hangoutt'),(90503,'Pesenkopi Plus Betek','Haydika Wildan',5,'4 bulan lalu','harga worth it dgn ambience yg didapat','harga layak ambience'),(90504,'Pesenkopi Plus Betek','rizka rizki',5,'3 bulan lalu','Josjis abisss, view nyaa bikin nagihhhh','josjis abisss view nyaa nagihhhh'),(90505,'Pesenkopi Plus Betek','Aditiya Kurniawan',5,'3 tahun lalu','Tempatnya sangat cozy, sangat instagramable, cocok yang suka hangout, ada tempat indoor maupun outdoor, jadi tidak akan khawatir jika hujan. Terdapat banyak menu yang tersedia. Tempat parkir yang luas dan aman pastinya','nyaman indah cocok suka hangout indoor outdoor khawatir hujan menu parkir luas aman'),(90506,'Pesenkopi Plus Betek','radifan n',5,'setahun lalu','Sering banget kesini, crewnya pada sat set, menu enak” semua. Pernah kapan itu pas abis ujan mejanya basah, crewnya gercep dibantu untuk beresin, terimakasih yaa 🫶🏼','crewnya sat set menu nikmat abis ujan meja basah crewnya gercep bantu resin terimakasih yaa'),(90507,'Pesenkopi Plus Betek','Adiyat “Kentir” Lazuardi',4,'setahun lalu','Ambiencenya sumpah enak banget bisa buat alternatif daripada ke area batu malang tetep dapet kok view citylightnya cuma minuman coklat dan latte yang dipesan tidak panas saat diterima saat dicomplain runner tidak memberikan jawaban jelas jadi yaa sudah okey kami anggap selesai saja tidak apa-apa','ambiencenya sumpah nikmat alternatif area batu tetep dapet view citylightnya minum coklat latte pes panas terima dicomplain runner yaa okey anggap selesai'),(90508,'Pesenkopi Plus Betek','Elsa Mutiara RR',5,'3 tahun lalu','new coffee in town! tempatnya cozy bgt apalagi di skylounge nya, cakep bgt buat ngumpul bareng temen, pacar, keluarga. menunya bervariatif, harganya affordable 15k-35k.','new town nyaman skylounge cakep nongkrong bareng teman pacar keluarga menu variatif harga affordable'),(90509,'Pesenkopi Plus Betek','Mochamad Afifudin94',5,'2 tahun lalu','Untuk makanan dilantai 5 menurut saya cukup baik. Layanan sangat memuaskan dan carefull mbak mbaknya. Untuk suasana sangat sejuk dan homey, kami suka.','makan lantai layan muas carefull mbak mbak suasana sejuk homey suka'),(90510,'Pesenkopi Plus Betek','Wisnu Dian Nugraha',5,'4 bulan lalu','Tempatnya nyaman, luas, banyak meja jadi nggak kuatir kehabisan meja, cocok jadi teman nugas','nyaman luas meja kuatir habis meja cocok teman tugas'),(90511,'Pesenkopi Plus Betek','Finna Nazilatur',5,'4 bulan lalu','Tempatnya enak dan cozy banget buat nugas, banyak tempat duduk, mungkin perlu ditambah colokannya aja, selebihnya sudah oke','nikmat nyaman tugas duduk colok'),(90512,'Pesenkopi Plus Betek','Andika Chudlary',5,'setahun lalu','Untuk makanan di pesan kopi tidak ada, mesti turun ke lantai 5 ada toko kue. Jadi mesti turun ke bawah lalu naik lagi keatas. Service saya kasih bintang 3 karena untuk colokan listrik tidak ada dibawah atap, adanya di outdoor kalau hujan kan gak bisa kerja laptopnya. Mas penjaganya mungkin perlu banyak senyum ya, kami jadi sedikit males buat datang lagi. untuk tempat oklah buat posting di sosmed.','makan pesan mesti turun lantai toko kue mesti turun service kasih colok listrik atap outdoor hujan kerja laptop mas jaga senyum males oklah posting sosmed'),(90513,'Pesenkopi Plus Betek','Bunda Yatik',5,'10 bulan lalu','Suara enak.tempat bagus.untuk ber foto.tempat luas','suara nikmat bagus ber luas'),(90514,'Pesenkopi Plus Betek','Aidan Pratama',5,'5 bulan lalu','pemandangan nya bagus banget soalnya dilantai atas','pandang bagus lantai'),(90515,'Pesenkopi Plus Betek','Wildah Azmah Azizah',5,'3 tahun lalu','suasananya enak banget, apalagi malang lagi adem2nya yaa cuacanya. buat ngopi sore enak banget (apalagi kalo mo foto cakep gt). ngopi malem jg. soalnya view nya langsung langit ya walopun malam ga keliatan bintang yak wkwk.','suasana nikmat adem yaa cuaca sore nikmat cakep malem view langit walopun liat yak wkwk'),(90516,'Pesenkopi Plus Betek','Ratulafika Aisya',5,'5 bulan lalu','tempatnya nyaman+dapet view baguss, recommended bgtt buat nongki atau ngerjain tugas bareng temen','nyaman dapet view baguss rekomendasi nongkrong ngerjain tugas bareng teman'),(90517,'Pesenkopi Plus Betek','Aprillia Citra',5,'5 bulan lalu','cafe ter bestt karna viewnya baguss bgt